#!/usr/bin/env node
// Appends 400 more vocabulary words (IDs 601–1000) to day-01 vocabulary.json
// Categories: Business, Office, Career/Interview, Academic, Advanced Adjectives,
//             Advanced Verbs, Phrasal Expressions, Technology & Digital

const fs = require('fs');
const path = require('path');

const FILE = path.join(__dirname, '../data/challenge/day-01/vocabulary.json');
const data = JSON.parse(fs.readFileSync(FILE, 'utf8'));
const existingIds = new Set(data.words.map(w => w.id));

function w(id, word, hindi, simpleMeaning, ipa, category, pos, cefr, syns, ants, daily, office, interview, business, formal, informal, usageNote, verbForms) {
  if (existingIds.has(id)) return null;
  const entry = { id, word, hindi, simpleMeaning, ipa, category, partOfSpeech: pos, cefrLevel: cefr,
    synonyms: syns, antonyms: ants,
    sentences: { daily, office, interview, business, formal, informal },
    usageNote };
  if (verbForms) entry.verbForms = verbForms;
  return entry;
}
const vf = (base, s3, ing, past, pp) => ({ base, s3, ing, past, pp });

const newWords = [
  // ─── Business & Finance (601–650) ───────────────────────────────────────
  w(601,"achieve","प्राप्त करना / हासिल करना","to successfully reach a goal","/əˈtʃiːv/","Business & Finance","verb","A2",["accomplish","attain","reach"],["fail","miss"],"I want to achieve my fitness goal this month.","We achieved all our quarterly targets.","I achieved the highest sales in my previous role.","The company achieved 30% growth in one year.","The team achieved exceptional results within budget.","Yes! We finally achieved what we wanted!","Always used with positive outcomes — a goal, dream, or target. Never use for bad results.",vf("achieve","achieves","achieving","achieved","achieved")),
  w(602,"budget","बजट / धन-योजना","a plan for managing money","/ˈbʌdʒɪt/","Business & Finance","noun/verb","B1",["plan","allocation","estimate"],["overspend","waste"],"I always plan a monthly budget for expenses.","The marketing budget was increased by 20%.","I managed a project budget of ₹10 lakhs.","We must review the annual budget before Q4.","The committee approved the revised budget proposal.","That trip is out of my budget!","As a verb: 'I budget carefully.' As a noun: 'What is our budget?' Both forms are common in business.",vf("budget","budgets","budgeting","budgeted","budgeted")),
  w(603,"invest","निवेश करना","to put money into something to earn more","/ɪnˈvɛst/","Business & Finance","verb","B2",["fund","finance","back"],["withdraw","divest"],"I invested in a savings scheme last year.","The company invested ₹5 crore in new machinery.","I have experience investing in stock markets.","We should invest in digital transformation now.","The firm invested strategically in emerging markets.","Don't invest money you can't afford to lose!","Invest in (a place/thing): 'invest in stocks.' Invest with (a person): 'invest with a broker.'",vf("invest","invests","investing","invested","invested")),
  w(604,"profit","लाभ / मुनाफ़ा","money earned after paying all costs","/ˈprɒfɪt/","Business & Finance","noun","A2",["gain","earnings","return"],["loss","deficit"],"The small bakery made a good profit last month.","Our Q3 profit exceeded last year by 40%.","The business turned a profit within six months.","Higher sales volume drives greater profit margins.","The annual profit report was presented to shareholders.","We made a nice profit selling old furniture!","Profit is the money LEFT after all costs are paid. 'We made a profit of ₹2 lakh this month.'"),
  w(605,"revenue","आय / कुल आमदनी","total income earned by a company","/ˈrɛvɪnjuː/","Business & Finance","noun","B2",["income","turnover","earnings"],["expenditure","cost"],"Small shops count every rupee of revenue.","Our annual revenue grew by 25% this quarter.","The startup reported ₹1 crore in monthly revenue.","Revenue from digital sales now exceeds offline sales.","Total revenue for the fiscal year stood at ₹50 crore.","Their YouTube channel earns good revenue!","Revenue = all money earned. Profit = revenue minus costs. Both are crucial business metrics."),
  w(606,"negotiate","बातचीत करना / सौदेबाज़ी करना","to discuss to reach an agreement","/nɪˈɡoʊʃɪeɪt/","Business & Finance","verb","B2",["bargain","discuss","mediate"],["demand","dictate"],"I negotiated a better rent with my landlord.","We negotiated a three-year contract with the supplier.","Can you negotiate your salary? Always try politely.","The two companies negotiated for weeks before signing.","Representatives negotiated terms acceptable to all parties.","I negotiated the price down by ₹5,000!","Negotiate WITH someone; negotiate FOR something: 'We negotiated with the vendor for a discount.'",vf("negotiate","negotiates","negotiating","negotiated","negotiated")),
  w(607,"contract","अनुबंध / समझौता","a formal written legal agreement","/ˈkɒntrækt/","Business & Finance","noun","B2",["agreement","deal","pact"],["disagreement","dissolution"],"Sign a contract before starting any freelance work.","The employment contract was signed by both parties.","Always read the contract carefully before signing.","We offer a one-year renewable contract for all suppliers.","The contract stipulates a 30-day notice period.","Never sign a contract without reading it!","As a noun: 'Sign the contract.' As a verb: 'The company contracted a new agency.'"),
  w(608,"deadline","अंतिम तिथि / समय-सीमा","the final date by which something must be done","/ˈdɛdlaɪn/","Business & Finance","noun","B1",["due date","cutoff","target date"],["extension","delay"],"The assignment deadline is Friday at midnight.","We must submit the report before the client deadline.","I never miss a deadline — it's my work ethic.","Missing the deadline may result in penalty charges.","The project deadline was extended by two weeks.","I forgot the deadline and had to work all night!","'Meet a deadline' (complete on time) and 'miss a deadline' (fail to complete) are key collocations."),
  w(609,"stakeholder","हितधारक / सम्बद्ध पक्ष","a person with interest or involvement in a project","/ˈsteɪkhoʊldər/","Business & Finance","noun","C1",["shareholder","partner","investor"],["outsider","bystander"],"Community members are stakeholders in local projects.","All stakeholders attended the quarterly review meeting.","I presented the project plan to key stakeholders.","Stakeholder feedback was incorporated into the final design.","Each stakeholder was briefed on their role and responsibilities.","Even customers are stakeholders — they care about results!","Stakeholders can be internal (employees) or external (clients, community). Always consider all of them."),
  w(610,"proposal","प्रस्ताव / योजना","a formal plan or suggestion presented for approval","/prəˈpoʊzəl/","Business & Finance","noun","B2",["suggestion","plan","offer"],["rejection","refusal"],"I wrote a business proposal for my new startup idea.","The team submitted a detailed project proposal.","My job application included a research proposal.","The client approved our marketing proposal on Friday.","The formal proposal outlined objectives, timelines, and costs.","I proposed a trip to Goa and everyone agreed!","'Submit/write/prepare a proposal.' A proposal is a plan you offer for someone else to accept or reject."),
  w(611,"strategy","रणनीति / कार्य-योजना","a careful plan to achieve a goal","/ˈstræt̬ɪdʒi/","Business & Finance","noun","B2",["plan","approach","tactic"],["improvisation","impulse"],"My study strategy helped me top the exam.","The company's pricing strategy attracted new customers.","Tell me about a strategy you used to solve a problem.","A strong digital marketing strategy drove 3× website traffic.","The board approved a five-year expansion strategy.","My strategy for traffic? Leave 30 minutes early!","Strategy is the big-picture PLAN. Tactics are the specific steps to carry out the strategy."),
  w(612,"milestone","मील का पत्थर / महत्वपूर्ण पड़ाव","an important achievement or stage in a project","/ˈmaɪlstoʊn/","Business & Finance","noun","B2",["achievement","landmark","checkpoint"],["setback","failure"],"Finishing school was a big milestone in my life.","The team celebrated every project milestone on time.","Getting my first job was a major career milestone.","Launching the app was a milestone for the startup.","Each milestone was reviewed by the project steering committee.","My first ₹1 lakh savings was a personal milestone!","Use 'reach/hit/celebrate a milestone.' It marks meaningful progress, not just any step."),
  w(613,"portfolio","कार्य-संग्रह / पोर्टफोलियो","a collection of work samples or investments","/pɔːrtˈfoʊlioʊ/","Business & Finance","noun","B2",["collection","file","showcase"],["single item"],"I built a design portfolio to show to employers.","The investment portfolio includes stocks and mutual funds.","Please send your portfolio before the interview.","A diversified portfolio reduces investment risk significantly.","The portfolio was presented to the board of directors.","My Instagram is basically my photography portfolio!","For jobs: show your portfolio. For finance: 'manage a portfolio of investments.'"),
  w(614,"launch","शुरू करना / लॉन्च करना","to officially start or introduce something new","/lɔːntʃ/","Business & Finance","verb","B1",["introduce","debut","release"],["discontinue","cancel"],"We launched a new product line last week.","The startup launched its app with a free trial offer.","I launched my freelance career during the pandemic.","The brand launched a nationwide advertising campaign.","The company officially launched operations in Southeast Asia.","They launched the party and everyone showed up!","'Launch' suggests something BIG starting officially — a product, campaign, career, or project.",vf("launch","launches","launching","launched","launched")),
  w(615,"scale","विस्तार करना / बढ़ाना","to grow or expand a business to a larger size","/skeɪl/","Business & Finance","verb","C1",["expand","grow","enlarge"],["shrink","downsize"],"Small businesses dream of scaling their operations.","We plan to scale our team from 10 to 50 people.","How did you scale the company to ₹10 crore revenue?","Scaling requires systems, processes, and strong leadership.","The startup scaled rapidly after receiving Series A funding.","They scaled the chai stall to 50 outlets nationwide!","'Scale' in business = grow systematically. Opposite: 'downsize' or 'scale back.'",vf("scale","scales","scaling","scaled","scaled")),
  w(616,"acquire","प्राप्त करना / अधिग्रहण करना","to buy or obtain something, especially a company","/əˈkwaɪər/","Business & Finance","verb","C1",["purchase","obtain","buy"],["sell","divest"],"I acquired new skills by taking online courses.","The tech giant acquired a small AI startup.","During my tenure, I acquired expertise in data analysis.","The company acquired three competitors in two years.","The corporation acquired a significant market share.","She acquired a taste for coffee in college!","Acquire (companies/assets) = buy. Acquire (skills/habits) = develop through effort or time.",vf("acquire","acquires","acquiring","acquired","acquired")),
  w(617,"dividend","लाभांश","a share of company profits paid to shareholders","/ˈdɪvɪdɛnd/","Business & Finance","noun","C1",["return","payout","share"],["loss","withholding"],"Hard work always pays a dividend in the long run.","Shareholders received a quarterly dividend of ₹5 per share.","The company declared its highest dividend in five years.","Regular dividend payments attract long-term investors.","The board voted to increase the annual dividend by 10%.","Good habits pay dividends — health, wealth, and peace!","Financial: money paid to investors. General use: 'Hard work pays dividends' = gives rewards later."),
  w(618,"forecast","पूर्वानुमान / भविष्यवाणी","a prediction of what will happen in the future","/ˈfɔːrkæst/","Business & Finance","noun/verb","B2",["prediction","projection","estimate"],["reality","outcome"],"The weather forecast says rain tomorrow.","Our sales forecast for Q4 shows 15% growth.","I can't forecast the exact outcome but I can plan.","The financial forecast was reviewed by all department heads.","The forecast indicated a strong performance in emerging markets.","The forecast said sunny — it rained all day!","As a noun: 'the forecast.' As a verb: 'We forecast strong growth.' Always implies looking ahead.",vf("forecast","forecasts","forecasting","forecast","forecast")),
  w(619,"vendor","विक्रेता / आपूर्तिकर्ता","a person or company that sells goods or services","/ˈvɛndər/","Business & Finance","noun","B2",["supplier","seller","dealer"],["buyer","customer"],"We chose a reliable vendor for office supplies.","The IT vendor provided software maintenance services.","Can you recommend a vendor for event management?","We shortlisted three vendors and requested proposals.","The vendor delivered materials two days ahead of schedule.","The street vendor sold the best momos in town!","Vendor = anyone who SELLS to you. The company that buys is the client or customer."),
  w(620,"invoice","चालान / बीजक","a bill asking for payment for goods or services","/ˈɪnvɔɪs/","Business & Finance","noun","B2",["bill","receipt","statement"],["payment","receipt"],"Send me the invoice and I'll process payment today.","The vendor submitted an invoice for ₹25,000.","As a freelancer, I send invoices every 15 days.","Invoices must include GST number and payment terms.","The invoice was approved by the accounts department.","My invoice got lost in their email — classic!","An invoice is sent BY the seller TO the buyer, requesting payment. A receipt is proof of payment."),
  w(621,"target","लक्ष्य / निशाना","a goal or objective you aim to achieve","/ˈtɑːrɡɪt/","Business & Finance","noun/verb","A2",["goal","aim","objective"],["miss","fail"],"My daily target is to read 20 pages.","We hit our sales target two weeks early!","I always set clear targets before starting a project.","The marketing team exceeded the acquisition target.","The annual target was set at ₹1 crore in revenue.","Target: finish assignment by 9 PM. Status: failed!","'Hit/reach/meet a target' (success) vs 'miss a target' (failure). Always be specific when setting targets.",vf("target","targets","targeting","targeted","targeted")),
  w(622,"margin","अंतर / लाभ-अंतर","the difference between cost and selling price","/ˈmɑːrdʒɪn/","Business & Finance","noun","C1",["profit margin","gap","difference"],["loss","deficit"],"The profit margin on electronics is usually very thin.","We increased our margin by cutting unnecessary costs.","What is the margin on this product category?","Higher margins mean more money stays in the business.","The company maintained healthy margins despite inflation.","Write in the margin — don't fill the whole page!","'Profit margin' = what % of revenue is profit. Wide margins = very profitable. Thin margins = risky."),
  w(623,"liability","दायित्व / देनदारी","a debt or legal obligation","/ˌlaɪəˈbɪlɪti/","Business & Finance","noun","C1",["debt","obligation","responsibility"],["asset","credit"],"Loans are a liability until fully repaid.","The company's total liability exceeded ₹5 crore.","Understand your financial liabilities before investing.","Directors carry personal liability in certain legal cases.","Assets minus liabilities equals the company's net worth.","Too many subscriptions become a financial liability!","In accounting: liability = what you OWE. Opposite of asset = what you OWN. Know both!"),
  w(624,"asset","संपत्ति / परिसंपत्ति","something valuable that a person or company owns","/ˈæsɛt/","Business & Finance","noun","B2",["resource","property","possession"],["liability","debt"],"Your skills are your greatest professional asset.","The company's assets include land, machines, and patents.","Punctuality is an asset in any workplace.","Brand recognition is a valuable intangible asset.","The assets were listed in the company's balance sheet.","A positive attitude is a huge personal asset!","Assets can be tangible (building, machine) or intangible (brand, goodwill, skills). Both count!"),
  w(625,"equity","इक्विटी / हिस्सेदारी","ownership share in a company","/ˈɛkwɪti/","Business & Finance","noun","C1",["ownership","share","stake"],["debt","liability"],"He got 10% equity in the startup for his work.","Equity investors share in the company's profits and losses.","I earned sweat equity by working without a salary.","The firm raised ₹2 crore through equity financing.","Equity was distributed among founding team members.","She negotiated equity instead of a pay raise!","Equity = ownership. More equity = more profit share but also more risk. Common in startups."),
  w(626,"compete","प्रतिस्पर्धा करना","to try to win or be better than others","/kəmˈpiːt/","Business & Finance","verb","B1",["rival","contend","vie"],["cooperate","collaborate"],"We compete with global brands every day.","The startup competes in a crowded fintech market.","I always compete with my past self, not others.","Our company competes on quality, not on price alone.","The firm competes across 15 markets internationally.","I only compete in eating contests — and I win!","Compete WITH someone / FOR something: 'We compete with rivals for the same customers.'",vf("compete","competes","competing","competed","competed")),
  w(627,"benchmark","मानदंड / तुलना-स्तर","a standard used to measure or compare something","/ˈbɛntʃmɑːrk/","Business & Finance","noun/verb","C1",["standard","reference","yardstick"],["exception","deviation"],"This test score is the benchmark for admission.","Our team uses industry benchmarks to set KPIs.","I benchmark my performance against top performers.","The company benchmarked its processes against global leaders.","The benchmark report compared 50 companies across 10 metrics.","My benchmark for a good movie: under 2 hours!","'Set a benchmark' = establish a standard. 'Meet/exceed/fall below the benchmark' are common collocations."),
  w(628,"outsource","बाहर से काम करवाना","to hire an outside company to do work for you","/ˈaʊtsɔːrs/","Business & Finance","verb","C1",["contract out","subcontract","delegate"],["in-house","internalize"],"Many companies outsource their IT support.","We outsource content writing to freelancers in India.","Our HR is fully outsourced to a third-party agency.","Outsourcing reduces costs but requires strong vendor management.","The company outsourced payroll processing for efficiency.","I outsource cooking on Sundays — Swiggy it is!","Outsource = give your work to an outside company. In-source = do it yourself internally.",vf("outsource","outsources","outsourcing","outsourced","outsourced")),
  w(629,"overhead","ओवरहेड / सामान्य व्यय","regular business costs not related to making a product","/ˈoʊvərˌhɛd/","Business & Finance","noun","C1",["operating cost","expense","burden"],["revenue","income"],"Rent and electricity are monthly overhead costs.","Reducing overhead helped the startup become profitable faster.","High overhead eats into your profit margin quickly.","The company cut overhead by moving to remote work.","Overhead expenses were reduced by 30% through digitisation.","My biggest personal overhead? My data plan!","Overhead = costs you pay regardless of how much you sell — rent, salaries, utilities."),
  w(630,"fiscal","वित्तीय / आर्थिक","relating to government or company finances","/ˈfɪskəl/","Business & Finance","adjective","C1",["financial","monetary","economic"],["non-financial"],"The government announced the fiscal budget in February.","Q4 is the last quarter of our fiscal year.","Fiscal responsibility is key to a healthy economy.","The company's fiscal performance improved year on year.","The fiscal deficit was reduced through prudent spending cuts.","My fiscal policy at home: don't spend what you don't have!","'Fiscal year' is a company's 12-month financial period, often April–March in India."),
  w(631,"turnover","कारोबार / कर्मचारी बदलाव दर","total sales made, or rate at which employees leave","/ˈtɜːrnoʊvər/","Business & Finance","noun","C1",["revenue","sales","churn"],["retention"],"The company's annual turnover crossed ₹100 crore.","High employee turnover is costly for any organisation.","Our retail turnover increased by 18% this holiday season.","Staff turnover in the industry averages 25% annually.","The turnover figure was reported in the annual accounts.","High staff turnover? Maybe improve the free snacks!","'Business turnover' = total sales. 'Staff turnover' = rate of employees leaving. Two very different meanings!"),
  w(632,"disrupt","बाधित करना / क्रांति लाना","to change an industry dramatically with a new idea","/dɪsˈrʌpt/","Business & Finance","verb","C1",["innovate","transform","upend"],["maintain","preserve"],"Smartphones disrupted the camera and map industries.","Our startup is set to disrupt the edtech market.","Don't be afraid to disrupt your own business model.","Digital payment apps disrupted traditional banking methods.","The new entrant disrupted established players with aggressive pricing.","Jio disrupted India's telecom industry completely!","In business: disruption = positive change that upends traditional methods. Disruptors create new market leaders.",vf("disrupt","disrupts","disrupting","disrupted","disrupted")),
  w(633,"incentive","प्रोत्साहन / लालच","something that motivates a person to act","/ɪnˈsɛntɪv/","Business & Finance","noun","B2",["motivation","reward","bonus"],["disincentive","punishment"],"Performance bonuses are a great work incentive.","The government offers tax incentives for electric vehicles.","Give employees clear incentives to perform better.","A referral incentive program doubled customer acquisition.","Financial incentives were offered to early adopters.","The incentive? Free pizza if we finish by 6 PM!","'Create/offer/provide incentives.' Incentive = something desirable that pushes people to take action."),
  w(634,"penetrate","बाज़ार में प्रवेश करना","to successfully enter a new market","/ˈpɛnɪtreɪt/","Business & Finance","verb","C2",["enter","break into","access"],["exit","withdraw"],"The brand penetrated Tier 2 cities with small packs.","Our goal is to penetrate the Southeast Asian market.","How did you penetrate a market with 10 competitors?","Low pricing helped penetrate the rural healthcare market.","The firm penetrated the premium segment through partnerships.","We penetrated the local food market with fusion dishes!","'Market penetration' = gaining customers in a new or competitive market. A key growth strategy.",vf("penetrate","penetrates","penetrating","penetrated","penetrated")),
  w(635,"valuation","मूल्यांकन","the estimated market value of a company","/ˌvæljuˈeɪʃən/","Business & Finance","noun","C1",["appraisal","assessment","worth"],["undervaluation"],"The startup's valuation reached $1 billion — a unicorn!","Investors base funding decisions on company valuation.","Getting a realistic valuation is crucial before fundraising.","The valuation rose 10× after the product launch.","An independent valuation was commissioned before the acquisition.","My self-valuation: priceless — but I'm open to offers!","'Pre-money valuation' (before investment) vs 'post-money valuation' (after). Important startup terms."),
  w(636,"entrepreneur","उद्यमी / व्यवसायी","a person who starts and runs their own business","/ˌɒntrəprəˈnɜːr/","Business & Finance","noun","B2",["founder","business owner","innovator"],["employee","salaried worker"],"Every entrepreneur starts with an idea and courage.","She became an entrepreneur at 23 with just ₹50,000.","Tell me what motivates you as an entrepreneur.","Successful entrepreneurs fail many times before they succeed.","The entrepreneur raised ₹2 crore in seed funding.","I'm an entrepreneur — I sell samosas and I'm the boss!","Entrepreneur = someone who takes financial risk to start a business. Plural: entrepreneurs. Adj: entrepreneurial."),
  w(637,"stakeholder","हितधारक","a person with interest in or affected by a business","/ˈsteɪkhoʊldər/","Business & Finance","noun","C1",["shareholder","partner","investor"],["outsider"],"Customers are the most important stakeholders.","All stakeholders attended the quarterly review meeting.","I presented the business plan to key stakeholders.","Stakeholder buy-in is critical before any major change.","Each stakeholder was briefed on their roles.","Even my mom is a stakeholder in my exam results!","Internal stakeholders: employees, management. External: customers, government, investors. Both matter."),
  w(638,"brand","ब्रांड / पहचान","a company's identity, name, and reputation","/brænd/","Business & Finance","noun","A2",["trademark","identity","name"],["generic","unknown"],"Apple is the most valuable brand in the world.","We need to build a strong brand image online.","How would you improve a brand's social media presence?","Consistent messaging is the foundation of brand identity.","The brand was repositioned to target younger consumers.","My brand: reliable, funny, and usually late by 10 minutes!","'Brand' is not just a logo — it's the entire experience and perception customers have of a company."),
  w(639,"merger","विलय / एकीकरण","when two companies combine to form one","/ˈmɜːrdʒər/","Business & Finance","noun","C1",["union","consolidation","combination"],["split","separation"],"The merger created the country's largest bank.","Post-merger integration is one of the hardest processes.","The merger was approved by the board unanimously.","Both companies benefited from the cost savings post-merger.","The proposed merger underwent regulatory review for six months.","It was less a merger, more a hostile takeover!","'Merger' = two companies agree to join. 'Acquisition' = one company buys another. Both reshape industries."),
  w(640,"dividend","लाभांश","profit share paid to shareholders","/ˈdɪvɪdɛnd/","Business & Finance","noun","C1",["return","payout"],["loss"],"Hard work always pays a dividend eventually.","The company declared a dividend of ₹5 per share.","Investors choose dividend stocks for steady income.","The dividend yield was 3.5% — attractive for investors.","Dividends were paid quarterly to all registered shareholders.","Good habits pay dividends for life — try it!","Financial dividend = money paid to shareholders. Broader use: 'the dividend of hard work = success.'"),
  w(641,"collateral","संपार्श्विक / गिरवी","an asset pledged to secure a loan","/kəˈlætərəl/","Business & Finance","noun","C2",["security","guarantee","pledge"],["unsecured"],"He used his house as collateral for the business loan.","No collateral is needed for small personal loans below ₹2 lakh.","Banks require collateral for large credit facilities.","The startup offered shares as collateral for the bridge loan.","Collateral damage can extend beyond the intended target.","I offered my scooter as collateral — bank said no!","'Put up/offer collateral.' In banking: collateral protects the lender if borrower can't repay."),
  w(642,"recession","मंदी / आर्थिक संकट","a period of economic decline","/rɪˈsɛʃən/","Business & Finance","noun","C1",["downturn","slump","depression"],["boom","recovery"],"The 2008 recession affected millions of jobs worldwide.","Companies must plan for a potential economic recession.","During the recession, many small businesses shut down.","Cost-cutting is essential when a recession hits.","The recession was caused by a collapse in the housing market.","Even a chocolate recession would be too much to bear!","Two consecutive quarters of negative GDP growth = recession. Protect savings and reduce debt when it hits."),
  w(643,"inflation","मुद्रास्फीति / महंगाई","the rise in prices of goods over time","/ɪnˈfleɪʃən/","Business & Finance","noun","B2",["price rise","cost increase"],["deflation","price drop"],"Inflation has made groceries very expensive this year.","The RBI raised interest rates to control inflation.","Inflation affects purchasing power and savings value.","High inflation erodes the real value of your income.","Inflation remained above the target rate for three consecutive months.","Inflation is real — my chai went from ₹5 to ₹20!","Inflation = prices going UP. Deflation = prices going DOWN. India targets 4% inflation (RBI policy)."),
  w(644,"subsidy","सब्सिडी / आर्थिक सहायता","money given by the government to reduce costs","/ˈsʌbsɪdi/","Business & Finance","noun","B2",["grant","support","allowance"],["tax","charge"],"The government provides a subsidy on LPG cylinders.","Farmers receive a fertilizer subsidy to reduce costs.","The EV industry benefits from government subsidies.","Remove the subsidy and prices will rise immediately.","Agricultural subsidies were reviewed as part of fiscal reform.","Without that canteen subsidy, lunch would cost ₹200!","Subsidy = financial support given to REDUCE prices or help certain industries or groups."),
  w(645,"depreciation","मूल्य-ह्रास / अवमूल्यन","the reduction in value of an asset over time","/dɪˌpriːʃiˈeɪʃən/","Business & Finance","noun","C1",["devaluation","decline","wear"],["appreciation","growth"],"Depreciation reduces the book value of machinery each year.","The car's depreciation was 20% in its first year.","Accounting rules define how to calculate asset depreciation.","High depreciation means lower taxable income for the business.","Depreciation was calculated using the straight-line method.","My phone's value depreciated the moment I walked out of the store!","Depreciation = assets losing value over time. Appreciation = gaining value. Real estate usually appreciates."),
  w(646,"liquidate","परिसमापन करना / बेचना","to sell assets to convert them into cash","/ˈlɪkwɪdeɪt/","Business & Finance","verb","C2",["sell off","convert","dispose"],["hold","invest"],"He had to liquidate his shares to pay urgent bills.","The company liquidated non-core assets to raise capital.","During the crisis, they were forced to liquidate inventory.","Liquidating assets quickly may result in lower prices.","The firm was ordered to liquidate following insolvency proceedings.","I liquidated my candy bar collection — now just crumbs!","'Liquidate' = turn into liquid cash. A company that closes down must liquidate all assets.",vf("liquidate","liquidates","liquidating","liquidated","liquidated")),
  w(647,"portfolio","पोर्टफोलियो / कार्य-संग्रह","a collection of investments or work samples","/pɔːrtˈfoʊlioʊ/","Business & Finance","noun","B2",["collection","showcase","holdings"],["single asset"],"My investment portfolio includes stocks, gold, and funds.","Please share your design portfolio before the interview.","A diversified portfolio protects against market volatility.","The portfolio manager reallocated assets based on market trends.","The client reviewed the portfolio before approving the campaign.","My Netflix watchlist is my entertainment portfolio!","Investment portfolio = all your financial assets. Professional portfolio = samples of your work. Same word, two uses."),
  w(648,"fiscal year","वित्त वर्ष","a 12-month period used for financial planning and reporting","/ˈfɪskəl jɪər/","Business & Finance","noun","B2",["financial year","accounting year"],["calendar year"],"India's fiscal year runs from April 1 to March 31.","The company reported record profits for the fiscal year.","Budget planning starts six months before the fiscal year ends.","All financial statements are submitted at fiscal year close.","The fiscal year results exceeded analyst expectations by 12%.","By the end of the fiscal year, I need to file my taxes!","Fiscal year ≠ calendar year. In India: April–March. In the US: often January–December."),
  w(649,"ROI","निवेश पर लाभ (Return on Investment)","the gain or loss from an investment compared to its cost","/ɑːr.oʊ.aɪ/","Business & Finance","noun","C1",["return","profit ratio","yield"],["loss","negative return"],"Every campaign should be measured by its ROI.","The training program delivered a 300% ROI.","Can you calculate the ROI on this marketing spend?","ROI = (Gain − Cost) / Cost × 100%.","The project delivered a strong ROI within 6 months.","My ROI on that Netflix subscription: 100% happiness!","ROI = (Net Profit / Cost of Investment) × 100. Higher ROI = better use of money."),
  w(650,"KPI","प्रमुख प्रदर्शन संकेतक (Key Performance Indicator)","a measurable value showing how well something performs","/keɪ.piː.aɪ/","Business & Finance","noun","C1",["metric","indicator","measure"],["irrelevant data"],"Our KPIs include customer satisfaction and revenue growth.","We track weekly KPIs to monitor team performance.","What KPIs did you use to measure success in your role?","KPIs must be Specific, Measurable, Achievable, Relevant, and Time-bound.","The dashboard displays all operational KPIs in real time.","My personal KPI: 8 hours of sleep — rarely achieved!","KPIs should be SMART. Review them regularly. Vanity metrics (likes, followers) are NOT good KPIs."),

  // ─── Office Communication (651–700) ─────────────────────────────────────
  w(651,"agenda","कार्यसूची / एजेंडा","a list of topics to be discussed in a meeting","/əˈdʒɛndə/","Office Communication","noun","B2",["schedule","list","plan"],["improvisation"],"The meeting agenda was shared 24 hours in advance.","Please review the agenda before tomorrow's discussion.","I always prepare an agenda before any meeting.","The client agenda included product demo, pricing, and Q&A.","The formal agenda was circulated to all attendees.","No agenda? That meeting is going to be a waste!","'Agenda' = what you plan to DISCUSS. 'Minutes' = what you actually SAID. Both are meeting essentials."),
  w(652,"minutes","कार्यवृत्त / बैठक का विवरण","an official written record of what was discussed in a meeting","/ˈmɪnɪts/","Office Communication","noun","B2",["record","notes","proceedings"],["agenda","preview"],"Who will take the minutes in today's meeting?","The meeting minutes were emailed to all participants.","Review last week's minutes before we begin.","Minutes must accurately record all decisions made.","The secretary maintained the minutes of all board meetings.","I wasn't paying attention — can I see the minutes?","'Take/keep/record the minutes.' Minutes are written AFTER the meeting. Agenda is written BEFORE."),
  w(653,"delegate","सौंपना / प्रतिनिधि","to assign tasks to others; or a representative","/ˈdɛlɪɡeɪt/","Office Communication","verb/noun","B2",["assign","hand over","entrust"],["micromanage","hoard"],"Good managers know when to delegate tasks.","I delegated the report to my junior and reviewed it.","Effective leaders delegate without losing accountability.","The project manager delegated research tasks to the team.","Each delegate at the conference represented a different region.","I delegated cooking to my sister — she over-salted it!","Delegate tasks DOWN (to junior staff). Escalate issues UP (to managers). Both are important skills.",vf("delegate","delegates","delegating","delegated","delegated")),
  w(654,"collaborate","सहयोग करना / मिलकर काम करना","to work together with others","/kəˈlæbəreɪt/","Office Communication","verb","B2",["cooperate","partner","team up"],["compete","work alone"],"I love to collaborate with creative people.","Our teams collaborated across three different cities.","I collaborated with designers to build the app.","Cross-functional collaboration led to faster product delivery.","The two firms collaborated on a joint sustainability initiative.","I collaborated with my neighbour to complain about the noise!","Collaborate WITH someone ON something: 'We collaborated with the design team on the new interface.'",vf("collaborate","collaborates","collaborating","collaborated","collaborated")),
  w(655,"implement","लागू करना / कार्यान्वित करना","to put a plan or decision into action","/ˈɪmplɪmɛnt/","Office Communication","verb","B2",["execute","apply","carry out"],["ignore","abandon"],"We implemented the new policy across all departments.","It's time to implement the feedback we received.","I implemented a new filing system that saved 2 hours daily.","The team implemented the changes within the agreed timeline.","The policy was implemented after board-level approval.","We implemented a 'no meetings before 10 AM' rule — paradise!","Implement comes AFTER planning. You plan first, then implement. Don't skip the planning step.",vf("implement","implements","implementing","implemented","implemented")),
  w(656,"prioritize","प्राथमिकता देना","to decide which tasks are most important and do them first","/praɪˈɒrɪtaɪz/","Office Communication","verb","B2",["rank","order","sequence"],["procrastinate","postpone"],"I prioritize my top three tasks every morning.","Can you prioritize this request? It's urgent.","Successful people prioritize health, family, and work — in that order.","We need to prioritize customer feedback over internal reports.","Please prioritize the deliverables based on client urgency.","I prioritize sleep — everything else can wait till morning!","'Prioritize' = decide what matters MOST right now. Use urgency + importance grid (Eisenhower Matrix).",vf("prioritize","prioritizes","prioritizing","prioritized","prioritized")),
  w(657,"brief","संक्षेप में बताना / दस्तावेज़","a short summary of information; to give instructions","/briːf/","Office Communication","noun/verb","B2",["summary","instructions","overview"],["detail","elaborate"],"I prepared a brief for the client meeting.","The manager briefed the team before the presentation.","Keep your report brief — no more than two pages.","The marketing brief defined target audience and key message.","Each department head was briefed before the press conference.","Brief me on the weekend plans — quickly please!","As a noun: a document with instructions. As a verb: to inform someone. As adjective: short and concise.",vf("brief","briefs","briefing","briefed","briefed")),
  w(658,"follow-up","अनुवर्ती कार्रवाई","an action taken after a first meeting or event","/ˈfɒloʊ ʌp/","Office Communication","noun","B2",["check-in","continuation","reminder"],["ignore","drop"],"I sent a follow-up email after the interview.","Always do a follow-up within 24 hours of a meeting.","The follow-up call confirmed the client's decision.","We scheduled a follow-up to track action item progress.","The follow-up meeting was held one week after the initial discussion.","I waited for their follow-up — it never came!","Always follow up after interviews, meetings, and proposals. It shows professionalism and keeps you top of mind."),
  w(659,"debrief","समीक्षा करना / जानकारी लेना","to discuss what happened after an event or project","/ˌdiːˈbriːf/","Office Communication","verb","C1",["review","evaluate","recap"],["brief","preview"],"We debriefed after the product launch to learn lessons.","The team was debriefed after the client presentation.","A post-event debrief helps improve future projects.","The project manager conducted a debrief with all stakeholders.","After the campaign, a full debrief was held with the agency.","Full debrief after my exam: I should have studied more!","Debrief = look BACKWARD (after an event). Brief = look FORWARD (before an event). Both are essential.",vf("debrief","debriefs","debriefing","debriefed","debriefed")),
  w(660,"escalate","वरिष्ठ को बताना / बढ़ाना","to refer a problem to a higher authority","/ˈɛskəleɪt/","Office Communication","verb","C1",["refer","raise","elevate"],["resolve","handle"],"If you can't solve it, escalate to your manager.","The complaint was escalated to the regional director.","Don't wait — escalate the issue before the deadline.","The bug was escalated to the engineering lead for a fix.","The unresolved dispute was escalated to the legal team.","I escalated the slow internet complaint to three people — still slow!","Escalate = take the issue to someone with MORE authority. Use when you've tried but can't resolve it.",vf("escalate","escalates","escalating","escalated","escalated")),
  w(661,"streamline","सरल बनाना / व्यवस्थित करना","to make a process simpler and more efficient","/ˈstriːmlaɪn/","Office Communication","verb","C1",["simplify","optimise","improve"],["complicate","burden"],"We streamlined the approval process from 5 steps to 2.","Technology can streamline repetitive office tasks.","My goal is to streamline our reporting workflow.","The new software streamlined order management significantly.","The company streamlined operations to reduce costs by 20%.","I streamlined my morning routine — now I'm late in just 15 minutes!","Streamline = remove steps that don't add value. Always ask: 'Can this process be simpler?'",vf("streamline","streamlines","streamlining","streamlined","streamlined")),
  w(662,"turnaround","बदलाव / जल्दी काम पूरा करना","the time to complete a task, or a major improvement","/ˈtɜːrnəˌraʊnd/","Office Communication","noun","C1",["recovery","improvement","delivery time"],["delay","decline"],"The turnaround time for visa approval is 5 days.","What is your turnaround for this design project?","The company achieved a remarkable financial turnaround.","Fast turnaround is essential in client-facing roles.","A 24-hour turnaround was agreed upon with the client.","My turnaround on bad moods is a cup of chai and sleep!","Two meanings: 1) How fast you complete something. 2) Reversing a declining business/situation."),
  w(663,"circulate","वितरित करना / प्रसारित करना","to send or distribute something to many people","/ˈsɜːrkjʊleɪt/","Office Communication","verb","B2",["distribute","share","send"],["withhold","keep"],"Please circulate the agenda before the meeting.","The report was circulated to all department heads.","I circulated the survey link to 500 employees.","The memo was circulated internally for comment.","The draft proposal was circulated for review and feedback.","That embarrassing video circulated the whole office instantly!","'Circulate a document/report/memo' = send it to all relevant people. Very common in office communication.",vf("circulate","circulates","circulating","circulated","circulated")),
  w(664,"endorse","समर्थन करना / अनुमोदन देना","to officially approve or support something","/ɪnˈdɔːrs/","Office Communication","verb","C1",["approve","support","back"],["oppose","reject"],"The manager endorsed the project proposal.","I would endorse this candidate wholeheartedly.","The board endorsed the new sustainability policy.","Three senior leaders endorsed the initiative publicly.","The plan was endorsed by the committee after revisions.","She endorsed my samosa business — two thumbs up!","Endorse = public or official support. LinkedIn endorsements = colleagues confirming your skills.",vf("endorse","endorses","endorsing","endorsed","endorsed")),
  w(665,"liaison","संपर्क / मध्यस्थ","a person who acts as a link between groups","/liˈeɪzɒn/","Office Communication","noun","C1",["contact","link","mediator"],["barrier","obstacle"],"She acts as liaison between the client and our team.","Good liaison between departments prevents miscommunication.","I serve as the liaison for international operations.","The project liaison ensured smooth communication.","The regional liaison reported to headquarters weekly.","My mom is my family liaison — she tells everyone my business!","'Liaison officer' = a person assigned to communicate between two groups. 'Act as liaison' is very common."),
  w(666,"consensus","आम सहमति / सर्वसम्मति","general agreement among a group","/kənˈsɛnsəs/","Office Communication","noun","C1",["agreement","accord","unity"],["disagreement","conflict"],"We reached a consensus after a two-hour discussion.","Building consensus takes time but produces better results.","The team achieved consensus on the project timeline.","The policy was adopted after cross-functional consensus.","A consensus decision means everyone agrees — or at least accepts.","Consensus on dinner: biryani. Final answer.","'Reach/build/achieve consensus.' Consensus ≠ unanimous. It means most agree or nobody strongly objects."),
  w(667,"acknowledge","स्वीकार करना / मान लेना","to recognize or confirm you have received or understood something","/əkˈnɒlɪdʒ/","Office Communication","verb","B2",["confirm","recognise","accept"],["deny","ignore"],"Please acknowledge receipt of this email.","The manager acknowledged the team's hard work.","I acknowledge that I made an error in the report.","Always acknowledge emails within 24 hours.","The CEO acknowledged the staff's contribution at the event.","I acknowledged the problem — fixing it is another story!","'Acknowledge receipt' = confirm you got it. Very important in professional email communication.",vf("acknowledge","acknowledges","acknowledging","acknowledged","acknowledged")),
  w(668,"clarify","स्पष्ट करना","to make something clearer or easier to understand","/ˈklærɪfaɪ/","Office Communication","verb","B2",["explain","clear up","elaborate"],["confuse","obscure"],"Please clarify the deadline — is it Friday or Monday?","I asked the client to clarify their requirements.","Can you clarify what you mean by 'urgent'?","The project scope was clarified in writing to avoid confusion.","The HR team clarified the leave policy for all employees.","Can you clarify? I zoned out for the last 10 minutes.","'Clarify' vs 'Confirm': clarify = make unclear things clear. Confirm = verify something already said.",vf("clarify","clarifies","clarifying","clarified","clarified")),
  w(669,"postpone","स्थगित करना / टालना","to delay an event to a later time","/poʊstˈpoʊn/","Office Communication","verb","B2",["delay","defer","reschedule"],["advance","bring forward"],"The meeting was postponed due to the manager's travel.","I had to postpone my vacation for a project deadline.","Can we postpone the call to Thursday?","The product launch was postponed after testing issues.","The event was postponed to the following quarter.","I keep postponing my gym start date — next Monday again!","'Postpone' = push to a later time. 'Cancel' = not happening at all. Very different consequences!",vf("postpone","postpones","postponing","postponed","postponed")),
  w(670,"escalation","उच्चतर स्तर पर रेफरल","referring a problem to a higher level of authority","/ˌɛskəˈleɪʃən/","Office Communication","noun","C1",["referral","promotion","increase"],["resolution","downgrade"],"This complaint requires immediate escalation to the VP.","Escalation should be the last resort, not the first.","The escalation matrix defines who handles what issue.","An escalation was triggered after the client complained twice.","All escalations were logged and tracked in the CRM.","Escalation: when you complain to the manager and the manager complains to their manager!","Escalation path: Team Member → Manager → Director → VP → CEO. Use the right level!"),
  w(671,"minutes","कार्यवृत्त","official written record of what was decided in a meeting","/ˈmɪnɪts/","Office Communication","noun","B1",["record","notes","log"],["agenda"],"The meeting minutes were shared within 30 minutes.","Could you take the minutes today?","Refer to last week's minutes for the action items.","Minutes should capture decisions, owners, and deadlines.","The company secretary maintained minutes for all board meetings.","I missed the meeting — at least I can read the minutes!","'Take minutes' = write them. 'Read/review minutes' = look at past records. Not the same as 'agenda'."),
  w(672,"action item","कार्य-वस्तु","a specific task someone must complete after a meeting","/ˈækʃən ˌaɪtəm/","Office Communication","noun","B2",["task","to-do","assignment"],["discussion","idea"],"Each action item must have an owner and a deadline.","Review the action items from last week's meeting.","My action item: send the report by 5 PM Friday.","Action items were tracked in the shared project board.","All action items from the sprint review were assigned.","Action item from family meeting: someone clean the fridge — everyone is looking at me!","Action items must have 3 parts: WHAT (task), WHO (owner), WHEN (deadline). Without all 3, things get lost."),
  w(673,"workflow","कार्य-प्रवाह","the sequence of steps to complete a process","/ˈwɜːrkfloʊ/","Office Communication","noun","C1",["process","system","pipeline"],["disorder","chaos"],"Our content workflow goes from draft to review to publish.","I mapped out the approval workflow step by step.","Automating repetitive workflow steps saves hours weekly.","The development workflow followed an agile sprint cycle.","The approval workflow was redesigned to reduce bottlenecks.","My morning workflow: alarm, snooze, panic, rush!","Workflow = how work MOVES through a system. Optimise your workflow to eliminate bottlenecks and delays."),
  w(674,"turnaround time","पूरा करने का समय","time taken to complete and return a piece of work","/ˈtɜːrnəˌraʊnd taɪm/","Office Communication","noun","B2",["delivery time","response time"],["delay"],"Our turnaround time for proposals is 48 hours.","Fast turnaround time is a key competitive advantage.","What is your turnaround time for design revisions?","The client demanded a 24-hour turnaround on the contract.","Turnaround time was reduced from 5 days to 2 by automation.","Turnaround time for deciding where to eat: 45 minutes!","Turnaround time = from when you receive work to when you deliver it back. Keep it short and consistent."),
  w(675,"bandwidth","उपलब्ध समय / क्षमता","how much work a person or system can handle","/ˈbændwɪdθ/","Office Communication","noun","C1",["capacity","availability","resources"],["overload","limitation"],"I don't have the bandwidth to take on new projects.","Do you have bandwidth this week to help with the event?","Check team bandwidth before assigning more tasks.","The server's bandwidth was upgraded to handle peak traffic.","She doesn't have the bandwidth — her calendar is full.","No bandwidth for drama — I'm fully booked this week!","In tech: bandwidth = data speed. In work: bandwidth = how much capacity (time/energy) you have available."),
  w(676,"bottleneck","बाधा / रुकावट","a point in a process where things slow down","/ˈbɒtlnɛk/","Office Communication","noun","C1",["obstacle","delay","chokepoint"],["flow","efficiency"],"Approval delays are the bottleneck in our process.","Identify the bottleneck before trying to speed things up.","Data entry is the biggest bottleneck in our workflow.","The single-point review created a major process bottleneck.","Removing the bottleneck reduced delivery time by 30%.","Traffic jam at the signal — classic bottleneck!","Bottleneck = one slow point that slows EVERYTHING else. Fix the bottleneck first; the rest flows faster."),
  w(677,"deliverable","परिणाम / सुपुर्दगी-वस्तु","a specific output or result that must be produced","/dɪˈlɪvərəbəl/","Office Communication","noun","C1",["output","result","product"],["input","process"],"The main deliverable is a 10-page strategy report.","What are the key deliverables for this project?","Each deliverable has a deadline and an owner.","All deliverables were submitted on time and on budget.","The deliverables were reviewed and approved by the client.","My key deliverable this weekend: doing laundry. Delayed again!","Every project must have clear deliverables. 'What will you produce?' = deliverable."),
  w(678,"stakeholder management","हितधारक प्रबंधन","the process of keeping all involved parties happy and informed","/ˈsteɪkhoʊldər ˈmænɪdʒmənt/","Office Communication","noun","C2",["stakeholder engagement","communication"],["isolation"],"Effective stakeholder management ensures project success.","Stakeholder management requires clear, regular communication.","I managed 15 stakeholders across 3 departments.","Stakeholder management is a critical skill for project managers.","The PM's stakeholder management prevented a major conflict.","Stakeholder management at home: keeping parents and friends both happy!","Key: identify stakeholders early, understand their interests, and communicate proactively. No surprises!"),
  w(679,"KPIs","प्रमुख प्रदर्शन संकेतक","Key Performance Indicators — measurable goals","/keɪ.piː.aɪz/","Office Communication","noun","C1",["metrics","targets","indicators"],["vague goals"],"We review our KPIs every Monday morning.","What KPIs are you tracking for customer satisfaction?","Setting clear KPIs helps the team focus on results.","The dashboard displays all team KPIs in real time.","KPIs were revised at the start of each new quarter.","My personal KPI: inbox zero by 6 PM — always fails!","KPIs must be measurable and time-bound. 'Improve customer service' is NOT a KPI. 'Respond in <2 hrs' IS one."),
  w(680,"SOP","मानक संचालन प्रक्रिया (Standard Operating Procedure)","a step-by-step instruction for a standard process","/ɛs.oʊ.piː/","Office Communication","noun","C1",["procedure","protocol","guidelines"],["improvisation"],"Follow the SOP for onboarding new employees.","Every department should have SOPs for recurring tasks.","We created an SOP for social media posting.","The SOP ensures consistent quality across all branches.","SOPs were reviewed and updated at the start of each year.","Even morning chai has an SOP in this office!","SOP = a documented, repeatable process. SOPs reduce errors, save training time, and ensure consistency."),
  w(681,"sync","सिंक / तालमेल बनाना","to update or align information; an informal meeting","/sɪŋk/","Office Communication","verb/noun","B2",["align","update","coordinate"],["desync","disconnect"],"Let's sync on the project status this afternoon.","Are you synced with the latest version of the file?","I need to sync with the design team before the deadline.","Daily syncs help the team stay aligned on priorities.","A quick sync call was scheduled for Friday morning.","My Bluetooth and brain are both out of sync today!","'Quick sync' = short meeting to update each other. 'Sync up' = make sure everyone has the same information.",vf("sync","syncs","syncing","synced","synced")),
  w(682,"pivot","दिशा बदलना / नई रणनीति","to change direction or strategy","/ˈpɪvɪt/","Office Communication","verb","C1",["shift","change","redirect"],["persist","continue"],"The startup pivoted from B2C to B2B after poor sales.","We may need to pivot our approach based on feedback.","When one strategy fails, pivot — don't give up.","The team pivoted to a new product segment in Q3.","A strategic pivot was announced at the all-hands meeting.","Instagram pivoted from a whiskey app to a photo app — true story!","'Pivot' = change direction while keeping core strengths. Not giving up — it's adapting strategically.",vf("pivot","pivots","pivoting","pivoted","pivoted")),
  w(683,"bandwidth","उपलब्धता / क्षमता","capacity to take on more work","/ˈbændwɪdθ/","Office Communication","noun","B2",["capacity","availability"],["overload"],"Sorry, I don't have bandwidth for this right now.","Let's check team bandwidth before adding tasks.","The team's bandwidth is fully used this sprint.","I'll have more bandwidth after Tuesday's deadline.","Bandwidth is tight with three parallel projects running.","Zero bandwidth — my brain is full!","In modern offices, 'bandwidth' is commonly used to mean AVAILABLE TIME AND ENERGY, not internet speed."),
  w(684,"loop in","शामिल करना / जानकारी देना","to include someone in a conversation or email chain","/luːp ɪn/","Office Communication","phrasal verb","B2",["include","cc","inform"],["exclude","omit"],"Loop in the finance team before sending the proposal.","Please loop me in on any client communication.","I looped in the HR manager for the policy question.","Always loop in stakeholders before making major decisions.","The regional director was looped in via email.","Loop me in on the lunch plans — I'm coming!","'Loop in' or 'loop someone in' = make sure they're included and informed. 'Please loop in Priya.'"),
  w(685,"wrap up","समाप्त करना","to finish or conclude something","/ræp ʌp/","Office Communication","phrasal verb","A2",["finish","conclude","close"],["start","begin"],"Let's wrap up this meeting in 5 minutes.","I need 30 minutes to wrap up this report.","We wrapped up the project ahead of schedule.","Please wrap up your presentation by 3 PM.","The conference was wrapped up with a keynote address.","Wrap up the argument — I'm hungry and need dinner!","'Wrap up' = end something neatly and completely. 'Let's wrap up' is one of the most-used office phrases."),
  w(686,"reach out","संपर्क करना","to make contact with someone","/riːtʃ aʊt/","Office Communication","phrasal verb","A2",["contact","connect","get in touch"],["ignore","avoid"],"Please reach out to the client by tomorrow.","I reached out to three vendors for quotes.","Feel free to reach out if you have any questions.","Reach out to HR if you face any workplace issues.","The team lead reached out to the consultant for advice.","I reached out to my old friend — turns out they're married now!","'Reach out to someone' = make first contact. Very common in professional emails and LinkedIn messages."),
  w(687,"touch base","संक्षिप्त बातचीत करना","to briefly communicate with someone to stay updated","/tʌtʃ beɪs/","Office Communication","phrasal verb","B2",["check in","connect","update"],["ignore","avoid"],"I'll touch base with you after the client call.","Can we touch base tomorrow morning to align?","Let's touch base weekly to track progress.","The manager touched base with each team member briefly.","The director touched base with branch heads every Monday.","Touching base: 5-minute chat or 3-hour meeting? You decide!","'Touch base' = a quick, brief interaction to stay in sync. Usually informal. 'Just touching base!'"),
  w(688,"hand off","सौंपना / ट्रांसफर करना","to give responsibility or a task to someone else","/hænd ɒf/","Office Communication","phrasal verb","B2",["transfer","pass on","give over"],["retain","keep"],"I'll hand off the project to Priya on Friday.","Make sure all details are ready before the hand-off.","The client was handed off from sales to customer success.","A smooth hand-off prevents information loss.","The outgoing team member handed off all documentation.","Hand-off the TV remote only when the cricket match ends!","'Hand off' = transfer ownership of a task or responsibility. Document everything before handing off."),
  w(689,"sign off","मंजूरी देना / अनुमोदन","to give final approval to something","/saɪn ɒf/","Office Communication","phrasal verb","B2",["approve","authorize","confirm"],["reject","deny"],"Can you sign off on this invoice today?","The project needs the director's sign-off before launch.","I signed off on the final budget last evening.","All changes require manager sign-off before implementation.","The client signed off on the design after two rounds.","Signed off on the weekend plan — now the weather disagrees!","'Sign off on something' = give your formal approval. After sign-off, no more changes without re-approval."),
  w(690,"take the lead","नेतृत्व करना","to be in charge of directing something","/teɪk ðə liːd/","Office Communication","phrasal verb","B1",["lead","head","direct"],["follow","assist"],"I'd like to take the lead on this project.","She took the lead in organizing the team event.","Taking the lead shows confidence and initiative.","He took the lead during the client crisis and resolved it.","The senior analyst took the lead on the market study.","No one took the lead at dinner so we ordered everything!","'Take the lead' = volunteer or be assigned to lead. Shows initiative. Strong interview phrase: 'I took the lead on...'"),
  w(691,"sign off","कार्य पूर्ण करना","to formally finish and approve something","/saɪn ɒf/","Office Communication","phrasal verb","B2",["approve","authorize","close"],["reject","reopen"],"Please sign off on these timesheets by end of day.","The manager signed off on the campaign creative.","We can't go live until the legal team signs off.","Final sign-off requires C-suite authorization.","The client signed off on the final deliverable yesterday.","Boss signed off — we're going home early!","'Sign off' = final approval that closes a task or project. Nothing proceeds until sign-off."),
  w(692,"on the same page","एक ही समझ पर होना","to have the same understanding or agreement","/ɒn ðə seɪm peɪdʒ/","Office Communication","idiom","B1",["aligned","agreed","in sync"],["confused","misaligned"],"Let's confirm we're all on the same page before we proceed.","Are you and the client on the same page about scope?","I called a quick meeting to make sure we're on the same page.","After the debrief, everyone was finally on the same page.","The briefing ensured all stakeholders were on the same page.","We're not on the same page about whose turn it is to wash dishes!","'Get/be on the same page' = ensure everyone understands the same thing. A very common office idiom."),
  w(693,"take ownership","जिम्मेदारी लेना","to fully accept responsibility for something","/teɪk ˈoʊnərʃɪp/","Office Communication","idiom","B2",["be accountable","own","claim responsibility"],["blame others","avoid"],"I take ownership of my mistakes and fix them.","Taking ownership of tasks builds trust with your manager.","He took ownership of the failed launch and made changes.","Team members who take ownership are promoted faster.","The lead developer took ownership of the critical bug fix.","I take ownership of my terrible sense of direction!","'Take ownership' = don't make excuses, don't blame others — just do the work and own the result."),
  w(694,"moving forward","आगे बढ़ते हुए","from now on; going ahead with a plan","/ˈmuːvɪŋ ˈfɔːrwərd/","Office Communication","idiom","B1",["going forward","from now on","ahead"],["looking back","previously"],"Moving forward, all requests must be submitted in writing.","Let's focus on solutions, moving forward.","Moving forward, weekly check-ins will be mandatory.","Moving forward, the team will follow a new approval process.","The revised policy takes effect moving forward from April 1.","Moving forward, I will wake up at 6 AM. (Said every Sunday)","'Moving forward' = from this point on. Common in emails and meetings. Signals a shift in policy or approach."),
  w(695,"bandwidth","समय की उपलब्धता","availability of time and mental energy for tasks","/ˈbændwɪdθ/","Office Communication","noun","C1",["capacity","time","energy"],["overload","burnout"],"My bandwidth this week is very limited.","Before assigning work, check the person's bandwidth.","The team is at full bandwidth with existing projects.","With limited bandwidth, we must prioritize ruthlessly.","The manager assessed team bandwidth before adding deliverables.","Zero bandwidth — even breathing is scheduled!","A person's bandwidth is not infinite. Respecting it = respecting them. Overloading leads to burnout and errors."),
  w(696,"initiative","पहल / स्वयं आगे बढ़ना","taking action without being told to","/ɪˈnɪʃɪətɪv/","Office Communication","noun","B2",["enterprise","drive","proactivity"],["passivity","inaction"],"She took the initiative to redesign the client report.","I appreciate employees who show initiative.","Taking initiative shows you are a self-starter.","The initiative to automate billing saved 10 hours weekly.","The employee's initiative impressed the senior leadership team.","No one took initiative to refill the water cooler. Surprise!","'Take the initiative' = act first without waiting to be told. A highly valued workplace quality."),
  w(697,"align","तालमेल बिठाना / एक दिशा में करना","to bring things or people into agreement or arrangement","/əˈlaɪn/","Office Communication","verb","C1",["coordinate","sync","match"],["misalign","disagree"],"We need to align our goals with the company's vision.","Please align your work schedule with the team's deadlines.","The campaign message was aligned with brand guidelines.","All departments must align before the strategy is executed.","The regional and global teams were fully aligned on priorities.","My alarm and my body are not aligned — never will be!","'Align with' = match or agree with. 'Misalign' = when two things don't match. Both are common in management.",vf("align","aligns","aligning","aligned","aligned")),
  w(698,"proofread","प्रूफरीड / त्रुटि जांच करना","to carefully read and correct errors in a document","/ˈpruːfriːd/","Office Communication","verb","B1",["check","review","edit"],["ignore","skip"],"Always proofread before sending a professional email.","I proofreaded the report three times before submission.","Proofreading takes 10 minutes and saves hours of embarrassment.","The editor proofread the annual report for accuracy.","All marketing materials must be proofread before publishing.","I sent the email without proofreading — there were five mistakes!","Proofread = read specifically to FIND ERRORS. Different from editing (improving content). Do both!",vf("proofread","proofreads","proofreading","proofread","proofread")),
  w(699,"feedback","प्रतिक्रिया / सुझाव","information about how well something has been done","/ˈfiːdbæk/","Office Communication","noun","A2",["comments","response","review"],["silence","ignorance"],"I always welcome constructive feedback on my work.","The manager gave feedback after the presentation.","Feedback should be specific, timely, and actionable.","Customer feedback helped us improve the product significantly.","360-degree feedback was collected from all team members.","Feedback received: 'Your cooking needs improvement.' Feedback ignored.","'Give/receive/seek feedback.' 'Constructive feedback' = helpful criticism. 'Positive feedback' = praise."),
  w(700,"CC / BCC","कार्बन कॉपी / ब्लाइंड कार्बन कॉपी","carbon copy / blind carbon copy in email","/siː siː / biː siː siː/","Office Communication","abbreviation","B1",["copy","include","notify"],["omit","exclude"],"CC me on all client communications.","I BCC'd my manager on the vendor complaint.","CC = the person can see they were copied. BCC = they are hidden.","Always CC your supervisor when escalating to a client.","The email was sent to 10 recipients and CC'd to the director.","She BCC'd HR on the passive-aggressive team email. Smart move.","CC = recipients see everyone included. BCC = copied but invisible to others. Use BCC for privacy."),

  // ─── Career & Interview (701–750) ────────────────────────────────────────
  w(701,"competence","योग्यता / दक्षता","the ability to do something successfully","/ˈkɒmpɪtəns/","Career & Interview","noun","B2",["skill","ability","expertise"],["incompetence","inability"],"Technical competence alone is not enough in modern jobs.","She demonstrated clear competence in data analysis.","I built my competence in Python over six months.","The company values competence and cultural fit equally.","Core competencies were assessed in the structured interview.","My competence in cooking: limited to maggi and chai.","'Core competency' = a key strength your company or role is built around. Map your skills to job requirements."),
  w(702,"interpersonal","पारस्परिक / लोगों के साथ संबंध","relating to relationships between people","/ˌɪntərˈpɜːrsənəl/","Career & Interview","adjective","C1",["social","relational","communicative"],["introverted","anti-social"],"Strong interpersonal skills are essential in any team.","My interpersonal skills helped build client relationships.","Interpersonal communication includes listening, empathy, and feedback.","The role requires excellent interpersonal skills.","Interpersonal conflicts were resolved through structured mediation.","My interpersonal skills failed me at the networking event — I stood in a corner!","'Interpersonal skills' = how well you work WITH other people. Key for interviews, leadership, and client roles."),
  w(703,"initiative","पहल करना","acting without being asked; a new plan or programme","/ɪˈnɪʃɪətɪv/","Career & Interview","noun","B2",["drive","proactivity","enterprise"],["passivity","inaction"],"I launched a peer mentoring initiative at my last job.","Always take initiative — don't wait to be told.","Tell me about an initiative you led successfully.","The employee-led wellness initiative improved team morale.","The company launched a digital literacy initiative for staff.","Initiative: setting 10 alarms and still waking up at 9.","Interviewers love: 'I took the initiative to...' Use it with a specific example and quantified result."),
  w(704,"accountability","जवाबदेही / उत्तरदायित्व","being responsible for your actions and their results","/əˌkaʊntəˈbɪlɪti/","Career & Interview","noun","C1",["responsibility","answerability","ownership"],["irresponsibility","blame-shifting"],"Accountability means owning both successes and failures.","I value a culture of accountability in the workplace.","Tell me about a time you demonstrated accountability.","High accountability leads to faster, higher-quality results.","The team's accountability culture was cited as a key strength.","Accountability starts with: 'I made a mistake. Here's my fix.'","Accountability = doing what you said you'd do AND owning the result when it doesn't go as planned."),
  w(705,"resilient","लचीला / दृढ़","able to recover quickly from difficulties","/rɪˈzɪlɪənt/","Career & Interview","adjective","C1",["tough","adaptable","strong"],["fragile","brittle"],"A resilient team bounces back from setbacks faster.","I stay resilient under pressure and meet deadlines.","Tell me about a time you had to be resilient.","Resilient leaders inspire confidence during uncertain times.","The company remained resilient despite economic challenges.","I am resilient — I can watch a sad movie without crying. Sometimes.","Resilience = the ability to RECOVER, not the inability to struggle. Struggling + recovering = resilient."),
  w(706,"adaptable","अनुकूलनीय / परिस्थितिनुसार बदलने में सक्षम","able to adjust to new conditions or changes","/əˈdæptəbəl/","Career & Interview","adjective","B2",["flexible","versatile","open"],["rigid","inflexible"],"I am adaptable and thrive in fast-changing environments.","Adaptable employees are invaluable during company transitions.","My adaptable nature helped me succeed in three different roles.","The most successful companies build adaptable teams.","Adaptable professionals embrace change as an opportunity.","I'm adaptable — I can sleep anywhere, anytime!","Adaptability = willingness and ability to change. In interviews: 'I adapted when...' with a specific story."),
  w(707,"proactive","सक्रिय / पहले से तैयार","taking action before problems arise, not waiting to react","/proʊˈæktɪv/","Career & Interview","adjective","C1",["anticipatory","forward-thinking","initiative-taking"],["reactive","passive"],"I proactively flagged the issue before it became a crisis.","Proactive employees identify risks before they escalate.","I take a proactive approach to project management.","Proactive customer service prevents complaints from escalating.","The proactive team prepared contingency plans in advance.","Proactive: charging my phone before it hits 5%. Revolutionary!","Proactive = acting BEFORE problems happen. Reactive = responding AFTER. Employers want proactive people."),
  w(708,"quantify","मात्रा में बताना","to express something as a number or quantity","/ˈkwɒntɪfaɪ/","Career & Interview","verb","C1",["measure","calculate","assess"],["estimate","guess"],"Quantify your achievements — say '20%' not 'many'.","I quantified the impact of my work using data.","Can you quantify the savings your idea generated?","HR prefers quantified achievements over vague descriptions.","The analyst quantified the cost of the system failure.","How do I quantify how much I love chai? Impossible.","In resumes and interviews: quantify everything. 'Improved sales' is weak. 'Grew sales by 35% in 6 months' wins.",vf("quantify","quantifies","quantifying","quantified","quantified")),
  w(709,"articulate","स्पष्ट बोलना / व्यक्त करना","to express ideas clearly and effectively","/ɑːrˈtɪkjʊleɪt/","Career & Interview","verb/adjective","C1",["express","communicate","explain"],["mumble","confuse"],"She is very articulate and presents ideas brilliantly.","I can articulate complex ideas in simple terms.","Articulate professionals advance faster in their careers.","The CEO was articulate in explaining the company's new vision.","His articulate response impressed the interview panel.","I sounded very articulate in my head — not so much out loud!","'Articulate' as adjective = speaks clearly. As a verb: 'articulate your thoughts' = express them clearly.",vf("articulate","articulates","articulating","articulated","articulated")),
  w(710,"tenure","कार्यकाल / सेवा अवधि","the period of time someone holds a position","/ˈtɛnjər/","Career & Interview","noun","C1",["term","period","time in role"],["vacancy"],"During my tenure at XYZ, I led a team of 12.","She had a successful 5-year tenure as marketing head.","Tenure shows loyalty, but job-hopping shows ambition.","His tenure was marked by record revenue growth.","Academic tenure provides job security for professors.","My tenure at my last job: 2 years, 3 months, 14 days — but who's counting?","'During my tenure as...' is excellent interview language. Shows you can describe your time in a role professionally."),
  w(711,"analytical","विश्लेषणात्मक","able to examine things carefully and logically","/ˌænəˈlɪtɪkəl/","Career & Interview","adjective","C1",["logical","systematic","data-driven"],["intuitive","impulsive"],"I am highly analytical and love solving data problems.","Analytical skills are essential in finance and consulting.","My analytical approach helped identify a ₹5 lakh cost saving.","The analyst's analytical mindset prevented a major error.","Analytical competency was tested through a case study exercise.","My most analytical decision: spending 30 minutes choosing a movie.","'Analytical skills' = ability to break a problem into parts and think logically. Crucial in data-heavy roles."),
  w(712,"multitask","एक साथ कई काम करना","to do several tasks at the same time","/ˈmʌltiˌtæsk/","Career & Interview","verb","B2",["juggle","handle","manage"],["single-task","focus"],"I can multitask effectively without missing deadlines.","Avoid multitasking — it often reduces quality.","She multitasks effortlessly between client calls and reports.","Multitasking is a myth for complex, creative work.","The role requires the ability to multitask in a fast-paced environment.","I multitask: eating breakfast while sending emails — usually both poorly!","Research shows multitasking reduces quality. Better: 'I manage multiple priorities' instead of 'I multitask.'",vf("multitask","multitasks","multitasking","multitasked","multitasked")),
  w(713,"strengths","ताकत / गुण","the positive qualities or skills someone has","/strɛŋθs/","Career & Interview","noun","A2",["skills","abilities","talents"],["weaknesses","limitations"],"My strengths include communication and problem-solving.","Tell me about your strengths and how you use them.","Play to your strengths in every role.","Knowing your strengths helps you choose the right career.","Strengths were assessed through a self-evaluation exercise.","My strength: I always say yes. My weakness: also that I always say yes.","In interviews: mention strengths RELEVANT to the job. Back each one with a specific example. Be concrete."),
  w(714,"weakness","कमज़ोरी / दुर्बलता","a quality or skill that needs improvement","/ˈwiːknəs/","Career & Interview","noun","A2",["limitation","flaw","shortcoming"],["strength","asset"],"My weakness is that I overcommit and take on too much.","Turn a weakness into a growth story in interviews.","Always show how you're improving your weakness.","A common interview weakness: being too detail-oriented.","Weaknesses were discussed honestly in the 360-degree review.","Weakness: chocolate. I have no defence against it.","Interview tip: never say 'I have no weaknesses.' Pick a REAL one and show how you're working on it."),
  w(715,"accomplishment","उपलब्धि / सफलता","something you have done successfully","/əˈkɒmplɪʃmənt/","Career & Interview","noun","B2",["achievement","success","feat"],["failure","setback"],"List your top three professional accomplishments.","My biggest accomplishment was reducing churn by 40%.","Accomplishments speak louder than job titles.","She shared her accomplishments confidently and clearly.","Each accomplishment was quantified on the resume.","Personal accomplishment: finishing a book in one sitting — only happened once.","'Accomplishment' = something you FINISHED successfully. In interviews, use the STAR method: Situation, Task, Action, Result."),
  w(716,"contribution","योगदान","what you add to a team, project, or goal","/ˌkɒntrɪˈbjuːʃən/","Career & Interview","noun","B2",["input","addition","impact"],["withdrawal","absence"],"My key contribution was implementing the new billing system.","Tell me about your most significant contribution at work.","I made meaningful contributions to all three projects.","Her contribution to the team's growth was invaluable.","Each team member's contribution was recognised at the awards.","My biggest contribution to family dinners: eating everything!","In interviews: 'What will you contribute?' Frame your answer around the EMPLOYER'S NEEDS, not yours."),
  w(717,"value add","मूल्य-वर्धन","something that provides extra benefit beyond what's expected","/ˈvæljuː æd/","Career & Interview","noun","C1",["extra benefit","enhancement","bonus"],["cost","deduction"],"Strong communication skills are a value add in any role.","I bring value add through my bilingual proficiency.","What value add can you bring to our team?","The free training was a significant value add for employees.","Every hire should be a clear value add to the organisation.","Free chai during meetings is a major value add for me!","'Value add' = something EXTRA that makes you or your work more valuable. Always highlight yours."),
  w(718,"notice period","सूचना अवधि","time you must work before leaving a job","/ˈnoʊtɪs ˌpɪərɪəd/","Career & Interview","noun","B2",["transition period","exit period"],["immediate exit"],"My notice period is 60 days as per my contract.","Can you negotiate a shorter notice period?","Serving the full notice period is professional and respectful.","The candidate was available after completing the notice period.","Notice periods vary from 1 month to 3 months in India.","Notice period: the longest 30 days of your professional life!","Typical India notice period: 1–3 months. Negotiate a buyout if you need to join faster."),
  w(719,"appraisal","मूल्यांकन / प्रदर्शन समीक्षा","a formal review of an employee's performance","/əˈpreɪzəl/","Career & Interview","noun","B2",["review","assessment","evaluation"],["dismissal"],"My annual appraisal is scheduled for next month.","Prepare for your appraisal with data, not just effort.","I received an outstanding rating in my appraisal.","The appraisal process includes self-review and manager review.","Post-appraisal increments were announced in April.","Pre-appraisal mood: nervous. Post-appraisal mood: depends.","'Performance appraisal' = formal annual or half-yearly review that determines pay raises and promotions."),
  w(720,"CTC","कॉस्ट टू कंपनी (Cost to Company)","total yearly cost a company pays for an employee","/siː.tiː.siː/","Career & Interview","abbreviation","B2",["salary","package","compensation"],["take-home","net pay"],"My current CTC is ₹8 LPA — I'm looking for ₹12 LPA.","CTC includes salary, PF, gratuity, and all benefits.","Always clarify the in-hand amount separately from CTC.","The offer letter listed CTC of ₹10 lakh per annum.","CTC often looks larger than the actual take-home salary.","CTC ₹10 LPA sounds great until you see the take-home!","CTC ≠ In-hand. CTC includes employer PF, health insurance, bonuses. In-hand = what hits your bank account."),
  w(721,"KRA","प्रमुख जिम्मेदारी क्षेत्र (Key Result Area)","the main areas of work a person is responsible for","/keɪ.ɑːr.eɪ/","Career & Interview","abbreviation","C1",["responsibility","core task","objective"],["peripheral task"],"My KRAs are sales targets, client retention, and team leadership.","Set clear KRAs at the start of each quarter.","My manager and I defined my KRAs in the first week.","KRAs determine what you're evaluated on during appraisal.","Employees who exceed their KRAs are considered for fast-track promotions.","KRA: don't be late. Status: always late. Result: appraisal awkward.","KRA = what you are primarily ACCOUNTABLE for. KPI = how you MEASURE success in those areas. Both matter."),
  w(722,"exit interview","विदाई साक्षात्कार","a meeting when an employee is leaving to gather feedback","/ˈɛksɪt ˌɪntəvjuː/","Career & Interview","noun","B2",["farewell interview","offboarding meeting"],["onboarding"],"The HR team conducted an exit interview before I left.","Be honest but diplomatic in your exit interview.","Exit interviews help companies understand why employees leave.","She used the exit interview to give constructive feedback.","Exit interview insights were compiled in an annual retention report.","Exit interview question: 'Why are you leaving?' Answer: 'Netflix was calling.'","Be professional in exit interviews. Don't burn bridges — industries are smaller than you think."),
  w(723,"onboarding","नई नियुक्ति की प्रक्रिया","the process of introducing a new employee to the company","/ˈɒnbɔːrdɪŋ/","Career & Interview","noun","B2",["induction","orientation","training"],["offboarding","exit"],"The onboarding process took 2 weeks at my last company.","Good onboarding reduces employee turnover significantly.","I redesigned the onboarding program for new hires.","Smooth onboarding sets employees up for success.","The onboarding experience was rated 4.8/5 by new joiners.","Onboarding at my first job: here's your laptop, here's your tea, figure it out!","Effective onboarding = role clarity + team introductions + tools access + culture immersion. All four matter."),
  w(724,"lateral move","समकक्ष पद पर स्थानांतरण","changing to a job at the same level but in a different area","/ˈlætərəl muːv/","Career & Interview","noun","C1",["sideways move","transfer","shift"],["promotion","demotion"],"I made a lateral move from sales to marketing.","Lateral moves build diverse skills and broaden your career.","Not all growth is upward — lateral moves matter.","The company encouraged lateral moves to develop future leaders.","Her lateral move from operations to strategy proved transformative.","Promotion denied? Make a lateral move — gather skills instead!","Lateral move = same level, different function. Builds breadth. Useful when a vertical promotion isn't available."),
  w(725,"upskill","नए कौशल सीखना","to learn new skills to improve your abilities","/ˈʌpskɪl/","Career & Interview","verb","B2",["learn","train","develop"],["stagnate","ignore"],"I upskilled in Python during the lockdown.","Companies invest in upskilling to retain top talent.","You must continuously upskill to stay relevant.","The training programme was designed to upskill the sales team.","Employees who upskill regularly are promoted more frequently.","Upskilled in Excel — now I'm the office hero at pivot tables!","'Upskill' = learn NEW skills for your existing or future role. Reskill = learn different skills for a new role.",vf("upskill","upskills","upskilling","upskilled","upskilled")),
  w(726,"soft skills","सॉफ्ट स्किल्स / व्यवहारिक कौशल","non-technical interpersonal skills","/sɒft skɪlz/","Career & Interview","noun","B2",["people skills","communication skills"],["hard skills","technical skills"],"Soft skills like communication and empathy are crucial.","Employers value soft skills as much as technical ability.","I strengthened my soft skills through team leadership.","Soft skills are harder to teach than hard skills.","The assessment included both technical and soft skill evaluation.","I have excellent soft skills — I'm great at apologizing!","Soft skills: communication, empathy, teamwork, leadership. Hard skills: Excel, coding, accounting. BOTH are essential."),
  w(727,"hard skills","तकनीकी कौशल","specific, teachable technical abilities","/hɑːrd skɪlz/","Career & Interview","noun","B2",["technical skills","expertise","qualifications"],["soft skills"],"My hard skills include Python, SQL, and data visualisation.","List your hard skills with certification names.","Hard skills get you the interview; soft skills get you the job.","The role requires hard skills in project management tools.","Hard skills were verified through a technical assessment.","Hard skill: parallel parking. Mastery level: never achieved.","Hard skills can be learned and measured. Example: 'certified in Salesforce CRM' is a measurable hard skill."),
  w(728,"gap year","अंतराल वर्ष","a year taken off between studies or work to travel or grow","/ɡæp jɪər/","Career & Interview","noun","B2",["sabbatical","break","time off"],["continuity","uninterrupted career"],"I took a gap year to travel and find my purpose.","A gap year isn't a weakness — it's a story.","Explain your gap year positively in interviews.","She used her gap year to complete two certifications.","A gap year between jobs is becoming more accepted globally.","Gap year plan: travel the world. Actual gap year: sat at home in pyjamas.","Never apologise for a gap year. Frame it: 'I used that time to...' Focus on what you LEARNED or GAINED."),
  w(729,"references","सन्दर्भ / अनुशंसाकर्ता","people who can vouch for your work and character","/ˈrɛfrənsɪz/","Career & Interview","noun","B1",["testimonials","endorsements","recommendations"],["criticism"],"Please provide two professional references.","Always inform your references before sharing their details.","Strong references can make a big difference in hiring.","Her references praised her leadership and attention to detail.","References were contacted before the final offer was made.","Reference check: 'Is she punctual?' Reference sweating nervously.","Always ask permission before listing someone as a reference. Choose people who know your work, not just friends."),
  w(730,"self-starter","स्वयंप्रेरित व्यक्ति","someone who works independently without being told what to do","/ˌsɛlf ˈstɑːrtər/","Career & Interview","noun","C1",["independent worker","initiator","go-getter"],["passive","dependent"],"I am a self-starter — I identify and solve problems independently.","Startups need self-starters who don't need micromanagement.","Being a self-starter helped me build a side business.","The role is ideal for a self-starter comfortable with ambiguity.","Self-starters require minimal supervision and deliver results.","Self-starter: set 5 goals today. Starter-self: watched YouTube for 4 hours.","'Self-starter' in job descriptions = we won't hold your hand. Make sure you're truly comfortable with autonomy."),
  w(731,"go-getter","महत्वाकांक्षी व्यक्ति","an ambitious and highly motivated person","/ˈɡoʊ ˌɡɛtər/","Career & Interview","noun","B2",["achiever","ambitious person","driver"],["passive person"],"She's a real go-getter — she closes 3 deals a week.","I consider myself a go-getter who sets bold goals.","Go-getters don't wait for opportunities — they create them.","The company recruited go-getters for its fast-growth team.","His go-getter attitude made him a VP in just four years.","Go-getter energy: 8 AM gym, 9 AM meeting, 10 PM still working.","'Go-getter' = positive label for someone driven. Avoid saying 'I'm a go-getter' — show it with evidence instead."),
  w(732,"passion","जुनून / गहरी रुचि","a strong enthusiasm or love for something","/ˈpæʃən/","Career & Interview","noun","A2",["enthusiasm","love","drive"],["indifference","apathy"],"My passion for data led me to pursue a career in analytics.","Passion fuels persistence when the work gets hard.","What is your passion, and how does it relate to this role?","Her passion for education drove her to start an NGO.","Passion alone is not enough — skills must match.","My passion: food. My career: trying to make money to fund it.","In interviews: 'I am passionate about...' Back it up with ACTION — courses, projects, or side work."),
  w(733,"gap analysis","अंतराल विश्लेषण","comparing the current state to the desired state","/ɡæp əˈnælɪsɪs/","Career & Interview","noun","C2",["assessment","audit","review"],["assumption"],"A gap analysis revealed missing skills on the team.","Run a gap analysis before building a training programme.","I performed a gap analysis of our digital marketing strategy.","The gap analysis identified 5 areas needing immediate attention.","Results from the gap analysis informed the Q3 roadmap.","My personal gap analysis: skills I have vs skills I need. The list is long.","Gap analysis = current state vs desired state. The 'gap' = what needs to be fixed. Use it in strategy and HR."),
  w(734,"transferable skills","स्थानांतरणीय कौशल","skills that can be used in many different roles","/trænsˈfɜːrəbəl skɪlz/","Career & Interview","noun","C1",["portable skills","versatile skills"],["role-specific skills"],"Leadership is one of the most transferable skills.","Highlight transferable skills when switching industries.","My transferable skills include project management and communication.","Transferable skills give career changers an edge.","The candidate's transferable skills outweighed the experience gap.","Transferable skill: convincing people — works in sales AND at home!","Transferable skills work across roles and industries. Communication, leadership, and analytical thinking top the list."),
  w(735,"STAR method","STAR विधि (साक्षात्कार तकनीक)","a structured way to answer interview questions","/stɑːr ˈmɛθəd/","Career & Interview","noun","B2",["interview framework","structured response"],["unstructured answer"],"Use the STAR method for behavioral interview questions.","STAR = Situation, Task, Action, Result.","I practiced STAR answers for 10 common questions.","Strong STAR answers impress interviewers with clear examples.","The STAR method helped candidates articulate accomplishments clearly.","STAR method: I know the theory. Live interview: forgot everything!","STAR = Situation → Task → Action → Result. Use it for: 'Tell me about a time when...' questions. Always end with RESULT."),
  w(736,"compensation","मुआवज़ा / वेतन","pay and benefits an employee receives","/ˌkɒmpənˈseɪʃən/","Career & Interview","noun","C1",["salary","pay","remuneration"],["deduction","cost"],"My expected compensation is between ₹10–12 LPA.","Compensation includes salary, bonuses, and benefits.","Discuss compensation only after an offer is made.","The company offers competitive compensation and flexible hours.","Compensation was benchmarked against industry standards.","Compensation for my hard work: at least make the chai!","'Compensation' is more formal than 'salary.' Use it in professional negotiations. Know your market rate."),
  w(737,"leverage","लाभ उठाना / दबाव का उपयोग करना","to use something to your advantage","/ˈlɛvərɪdʒ/","Career & Interview","verb","C1",["utilise","use","exploit"],["ignore","waste"],"I leveraged my network to find this opportunity.","Leverage your strengths in every interview answer.","Use data to leverage your argument in salary negotiations.","The startup leveraged social media for zero-cost marketing.","The negotiator leveraged the competing offer successfully.","I leveraged my seniority to get the window seat!","'Leverage' = use something you have to gain an advantage. A very useful word in business and career contexts.",vf("leverage","leverages","leveraging","leveraged","leveraged")),
  w(738,"mentor","गुरु / मार्गदर्शक","an experienced person who guides and advises someone","/ˈmɛntər/","Career & Interview","noun","B2",["guide","advisor","coach"],["student","mentee"],"Find a mentor in your first job — it makes all the difference.","My mentor helped me navigate office politics early on.","A good mentor gives honest feedback, not just praise.","I mentor two junior developers every week.","The mentoring relationship lasted 5 years and shaped her career.","My mentor told me to speak up. Still working on it!","'Mentor' = guides with wisdom and experience. 'Coach' = helps you improve specific skills. Both are valuable."),
  w(739,"network","नेटवर्क / संपर्क जाल","a group of professional contacts you build over time","/ˈnɛtwɜːrk/","Career & Interview","noun/verb","B2",["contacts","connections","relationships"],["isolation"],"My professional network helped me find this role.","Networking is not about collecting business cards — it's about relationships.","I network at conferences and on LinkedIn.","A strong network opens doors that skills alone cannot.","She built a network of 500 professionals in her first year.","Networking event: I spoke to the appetizers mostly.","'Network' as verb: 'I regularly network in my industry.' LinkedIn, alumni meets, and conferences are best places.",vf("network","networks","networking","networked","networked")),
  w(740,"job description","नौकरी का विवरण","a document detailing the duties and requirements of a job","/dʒɒb dɪˈskrɪpʃən/","Career & Interview","noun","A2",["JD","role profile","job spec"],["job offer"],"Read the job description carefully before applying.","The job description matched my skills and experience perfectly.","I tailored my resume to each job description.","The job description specified 5 years of experience in Python.","Job descriptions often list 'must-have' and 'nice-to-have' skills.","Job description says '2 years experience required' — hired a fresher anyway!","Map your skills to the job description point-by-point. Match their language in your cover letter and resume."),
  w(741,"elevator pitch","संक्षिप्त आत्म-परिचय","a brief, persuasive description of yourself or your idea","/ˈɛlɪveɪtər pɪtʃ/","Career & Interview","noun","B2",["introduction","self-pitch","summary"],["long presentation"],"Practice your elevator pitch until it sounds natural.","My elevator pitch: 'I'm a data analyst who turns numbers into stories.'","You have 60 seconds — make your elevator pitch count.","The entrepreneur delivered a compelling elevator pitch at the summit.","Elevator pitches should be clear, confident, and memorable.","My elevator pitch was great — until the elevator reached my floor!","Elevator pitch = 30–60 second answer to 'Tell me about yourself.' Include: who you are, what you do, what you want."),
  w(742,"shortlist","शॉर्टलिस्ट / चयनित सूची","a list of selected candidates for the final round","/ˈʃɔːrtlɪst/","Career & Interview","noun/verb","B2",["select","screen","filter"],["reject","eliminate"],"I was shortlisted for the final round of interviews.","Only 5 candidates were shortlisted from 200 applicants.","Tailor your resume to get shortlisted.","The hiring team shortlisted 10 candidates for assessment.","Shortlisted candidates were notified by email.","I was shortlisted for pizza toppings decision — prestigious!","Getting shortlisted = making it past initial screening. The next step: interview rounds. Polish your resume!",vf("shortlist","shortlists","shortlisting","shortlisted","shortlisted")),
  w(743,"panel interview","पैनल साक्षात्कार","an interview with multiple interviewers at once","/ˈpænəl ˈɪntəvjuː/","Career & Interview","noun","B2",["group interview"],["one-on-one interview"],"I had a panel interview with HR, the manager, and a director.","Panel interviews assess how you handle multiple perspectives.","Address all panel members equally, not just the senior person.","The panel interview lasted 90 minutes and was very thorough.","Panel interviews are common in government and corporate hiring.","Panel of 5 people. Me: panicking. Classic panel interview.","In a panel interview: make eye contact with each person. Answer the question while addressing the whole group."),
  w(744,"probation period","परिवीक्षा अवधि","an initial trial period at a new job","/prəˈbeɪʃən ˌpɪərɪəd/","Career & Interview","noun","B2",["trial period","initial period"],["permanent status"],"My probation period is 6 months.","Perform your best during the probation period — it's your foundation.","The company extends probation if performance is below expectations.","I successfully completed probation and received a glowing review.","Probation performance determines confirmation as a permanent employee.","Probation period: they're watching everything. ACT accordingly.","During probation: be punctual, ask questions, document your work, meet goals, and BUILD TRUST."),
  w(745,"letter of intent","आशय-पत्र","a document expressing your intention to take a job or apply","/ˈlɛtər əv ɪnˈtɛnt/","Career & Interview","noun","C1",["LOI","cover letter","application"],["rejection"],"Submit a letter of intent with your application.","My letter of intent explained why I want this specific role.","A strong letter of intent can outweigh a mediocre CV.","The letter of intent was reviewed by the department head.","The university required a letter of intent for the PhD program.","Letter of intent: 'I intend to work here and eat all the free food.'","Letter of Intent (LOI) = your motivation to join. Different from a cover letter (which summarises your qualifications)."),
  w(746,"severance","छंटनी भत्ता / नौकरी समाप्ति पर मिलने वाला मुआवज़ा","compensation given to an employee when their job ends","/ˈsɛvərəns/","Career & Interview","noun","C2",["termination pay","exit package"],["bonus","reward"],"He received three months' severance when the company downsized.","Negotiate severance terms before signing a contract.","Severance packages vary by company policy and tenure.","The departing director received a generous severance package.","Severance was paid in lieu of the notice period.","Severance: the silver lining of being let go.","Severance = money paid when employment is TERMINATED. Know your rights — it's usually one month per year served."),
  w(747,"headhunter","हेडहंटर / प्रतिभा शिकारी","a recruiter who approaches people for specific job roles","/ˈhɛdˌhʌntər/","Career & Interview","noun","C1",["executive recruiter","talent scout"],["applicant","job seeker"],"A headhunter reached out to me on LinkedIn.","Headhunters are paid by companies to find specific talent.","If a headhunter contacts you, your reputation precedes you.","Top headhunters specialise in C-suite recruitment.","The headhunter placed her in a senior role within 2 weeks.","Being headhunted: feel like a celebrity. For 5 minutes, at least.","Headhunters are recruiters who FIND YOU. Opposite of a job portal where you find them. Both paths work."),
  w(748,"counter offer","प्रति-प्रस्ताव","an offer made in response to another offer, usually in salary talks","/ˈkaʊntər ˌɒfər/","Career & Interview","noun","C1",["counter proposal","revised offer"],["original offer"],"I made a counter offer asking for ₹2 lakh more.","Always be ready to negotiate and make a counter offer.","The employer accepted my counter offer after a day.","Counter offers from the current employer should be assessed carefully.","A counter offer was exchanged and a final package agreed upon.","Counter offer accepted. Now my current boss wants to fight.","Counter offer = your response to their initial offer. Research market rates so your counter is justified."),
  w(749,"work-life balance","कार्य-जीवन संतुलन","maintaining a healthy balance between work and personal life","/wɜːrk laɪf ˈbæləns/","Career & Interview","noun","B2",["balance","wellbeing","harmony"],["overwork","burnout"],"I choose companies that prioritise work-life balance.","Work-life balance means different things to different people.","My team ensures work-life balance by respecting off-hours.","Poor work-life balance leads to burnout and decreased productivity.","The company's work-life balance policy included flexible hours.","Work-life balance: work from home + no commute = still overworking.","Work-life balance is about BOUNDARIES. Set them early. 'Hustle culture' glorifies overwork — it's not sustainable."),
  w(750,"appraise","मूल्यांकन करना","to evaluate something or someone's performance or value","/əˈpreɪz/","Career & Interview","verb","C1",["evaluate","assess","review"],["ignore","overlook"],"The manager appraised each team member quarterly.","Self-appraise honestly before your official review.","Properties are appraised by certified valuers.","The director appraised the project's ROI before approving it.","Staff were appraised using a 360-degree feedback model.","My cat appraised me and decided I was an acceptable couch.","'Appraise' = formally evaluate. 'Appraisal' = the process. 'Appraiser' = person who does it.",vf("appraise","appraises","appraising","appraised","appraised")),

  // ─── Academic & Study Skills (751–800) ───────────────────────────────────
  w(751,"comprehend","समझना / आत्मसात करना","to understand something fully","/ˌkɒmprɪˈhɛnd/","Academic & Study","verb","C1",["understand","grasp","absorb"],["misunderstand","confuse"],"I read the chapter twice before I could comprehend it.","Good readers comprehend both meaning and tone.","Did you fully comprehend the assignment instructions?","Students were tested on their ability to comprehend complex texts.","The researcher took time to comprehend the full dataset.","I comprehend the theory; the exam disagrees.","Comprehend > understand. Use in formal writing. 'Reading comprehension' = how well you understand what you read.",vf("comprehend","comprehends","comprehending","comprehended","comprehended")),
  w(752,"synthesize","संश्लेषण करना / मिलाकर समझना","to combine information from different sources into one idea","/ˈsɪnθɪsaɪz/","Academic & Study","verb","C2",["combine","integrate","merge"],["separate","isolate"],"A good essay synthesizes ideas from multiple sources.","I synthesized findings from 10 research papers.","Synthesize, don't just summarize — add your own insight.","The report synthesized customer feedback from three markets.","The student synthesized theory and practice effectively.","Synthesizing information takes practice — it's not just copy-paste!","Summarize = repeat. Synthesize = combine DIFFERENT ideas into a NEW insight. Synthesis is a higher-order skill.",vf("synthesize","synthesizes","synthesizing","synthesized","synthesized")),
  w(753,"hypothesis","परिकल्पना","a proposed explanation that needs to be tested","/haɪˈpɒθɪsɪs/","Academic & Study","noun","C1",["theory","assumption","proposition"],["fact","proof"],"My hypothesis is that students learn better with examples.","Form a hypothesis before starting any experiment.","The hypothesis was tested through controlled experiments.","A good hypothesis must be specific and falsifiable.","The research hypothesis was rejected based on the data.","Hypothesis: studying the night before works. Result: does not.","Hypothesis → Experiment → Data → Conclusion. The scientific method in 4 steps."),
  w(754,"argument","तर्क / दलील","a reason or set of reasons to support an idea","/ˈɑːrɡjʊmənt/","Academic & Study","noun","B1",["claim","reasoning","point"],["fallacy","contradiction"],"Build a strong argument with evidence, not emotion.","The essay's central argument was clear and convincing.","What is your main argument in this assignment?","The student's argument was well-structured and supported.","The debate required each team to present a logical argument.","My argument with myself at midnight: 'Should I study?' 'Yes.' 'But...'","In academic writing: an argument is a REASONED CLAIM supported by evidence. It must be logical, not emotional."),
  w(755,"evidence","प्रमाण / साक्ष्य","facts or information that support a claim","/ˈɛvɪdəns/","Academic & Study","noun","B1",["proof","support","data"],["opinion","conjecture"],"Always support your argument with evidence.","The evidence clearly showed a link between sleep and memory.","Cite your evidence with proper references.","Strong evidence makes a weak argument strong.","The courtroom evidence was presented over three days.","Evidence for why I should stay home: this couch is comfortable.","In academic writing: every claim needs evidence. Evidence includes data, examples, quotes, and research findings."),
  w(756,"thesis","थीसिस / शोध प्रबंध","the main argument of an essay or a research dissertation","/ˈθiːsɪs/","Academic & Study","noun","C1",["argument","dissertation","paper"],["disproof"],"State your thesis clearly in the first paragraph.","Her PhD thesis challenged existing theories of memory.","A strong thesis statement is specific, debatable, and clear.","The thesis was reviewed by three external examiners.","I spent 6 months writing and rewriting my thesis.","Thesis statement: crisp. Thesis submission: always late.","Thesis (essay) = main argument. Thesis (postgrad) = a long research paper submitted for a degree."),
  w(757,"citation","उद्धरण / स्रोत संदर्भ","a reference to the source of information you have used","/saɪˈteɪʃən/","Academic & Study","noun","B2",["reference","quote","footnote"],["plagiarism"],"Add a citation whenever you use someone else's idea.","APA and MLA are two common citation styles.","Missing citations leads to plagiarism penalties.","Each fact was supported with a proper citation.","The bibliography listed 35 citations from peer-reviewed journals.","Citation style: perfect in my head, always wrong on paper.","Cite your sources — always. 'Give credit where credit is due.' No citation = potential plagiarism."),
  w(758,"plagiarism","साहित्यिक चोरी","copying someone else's work and claiming it as your own","/ˈpleɪdʒərɪzəm/","Academic & Study","noun","C1",["copying","theft","cheating"],["originality","integrity"],"Plagiarism can result in expulsion from university.","Always cite sources to avoid accidental plagiarism.","Turnitin is a tool that detects plagiarism in submitted work.","Her assignment was flagged for plagiarism due to missing citations.","Academic institutions take plagiarism very seriously.","Plagiarism check passed: somehow my essay was 0% original, 100% copied. Oops.","Plagiarism = taking credit for work you didn't create. Even unintentional plagiarism can have serious consequences."),
  w(759,"paraphrase","अपने शब्दों में कहना","to restate something in your own words","/ˈpærəfreɪz/","Academic & Study","verb","B2",["rephrase","reword","restate"],["copy","quote"],"Don't copy text — paraphrase it in your own words.","Paraphrasing shows you truly understand the material.","I paraphrased the concept to explain it to my classmate.","The student paraphrased the source without changing the meaning.","Paraphrasing is an essential academic writing skill.","I paraphrased my essay so well my teacher thought it was original!","Paraphrase = same idea, YOUR words. Different from summarize = shorter. Different from quote = exact words.",vf("paraphrase","paraphrases","paraphrasing","paraphrased","paraphrased")),
  w(760,"curriculum","पाठ्यक्रम","the subjects and courses taught in an educational programme","/kəˈrɪkjʊləm/","Academic & Study","noun","B2",["syllabus","course","programme"],["elective","optional"],"The curriculum was updated to include digital literacy.","The school's curriculum covers STEM and arts equally.","I designed a curriculum for the English speaking workshop.","The university curriculum was redesigned based on industry needs.","Students were consulted before finalising the new curriculum.","The curriculum said 'no mobile phones.' The students disagreed.","Curriculum (whole programme) vs Syllabus (specific course). Curriculum = bigger, syllabus = smaller and more specific."),
  w(761,"annotate","व्याख्या लिखना / टिप्पणी करना","to add notes or comments to a text","/ˈænəteɪt/","Academic & Study","verb","C1",["comment","note","mark"],["ignore"],"I annotate every book I read with my own thoughts.","Students were asked to annotate the passage for homework.","Annotating helps you engage more deeply with the material.","The teacher annotated the essay with feedback.","The PDF was annotated using digital highlighting tools.","My annotations are 90% question marks and 10% 'what?'","Annotate = write notes IN or BESIDE the text. Creates a conversation between you and the author.",vf("annotate","annotates","annotating","annotated","annotated")),
  w(762,"revise","पुनरीक्षण करना / दोबारा पढ़ना","to review and improve, or to study again before an exam","/rɪˈvaɪz/","Academic & Study","verb","B2",["review","edit","re-study"],["ignore","submit"],"I revise my notes every Sunday to retain information.","Revise the essay once before you submit it.","Revising under pressure is harder than studying early.","The research team revised the paper after peer review.","Students revised all 10 chapters the night before the exam.","Revision plan: excellent. Execution: Netflix then panic.","In UK English, 'revise' = study before an exam. In writing: revise = improve and edit your draft.",vf("revise","revises","revising","revised","revised")),
  w(763,"abstract","सारांश / सार-तत्व","a brief summary of a longer academic text","/ˈæbstrækt/","Academic & Study","noun","C1",["summary","overview","synopsis"],["full text","detail"],"Write a 150-word abstract before submitting your paper.","I read the abstract first to decide if the paper is relevant.","A strong abstract contains the problem, method, and findings.","The abstract was the most read part of the published paper.","Each conference paper required a 200-word abstract.","Read the abstract: 30 seconds. Read the full paper: 3 hours. Worth it!","Abstract = what the paper is ABOUT in brief. It should answer: Why? How? What did you find? So what?"),
  w(764,"peer review","सहकर्मी समीक्षा","evaluation of academic work by other experts","/pɪər rɪˈvjuː/","Academic & Study","noun","C2",["peer evaluation","expert review"],["self-assessment"],"All our research is peer reviewed before publication.","Peer review improves the quality of academic work.","The paper passed peer review and was published in Nature.","Students conducted peer reviews of each other's essays.","Peer review provides critical feedback from knowledgeable readers.","Peer review of my essay: 'This needs more work.' Understatement.","Peer review = independent check by experts in the same field. It is the gold standard of academic quality."),
  w(765,"seminar","सेमिनार / विचार-गोष्ठी","a small, interactive class or academic session","/ˈsɛmɪnɑːr/","Academic & Study","noun","B2",["workshop","session","class"],["lecture","solo study"],"The seminar had 15 students and lots of discussion.","I attend a weekly seminar on machine learning.","Seminars are more interactive than lectures.","The professor led a three-hour seminar on postcolonial theory.","The seminar required students to come prepared with arguments.","Seminar participation: 10% insight, 90% hoping no one calls on me.","Seminar = small interactive group discussion. Lecture = one person speaking to many. Both are important."),
  w(766,"assess","मूल्यांकन करना","to evaluate or judge something carefully","/əˈsɛs/","Academic & Study","verb","B2",["evaluate","judge","measure"],["ignore","skip"],"Teachers assess students through assignments and exams.","Assess your own understanding before the test.","The committee assessed the project's feasibility.","Students were assessed on content, structure, and clarity.","The risk was assessed before the implementation began.","Assessed myself as 'exam-ready.' The exam had other opinions.","'Assess' is used in academic, medical, and business contexts. More formal than 'check' or 'look at.'",vf("assess","assesses","assessing","assessed","assessed")),
  w(767,"methodology","कार्यप्रणाली / शोध-विधि","the specific methods used in research or a project","/ˌmɛθəˈdɒlədʒi/","Academic & Study","noun","C2",["approach","method","technique"],["random approach"],"My research methodology included surveys and case studies.","Explain your methodology clearly in the report.","A mixed-methods methodology was used in the study.","The methodology chapter is the backbone of a good dissertation.","The research methodology was approved by the ethics committee.","Methodology: 'I made it up as I went.' Research board: 'Please don't.'","Methodology = the SYSTEM of methods you use. A single method vs a methodology = one tool vs a whole toolbox."),
  w(768,"dissertation","शोध-प्रबंध","a long research document required for a postgraduate degree","/ˌdɪsəˈteɪʃən/","Academic & Study","noun","C1",["thesis","research paper"],["essay","assignment"],"I spent 8 months writing my master's dissertation.","Your dissertation must demonstrate original research.","Submit the dissertation draft to your supervisor first.","The dissertation was 20,000 words and passed with distinction.","Dissertation defence is a formal oral examination of your research.","Dissertation status: started, abandoned, restarted, nearly done, crying.","Dissertation = major research project for a Master's or PhD. Typically 10,000–100,000 words depending on level."),
  w(769,"literature review","साहित्य समीक्षा","a summary and analysis of existing research on a topic","/ˈlɪtrɪtʃər rɪˈvjuː/","Academic & Study","noun","C2",["review of research","bibliographic analysis"],["original research"],"My literature review covered 50 published papers.","The literature review shows what is already known.","A good literature review identifies gaps in current knowledge.","The literature review took three weeks to complete.","Reviewers praised the comprehensive literature review.","Literature review: reading 50 papers to say 'we need more research.'","Lit review = map of existing knowledge. It shows WHERE your research fits and WHY it is needed."),
  w(770,"inference","अनुमान / निष्कर्ष","a conclusion drawn from evidence","/ˈɪnfərəns/","Academic & Study","noun","C1",["conclusion","deduction","interpretation"],["assumption","guess"],"Draw a logical inference from the given data.","Critical reading involves making inferences between the lines.","The researcher's inference was supported by three datasets.","Students must make inferences when information is implied.","The inference was validated through follow-up experimentation.","Inference: they stopped replying = they're not interested. Mostly correct.","Inference = conclusion reached through REASONING. Different from assumption, which may have no evidence."),
  w(771,"critique","आलोचना / समालोचना","a detailed evaluation or analysis of something","/krɪˈtiːk/","Academic & Study","noun/verb","C1",["analysis","review","appraisal"],["praise","endorsement"],"Write a critique of the article, not just a summary.","Her critique of the policy was sharp and evidence-based.","I critiqued three case studies for my management course.","A fair critique acknowledges both strengths and weaknesses.","The design critique led to significant improvements in the product.","Critique: 'Your essay needs work.' Me: 'Which parts?' 'All of it.'","Critique ≠ criticize. A critique is ANALYTICAL and BALANCED — it evaluates fairly, not just negatively.",vf("critique","critiques","critiquing","critiqued","critiqued")),
  w(772,"outline","रूपरेखा / ढाँचा","a plan showing the main points of something","/ˈaʊtlaɪn/","Academic & Study","noun/verb","B1",["plan","framework","structure"],["rambling","disorganized"],"Create an outline before writing your essay.","I outlined my presentation into three main sections.","A clear outline keeps your essay focused and structured.","The project outline was approved by the supervisor.","Students submitted a chapter outline before beginning the draft.","Outline: 5 minutes. Actual essay: 5 hours. Still worth doing.","Outline first, write second. An outline prevents you from going off-track and losing marks for structure.",vf("outline","outlines","outlining","outlined","outlined")),
  w(773,"cite","उद्धृत करना / हवाला देना","to reference the source of information you have used","/saɪt/","Academic & Study","verb","B2",["quote","reference","attribute"],["plagiarise"],"Always cite your sources in academic writing.","I cited 20 peer-reviewed articles in my paper.","Did you cite the data or did you make it up?","All cited works must appear in the reference list.","The student cited APA style correctly throughout the essay.","Forgot to cite one source — marked down 5%. Lesson learned.","Cite = point to where your information came from. No citation = no credibility, or worse, plagiarism.",vf("cite","cites","citing","cited","cited")),
  w(774,"rubric","मूल्यांकन मानदंड / रूब्रिक","a set of criteria used to grade or evaluate work","/ˈruːbrɪk/","Academic & Study","noun","C1",["criteria","grading guide","marking scheme"],["random grading"],"Check the rubric before starting your assignment.","The rubric weights creativity at 30% and content at 40%.","My work scored full marks against every rubric criterion.","The professor shared the rubric at the start of the semester.","Rubric-based grading ensures fairness and transparency.","I read the rubric AFTER submitting. Never again.","A rubric breaks a grade into specific, measurable criteria. It removes subjectivity. Always read it first!"),
  w(775,"semester","सत्र / सेमेस्टर","a half-year academic term","/sɪˈmɛstər/","Academic & Study","noun","A2",["term","session","period"],["year"],"I'm in my second semester of the MBA programme.","The semester starts in July and ends in November.","Each semester has its own set of courses and deadlines.","Results were published two weeks after the semester ended.","The exchange student joined in the second semester.","My semester plan: study hard. Reality: coffee and last-minute panic.","Most universities: 2 semesters per year. Some: 3 trimesters. Know your academic calendar — it prevents surprises."),
  w(776,"tutor","ट्यूटर / निजी शिक्षक","a private teacher who helps one-on-one","/ˈtjuːtər/","Academic & Study","noun","A2",["teacher","instructor","coach"],["student"],"I hire a tutor for mathematics every week.","My English tutor helped me become fluent in 6 months.","She tutors three students in the evening.","A good tutor asks questions — they don't just explain.","The tutor prepared personalised study materials for each student.","My English tutor: this app. My math tutor: also this app!","Tutor = personal, one-on-one teaching. More focused than a classroom teacher. Great for specific skill gaps."),
  w(777,"assignment","गृह-कार्य / असाइनमेंट","a task given to a student to complete outside class","/əˈsaɪnmənt/","Academic & Study","noun","A2",["task","project","homework"],["exam","test"],"I have three assignments due this week.","Submit your assignment by midnight on Friday.","This assignment asks you to compare two business models.","The assignment was weighted at 40% of the final grade.","All assignments must be submitted via the online portal.","Assignment submitted at 11:59 PM. Grace under pressure.","Assignment (task given to you) vs project (larger, often group work) vs exam (in-class test). Know the difference."),
  w(778,"extracurricular","पाठ्येतर / अतिरिक्त गतिविधियाँ","activities outside the regular academic programme","/ˌɛkstrəkəˈrɪkjʊlər/","Academic & Study","adjective","B2",["outside class","co-curricular","extra-academic"],["academic","curricular"],"Extracurricular activities build leadership and social skills.","I led the drama club as an extracurricular commitment.","Employers value extracurricular achievements on resumes.","The school offered 15 extracurricular clubs and sports.","Extracurricular experience was factored into university admissions.","Extracurricular activities: I watched Netflix. Does that count?","Extracurricular = activities beyond formal study. Sports, clubs, volunteering, events. List them on your CV!"),
  w(779,"GPA","ग्रेड पॉइंट औसत (Grade Point Average)","a student's average academic grade","/dʒiː.piː.eɪ/","Academic & Study","abbreviation","B1",["grade average","academic score"],["individual grade"],"My GPA was 3.8 out of 4.0 in my undergraduate degree.","A high GPA opens doors to top universities and scholarships.","Some employers still ask for GPA in entry-level hiring.","I maintained a 9.2 CGPA throughout my engineering course.","GPA requirements vary by university and programme.","Studying hard for a 10 GPA. Got an 8. Still proud!","GPA (US) = 4.0 scale. CGPA (India) = 10.0 scale. Both measure academic performance across all subjects."),
  w(780,"internship","इंटर्नशिप","a short-term work experience while studying","/ˈɪntɜːrnʃɪp/","Academic & Study","noun","B1",["work placement","traineeship","work experience"],["full-time job"],"I did a 3-month internship at a marketing agency.","Internships give students real-world experience.","My internship was unpaid, but the learning was invaluable.","The company hired 5 interns who performed well.","The internship programme offered mentorship and live projects.","Internship task: make tea AND do analysis. Did both.","Internships are stepping stones. Even unpaid ones build your portfolio, network, and resume. Take them seriously."),
  w(781,"deadline","अंतिम तिथि","the last date or time by which something must be done","/ˈdɛdlaɪn/","Academic & Study","noun","A2",["due date","cutoff","submission date"],["extension","grace period"],"My assignment deadline is tomorrow night at 11:59 PM.","Always start before the deadline — never at it.","Missing deadlines has academic and professional consequences.","The student requested an extension to the submission deadline.","All project deadlines were tracked on the shared calendar.","Deadline: 11:59 PM. Started: 11:30 PM. Finished: 11:58 PM. Warrior.","Missing academic deadlines = grade penalties. Missing professional deadlines = reputation damage. Respect both!"),
  w(782,"rubric","श्रेणीकरण मानदंड","grading criteria with clear descriptions of performance levels","/ˈruːbrɪk/","Academic & Study","noun","C1",["marking scheme","grading guide"],["random grading"],"I designed a rubric for the oral presentation assessment.","Always read the rubric — it tells you exactly how you'll be graded.","The rubric had four levels: excellent, good, satisfactory, and failing.","The rubric was shared a week before the assignment was due.","Rubric-based grading gave students clear feedback on improvement.","Finally read the rubric. Turns out content was only 30%. Formatting was 70%. Oops.","Rubric = a table showing what you need to do to earn each grade. It's your roadmap to a top score."),
  w(783,"critical thinking","आलोचनात्मक सोच","the ability to analyse and evaluate information objectively","/ˈkrɪtɪkəl ˈθɪŋkɪŋ/","Academic & Study","noun","C1",["analytical thinking","logical reasoning"],["passive acceptance"],"Critical thinking is the most important skill for the 21st century.","I apply critical thinking to evaluate news and information.","Universities aim to develop students' critical thinking skills.","Critical thinking helped identify flaws in the study design.","The interview tested candidates' critical thinking through case studies.","Critical thinking: questioning everything, even this sentence.","Critical thinking = don't accept information at face value. Ask: What's the evidence? Who says so? What's missing?"),
  w(784,"scholarship","छात्रवृत्ति","financial support given to students to study","/ˈskɒlərʃɪp/","Academic & Study","noun","B1",["grant","bursary","award"],["loan","debt"],"I received a full scholarship to study engineering.","Scholarships reduce the financial burden of higher education.","Apply early — most scholarships have limited seats.","The scholarship covered tuition, accommodation, and travel.","The merit scholarship was awarded to the top 10 students.","Applied for 10 scholarships. Got 1. Worth every application!","Scholarship (merit-based) vs bursary (need-based) vs grant (for research). Know which type you're applying for."),
  w(785,"learning curve","सीखने की अवस्था","the process of getting better at something over time","/ˈlɜːrnɪŋ kɜːrv/","Academic & Study","noun","B2",["growth process","adjustment"],["instant mastery"],"There is a steep learning curve when starting a new job.","Every skill has a learning curve — embrace it.","I got through the learning curve for Python in about 3 weeks.","New software always has a short but steep learning curve.","Patience and practice flatten any learning curve over time.","My learning curve for cooking: still a very steep uphill road!","'Steep learning curve' = hard to learn quickly. 'Shallow curve' = easy to pick up. Embrace both with patience."),
  w(786,"cognitive","संज्ञानात्मक","relating to mental processes like thinking, learning, and memory","/ˈkɒɡnɪtɪv/","Academic & Study","adjective","C2",["mental","intellectual","cerebral"],["physical","emotional"],"Exercise improves cognitive performance in students.","Cognitive load affects how much you can learn at one time.","Sleep deprivation impairs cognitive function significantly.","The test measured cognitive skills, not just subject knowledge.","Cognitive science explores how the human mind processes information.","My cognitive function peaks at 10 AM and crashes at 3 PM.","Cognitive = related to HOW THE MIND WORKS. Cognitive skills include memory, attention, problem-solving, and reasoning."),
  w(787,"procrastinate","टालमटोल करना","to delay doing something you should do","/prəˈkræstɪneɪt/","Academic & Study","verb","C1",["delay","postpone","stall"],["act","begin"],"I procrastinate when a task feels overwhelming.","Stop procrastinating — start with just 5 minutes.","Procrastinating costs more stress than the task itself.","The student procrastinated for two weeks and then panicked.","Chronic procrastination is linked to anxiety, not laziness.","I procrastinate on procrastinating. Meta.","Procrastination is not laziness — it's often fear or perfectionism. Break tasks into tiny steps to overcome it.",vf("procrastinate","procrastinates","procrastinating","procrastinated","procrastinated")),
  w(788,"bibliography","ग्रंथ-सूची","a list of all sources used in a piece of writing","/ˌbɪblɪˈɒɡrəfi/","Academic & Study","noun","C1",["reference list","works cited","sources"],["text","body"],"Add a bibliography at the end of your research paper.","A bibliography is mandatory for all academic submissions.","I formatted my bibliography in APA style.","The bibliography listed 45 sources from 8 countries.","The professor checked the bibliography for citation accuracy.","My bibliography was longer than my essay — I over-researched!","Bibliography (all sources you read) vs reference list (only sources you cited). Know the difference!"),
  w(789,"module","मॉड्यूल / विषय-इकाई","a self-contained unit of a course","/ˈmɒdjuːl/","Academic & Study","noun","B2",["unit","section","course"],["programme","degree"],"I completed 6 modules in the first semester.","Each module has its own assignments and final assessment.","The data science module was my favourite of the year.","Modules can be elective (chosen) or compulsory.","The online platform delivers each module through video and quiz.","Module on statistics: loved the graphs, hated the math.","Module = one course/subject within a larger programme. You get separate marks for each module."),
  w(790,"tutorial","ट्यूटोरियल / निर्देशिका","a teaching session for a small group; or an instructional guide","/tjuːˈtɔːrɪəl/","Academic & Study","noun","B1",["lesson","session","guide"],["lecture"],"I watch YouTube tutorials to learn new software skills.","The tutorial covered the first three chapters of the textbook.","Online tutorials make self-study much easier.","The professor's tutorial group met every Thursday afternoon.","Step-by-step tutorials are available on the university portal.","Tutorial: 10 minutes long. Time I spent: 3 hours rewatching it.","Tutorial (academic) = small teaching session. Tutorial (tech) = step-by-step instructional guide. Both are useful!"),
  w(791,"retention","याद रखने की क्षमता","the ability to remember and keep information","/rɪˈtɛnʃən/","Academic & Study","noun","C1",["memory","recall","retention rate"],["forgetting","loss"],"Spaced repetition improves information retention significantly.","Sleep plays a critical role in long-term memory retention.","Regular review boosts retention of vocabulary words.","The training focused on knowledge retention through active recall.","Student retention rates improved after the new curriculum was introduced.","My retention: 100% for movie quotes, 0% for exam formulas.","Retention = remembering information LONG-TERM. Sleep, revision, and practice all improve retention. No magic shortcut."),
  w(792,"abstract reasoning","अमूर्त तर्क","thinking logically about patterns and relationships, not concrete facts","/ˈæbstrækt ˈriːzənɪŋ/","Academic & Study","noun","C2",["logical reasoning","pattern recognition"],["factual recall"],"Abstract reasoning is tested in most aptitude exams.","Strong abstract reasoning is essential for problem-solving roles.","Practice pattern-based questions to develop abstract reasoning.","The psychometric test included a 20-minute abstract reasoning section.","Abstract reasoning ability was assessed during the selection process.","Abstract reasoning question: which shape comes next? Me: yes.","Abstract reasoning = thinking about rules and patterns, not specific content. Tested in IQ tests and aptitude exams."),
  w(793,"submission","जमा करना / प्रस्तुति","the act of handing in work for assessment","/səbˈmɪʃən/","Academic & Study","noun","B1",["submission","entry","upload"],["withdrawal","rejection"],"The submission portal closes at midnight tonight.","Late submissions are penalised by 10% per day.","I submitted my assignment on time and received full marks.","Submissions must be in PDF format with cover page.","All submissions are automatically checked for plagiarism.","Submission: 11:58 PM. Server crash: 11:59 PM. My life in chaos.","'Submission' in UK/India universities = turning in your work. 'Extension' = extra time when you need more."),
  w(794,"invigilate","परीक्षा की निगरानी करना","to watch over students during an exam","/ɪnˈvɪdʒɪleɪt/","Academic & Study","verb","C2",["supervise","monitor","watch"],["examine","sit"],"Three teachers invigilated the three-hour exam.","The hall was silent while the invigilator checked the room.","Invigilators ensure exams are conducted fairly.","Only certified staff are allowed to invigilate university exams.","The invigilator confiscated a mobile phone during the paper.","Invigilator walked past. Heart rate: 200 BPM. Reason: innocent.","Invigilate (UK English) = proctor (US English). The person who watches during an exam to prevent cheating.",vf("invigilate","invigilates","invigilating","invigilated","invigilated")),
  w(795,"rote learning","रटना / याद करना","learning by memorizing without deeper understanding","/roʊt ˈlɜːrnɪŋ/","Academic & Study","noun","B2",["memorisation","cramming"],["conceptual learning","understanding"],"Rote learning helps with vocabulary but not with essays.","India's education system has long relied on rote learning.","Rote learning is effective for facts, not for application.","Modern education encourages understanding over rote learning.","Students who rely only on rote learning struggle in practical exams.","Rote learning: I know ALL the words. I understand NONE of them.","Rote learning = memorising WITHOUT understanding. Useful for tables, vocabulary, dates. Risky for exams that test application."),
  w(796,"active recall","सक्रिय स्मरण","the method of testing yourself to strengthen memory","/ˈæktɪv rɪˈkɔːl/","Academic & Study","noun","C2",["self-testing","retrieval practice"],["passive reading","highlighting"],"Active recall is the most effective study technique.","Use flashcards for active recall after reading a chapter.","I scored 90% because I practised active recall every day.","Active recall forces your brain to retrieve information.","Research shows active recall outperforms passive re-reading.","Active recall vs highlighting: one works, one is colourful.","Active recall = close the book and TRY to remember. This forces your brain to strengthen the memory pathway."),
  w(797,"spaced repetition","अंतराल पुनरावृत्ति","reviewing material at increasing intervals over time","/speɪst ˌrɛpɪˈtɪʃən/","Academic & Study","noun","C2",["interval review","delayed practice"],["cramming","binge studying"],"Spaced repetition is the science behind Anki flashcards.","I use spaced repetition to memorise vocabulary efficiently.","Review material at Day 1, 3, 7, 14, 30 — that's spaced repetition.","Spaced repetition takes longer but produces permanent memory.","Language learners who use spaced repetition progress 40% faster.","Spaced repetition: studying now so future-me suffers less. Genius.","Spaced repetition = review right before you forget. It's the most efficient way to transfer info to long-term memory."),
  w(798,"Socratic method","सुकराती पद्धति","a teaching method based on asking and answering questions","/səˈkrætɪk ˈmɛθəd/","Academic & Study","noun","C2",["questioning method","critical dialogue"],["lecturing","telling"],"The Socratic method challenges students to think, not just recall.","Law schools often use the Socratic method in classrooms.","A good teacher uses the Socratic method to guide discovery.","The Socratic method develops critical thinking through dialogue.","The professor used the Socratic method to help students form conclusions.","Socratic method: teacher asks questions. Student panics. Learning happens.","Socratic method = learning through QUESTIONS, not answers. Named after the Greek philosopher Socrates."),
  w(799,"metacognition","मेटाकॉग्निशन / स्वयं की सोच के बारे में सोचना","thinking about your own thinking and learning process","/ˌmɛtəkɒɡˈnɪʃən/","Academic & Study","noun","C2",["self-reflection","self-awareness of learning"],["unconscious learning"],"Metacognition improves how efficiently you study.","Ask yourself: 'Do I really understand this, or just think I do?'","Metacognition is the key difference between good and great students.","Metacognitive learners know WHEN to slow down and revisit.","Metacognition was found to be a top predictor of academic success.","Metacognition: knowing you don't know. A superpower.","Metacognition = awareness and control of your OWN learning. Plan, monitor, and evaluate how you study."),
  w(800,"exam anxiety","परीक्षा की चिंता","stress or fear before or during an exam","/ɪɡˈzæm æŋˈzaɪɪti/","Academic & Study","noun","B2",["test anxiety","exam stress","nervousness"],["confidence","calm"],"Exam anxiety is normal and can be managed.","Deep breathing helps reduce exam anxiety before a paper.","I overcame exam anxiety through mock tests and preparation.","Severe exam anxiety can impair even well-prepared students.","The university offered counselling sessions for exam anxiety.","Exam anxiety: body in the hall, brain on vacation.","Manage exam anxiety with: good preparation, sleep, breathing exercises, mock tests, and positive self-talk."),

  // ─── Advanced Adjectives (801–850) ───────────────────────────────────────
  w(801,"meticulous","सावधान / बारीकी से काम करने वाला","extremely careful and precise","/mɪˈtɪkjʊləs/","Advanced Adjectives","adjective","C1",["precise","thorough","detailed"],["careless","sloppy"],"She is meticulous about formatting every document.","My meticulous approach to testing caught the critical bug.","A surgeon must be meticulous in every procedure.","The meticulous report was praised by all stakeholders.","His meticulous attention to detail set him apart.","I am meticulous about coffee — three sugars, exact temperature.","Meticulous = extremely careful about small details. Often a positive quality in professional and academic contexts."),
  w(802,"eloquent","वाकपटु / स्पष्ट और प्रभावशाली वक्ता","fluent, persuasive, and well-expressed","/ˈɛləkwənt/","Advanced Adjectives","adjective","C1",["articulate","expressive","fluent"],["inarticulate","mumbling"],"She gave an eloquent speech that moved the audience.","His eloquent writing style impressed the editorial board.","Being eloquent in English opens doors in professional life.","The eloquent presentation earned a standing ovation.","She was eloquent, confident, and utterly persuasive.","I'm eloquent in my mind. Out loud: very different story.","Eloquent = speaking or writing in a clear, moving, and well-expressed way. A very powerful compliment."),
  w(803,"persistent","दृढ़ / हठी","continuing despite difficulties or opposition","/pərˈsɪstənt/","Advanced Adjectives","adjective","B2",["determined","tenacious","relentless"],["giving up","quitting"],"Persistent effort is the key to mastering any language.","She was persistent in chasing her dream despite setbacks.","His persistent follow-up secured the deal.","The persistent student improved her grade from C to A.","Persistent complaints from customers led to a product redesign.","Persistent: me asking mom if we have food every 5 minutes.","Persistent = keeps going even when it's hard. Persistence = the noun. 'Keep going' in one word."),
  w(804,"versatile","बहुमुखी / विविध क्षमताओं वाला","able to adapt to many different functions","/ˈvɜːrsətaɪl/","Advanced Adjectives","adjective","C1",["flexible","adaptable","multipurpose"],["narrow","limited"],"She is a versatile professional — design, writing, and coding.","Python is a versatile programming language for any domain.","A versatile player is valuable to any sports team.","Versatile employees are promoted faster in dynamic companies.","The versatile candidate impressed with her range of skills.","Chapati is versatile — sabji, roll, or just with butter!","Versatile = useful in MANY different ways. A versatile skill set makes you more employable and promotable."),
  w(805,"coherent","सुसंगत / तार्किक रूप से जुड़ा हुआ","logically connected and easy to understand","/koʊˈhɪərənt/","Advanced Adjectives","adjective","C1",["logical","clear","consistent"],["incoherent","confusing"],"Your essay must be coherent from start to finish.","A coherent strategy requires alignment across all teams.","The proposal was well-organised and completely coherent.","His explanation was so coherent that even beginners understood.","The coherent argument was easy to follow and accept.","My explanation made perfect sense. Not coherent to anyone else.","Coherent (ideas connect logically) vs Cohesive (ideas flow smoothly). Both are needed in good writing."),
  w(806,"pragmatic","व्यावहारिक / व्यवहारवादी","dealing with things realistically and practically","/præɡˈmætɪk/","Advanced Adjectives","adjective","C1",["practical","realistic","sensible"],["idealistic","theoretical"],"Take a pragmatic approach to solving this problem.","She is a pragmatic leader who focuses on what works.","Be pragmatic — not every decision can be perfect.","The company made a pragmatic choice to cut costs.","The pragmatic solution was cheaper and faster to implement.","Pragmatic decision: skip the gym today, sleep is better.","Pragmatic = focused on what actually works, not ideals. 'A pragmatic solution' = one that is realistic, not just pretty."),
  w(807,"innovative","अभिनव / नवाचारी","introducing new and creative ideas","/ˈɪnəveɪtɪv/","Advanced Adjectives","adjective","B2",["creative","pioneering","original"],["conventional","traditional"],"The company is known for its innovative products.","I brought an innovative approach to customer onboarding.","An innovative mindset drives growth in any organisation.","The innovative campaign reached 10 million users on Day 1.","Innovative thinkers challenge the status quo.","My most innovative idea: a mute button for loud colleagues.","'Innovative' is overused — back it up with a specific example of what you actually created or changed."),
  w(808,"strategic","रणनीतिक / दूरदर्शी","relating to long-term planning and goals","/strəˈtiːdʒɪk/","Advanced Adjectives","adjective","C1",["planned","calculated","long-term"],["reactive","impulsive"],"Every decision in business should be strategic.","Strategic thinking is what separates managers from leaders.","I took a strategic break to rebuild my skills.","A strategic partnership opened new markets in Southeast Asia.","Strategic hiring was critical to the company's scale-up plan.","Strategic plan for weekend: rest. Actual plan: ruin it with procrastination.","Strategic = done with clear PURPOSE and LONG-TERM thinking. Not just smart — deliberately planned for the future."),
  w(809,"transparent","पारदर्शी","open, honest, and not secretive","/trænsˈpærənt/","Advanced Adjectives","adjective","B2",["open","honest","clear"],["secretive","opaque"],"Be transparent with your team about project challenges.","Transparent leadership builds trust quickly.","I am transparent about my progress and blockers.","The company's transparent pricing model won customer loyalty.","Transparent communication was cited as a company strength.","Transparent: I told them I didn't finish. They appreciated it.","'Be transparent about...' = openly share information. Transparency in business = honesty with customers and employees."),
  w(810,"empathetic","सहानुभूतिपूर्ण","able to understand and share others' feelings","/ˌɛmpəˈθɛtɪk/","Advanced Adjectives","adjective","C1",["compassionate","understanding","sensitive"],["cold","indifferent"],"A good leader is empathetic and listens actively.","She is empathetic — she always understands how I feel.","Being empathetic is essential in customer service roles.","Empathetic managers have lower staff turnover rates.","The empathetic response calmed the upset customer immediately.","I try to be empathetic. My face doesn't always agree.","Empathetic = you FEEL and UNDERSTAND what others are going through. Different from sympathetic = you feel FOR them."),
  w(811,"tenacious","दृढ़निश्चयी / हठी","holding firmly to something; very determined","/tɪˈneɪʃəs/","Advanced Adjectives","adjective","C2",["persistent","stubborn","resolute"],["giving up","flexible"],"Tenacious learners succeed even without natural talent.","She was tenacious in her pursuit of the scholarship.","His tenacious negotiation style secured the best terms.","A tenacious entrepreneur turns every failure into fuel.","The tenacious team completed the project despite setbacks.","Tenacious: me with the last piece of gulab jamun.","Tenacious = will NOT let go. A very strong, positive word. Use it for persistence in the face of real obstacles."),
  w(812,"concise","संक्षिप्त / सारगर्भित","expressing much in few words","/kənˈsaɪs/","Advanced Adjectives","adjective","C1",["brief","clear","compact"],["verbose","wordy"],"Write a concise summary — no more than 100 words.","His emails are always concise and easy to act on.","Be concise in interviews — say it clearly, then stop.","A concise report saves everyone's time.","The concise presentation was praised for its clarity.","Concise: me explaining plans. Not concise: me telling a story.","Concise = short + complete. 'Eliminate words that add length but not meaning.' A vital professional writing skill."),
  w(813,"diligent","परिश्रमी / मेहनती","working hard and carefully","/ˈdɪlɪdʒənt/","Advanced Adjectives","adjective","B2",["hardworking","thorough","conscientious"],["lazy","careless"],"She is a diligent student who reviews notes every day.","Diligent employees rarely need to be reminded of their tasks.","My diligent preparation helped me ace the interview.","The diligent team delivered the project two days early.","Diligent verification prevented a costly mistake.","Diligent study? Define diligent. Define study.","Diligent = steady, careful, and hard-working. Strong resume word. Back it up: 'I diligently reviewed every report before submission.'"),
  w(814,"lucid","स्पष्ट / समझने में आसान","very clear and easy to understand","/ˈluːsɪd/","Advanced Adjectives","adjective","C2",["clear","transparent","intelligible"],["confusing","unclear"],"The professor gave a lucid explanation of quantum theory.","Write in a lucid style so all readers can understand.","Her lucid summary helped the team make a quick decision.","The report was praised for its lucid and precise language.","A lucid argument is easier to accept and act on.","Lucid: my writing after coffee. Not lucid: before coffee.","Lucid = something that is immediately, effortlessly clear. Use for explanations, arguments, and writing style."),
  w(815,"indispensable","अपरिहार्य / अनिवार्य","absolutely necessary; impossible to do without","/ˌɪndɪˈspɛnsəbəl/","Advanced Adjectives","adjective","C1",["essential","vital","necessary"],["optional","dispensable"],"Good communication skills are indispensable in any career.","She made herself indispensable by mastering every process.","Strong documentation is indispensable for project handover.","The team lead was indispensable during the crisis.","Indispensable team members are rewarded and promoted.","My phone is indispensable. My brain agrees reluctantly.","'Make yourself indispensable' = become so valuable they can't afford to let you go. A career strategy."),
  w(816,"prolific","विपुल / बहुत कुछ उत्पन्न करने वाला","producing much work or many results","/prəˈlɪfɪk/","Advanced Adjectives","adjective","C2",["productive","fertile","abundant"],["barren","unproductive"],"She is a prolific writer who publishes three books a year.","Prolific coders commit hundreds of lines of clean code daily.","The prolific researcher published 50 papers in a decade.","Prolific creators find inspiration everywhere.","His prolific output made him the most cited author in his field.","Prolific napper: I am. Prolific worker: aspirational.","Prolific = produces a LOT. Use for writers, creators, scientists, or artists with a large body of work."),
  w(817,"paramount","सर्वोच्च / सबसे महत्वपूर्ण","more important than anything else","/ˈpærəmaʊnt/","Advanced Adjectives","adjective","C1",["supreme","utmost","primary"],["minor","secondary"],"Customer safety is of paramount importance.","Accuracy is paramount when handling financial data.","Trust is paramount in a client-consultant relationship.","Communication was identified as the paramount success factor.","Following protocol is paramount during a medical emergency.","Paramount importance: passing the exam. Secondary: everything else.","'Paramount' = the MOST important thing above all else. 'Safety is paramount' is a classic formal usage."),
  w(818,"meagre","अल्प / नगण्य","very small or insufficient in quantity","/ˈmiːɡər/","Advanced Adjectives","adjective","C1",["scant","sparse","inadequate"],["generous","abundant"],"She survived on a meagre salary of ₹8,000 a month.","The meagre budget forced creative problem-solving.","A meagre portion of the research covered this topic.","Resources were meagre, but the team delivered exceptional work.","The charity struggled with meagre funding from donors.","Meagre meal plan: dal-chawal again. Every. Single. Day.","Meagre = not enough — barely what is needed. A slightly negative word, conveying insufficient quantity or quality."),
  w(819,"exorbitant","बहुत अधिक / अत्यधिक मँहगा","unreasonably high in price","/ɪɡˈzɔːrbɪtənt/","Advanced Adjectives","adjective","C1",["excessive","outrageous","overpriced"],["reasonable","fair"],"The hotel charged an exorbitant rate during the holidays.","Exorbitant fuel prices hurt the working class the most.","The legal fees were exorbitant for a small business.","Investors avoided the project due to exorbitant initial costs.","The exorbitant price of urban real estate shocked first-time buyers.","Delivery charge: exorbitant. Ordering anyway: always.","Exorbitant = WAY TOO EXPENSIVE. Stronger than 'expensive'. Use when the price is unfair or shocking."),
  w(820,"exemplary","अनुकरणीय / उत्कृष्ट","so good it deserves to be copied","/ɪɡˈzɛmplərɪ/","Advanced Adjectives","adjective","C1",["outstanding","model","excellent"],["mediocre","poor"],"Her exemplary performance earned her the Employee of the Year award.","He showed exemplary leadership during the crisis.","The project was completed with exemplary attention to detail.","Exemplary service leads to loyal, referring customers.","The student's exemplary effort was praised in the school assembly.","Exemplary punctuality means arriving 5 minutes early. I aspire.","Exemplary = so good it sets the EXAMPLE for others. A high-level compliment in professional settings."),
  w(821,"ambiguous","अस्पष्ट / दो अर्थों वाला","having more than one possible meaning; unclear","/æmˈbɪɡjuəs/","Advanced Adjectives","adjective","C1",["vague","unclear","uncertain"],["clear","explicit"],"Avoid ambiguous language in legal documents.","The question was ambiguous — two answers were correct.","Her response was ambiguous — I'm still not sure what she meant.","Ambiguous instructions led to three different interpretations.","The ambiguous clause in the contract created a dispute.","Ambiguous text: 'Let's eat, kids' or 'Let's eat kids'. Commas save lives.","Ambiguous = could mean two or more things. Always clarify ambiguous information in professional settings."),
  w(822,"redundant","अनावश्यक / अतिरिक्त","not needed; repeating information unnecessarily; laid off","/rɪˈdʌndənt/","Advanced Adjectives","adjective","C1",["unnecessary","superfluous","duplicate"],["necessary","essential"],"Cut redundant sentences from your essay for clarity.","He was made redundant when the company downsized.","Remove redundant steps from the workflow to save time.","The new software made several manual roles redundant.","Redundant code wastes processing power and slows systems.","'Please RSVP if you're coming' — RSVP already means that. Redundant!","Two meanings: 1) Repetitive/unnecessary. 2) UK job term: your role was eliminated. Both are important to know."),
  w(823,"comprehensive","व्यापक / पूर्ण","covering everything completely","/ˌkɒmprɪˈhɛnsɪv/","Advanced Adjectives","adjective","B2",["thorough","complete","exhaustive"],["partial","incomplete"],"This is a comprehensive guide to English grammar.","The comprehensive report covered all aspects of the project.","A comprehensive approach to health includes mind and body.","Comprehensive training reduced errors by 35%.","The comprehensive insurance plan covered all medical scenarios.","Comprehensive study notes: 200 pages. Time to read: never.","Comprehensive = COVERS EVERYTHING. Use when you want to emphasise completeness and thoroughness."),
  w(824,"substantial","पर्याप्त / महत्वपूर्ण","large in size, value, or importance","/səbˈstænʃəl/","Advanced Adjectives","adjective","C1",["significant","considerable","ample"],["negligible","minimal"],"There was a substantial improvement after the training.","The company made a substantial investment in R&D.","She provided substantial evidence to support her claim.","A substantial portion of the budget was allocated to marketing.","Substantial changes were made to the original plan.","That was a very substantial meal. I cannot move.","Substantial = MEANINGFULLY large, not just 'big'. More formal than 'big'. Great for academic and business writing."),
  w(825,"notorious","कुख्यात / बदनाम","famous for something negative","/noʊˈtɔːrɪəs/","Advanced Adjectives","adjective","B2",["infamous","disreputable"],["celebrated","famous"],"He is notorious for missing every deadline.","The company became notorious for poor customer service.","That road is notorious for accidents during monsoon.","The notorious bug caused the entire system to crash.","The notorious executive was removed after the scandal broke.","I'm notorious in my family for forgetting birthdays. Sorry.","Notorious = famous but for BAD reasons. 'Famous' vs 'Notorious': one is positive, the other is negative."),
  w(826,"inevitable","अपरिहार्य / अवश्यम्भावी","certain to happen; impossible to avoid","/ɪnˈɛvɪtəbəl/","Advanced Adjectives","adjective","B2",["unavoidable","certain","inescapable"],["avoidable","preventable"],"Growth and change are inevitable parts of life.","It was inevitable that prices would rise post-lockdown.","If you don't revise, failure is nearly inevitable.","Market correction was seen as inevitable by analysts.","Conflict was inevitable given the two teams' different goals.","Rain on exam day: inevitable. Umbrella at home: also inevitable.","'It was inevitable' = it was going to happen no matter what. A strong, final-sounding word."),
  w(827,"obsolete","अप्रचलित / पुराना पड़ जाना","no longer useful or in use","/ˈɒbsəliːt/","Advanced Adjectives","adjective","C1",["outdated","old-fashioned","redundant"],["current","modern"],"Fax machines have become obsolete in most offices.","Paper maps became obsolete after GPS was developed.","Upskill regularly or your expertise will become obsolete.","Several job roles became obsolete after automation.","The obsolete software was replaced with a cloud-based system.","My phone charger: three years old. Obsolete? Cable company thinks so.","Obsolete = still exists but no longer used or needed. Technology moves fast — keep learning or risk becoming obsolete."),
  w(828,"scrutinize","बारीकी से जाँचना","to examine something very carefully","/ˈskruːtɪnaɪz/","Advanced Adjectives","verb","C2",["examine","inspect","analyse"],["glance","overlook"],"Scrutinize every clause before signing a contract.","Investors scrutinized the startup's financial projections.","The committee scrutinized all applications thoroughly.","The report was scrutinized for accuracy before publication.","The new policy was scrutinized by the media and the public.","I scrutinized the menu for 20 minutes and ordered dal makhani anyway.",vf("scrutinize","scrutinizes","scrutinizing","scrutinized","scrutinized")),
  w(829,"pivotal","निर्णायक / अत्यंत महत्वपूर्ण","of critical importance in a process","/ˈpɪvɪtəl/","Advanced Adjectives","adjective","C1",["crucial","decisive","central"],["minor","irrelevant"],"This is a pivotal moment for the company's future.","Her pivotal contribution changed the direction of the project.","The pivotal decision was made by the board in Q3.","Pivotal hires are those who elevate an entire team's performance.","The pivotal match was won in the final 10 minutes.","Pivotal exam tomorrow. Sleep or revision? Decided: both. Neither done.","Pivotal = at the center of everything; the moment that changes the direction. Very powerful in formal writing."),
  w(830,"candid","सीधा / स्पष्टवादी","honest and direct, even about difficult topics","/ˈkændɪd/","Advanced Adjectives","adjective","C1",["frank","open","straightforward"],["evasive","indirect"],"Please give me candid feedback on my presentation.","She was candid about the challenges the project faced.","A candid conversation saved the team from a bigger conflict.","I appreciate candid colleagues more than polite ones.","The CEO gave a candid assessment of the company's performance.","Candid feedback: 'Your cooking is... improving.' It's not.","Candid = honest and direct, even when the truth is uncomfortable. 'Candid feedback' ≠ brutal — it's kind but honest."),
  w(831,"pragmatic","व्यावहारिक / यथार्थवादी","practical rather than idealistic","/præɡˈmætɪk/","Advanced Adjectives","adjective","C1",["practical","realistic","sensible"],["idealistic","theoretical"],"We need a pragmatic plan, not a perfect one.","She took a pragmatic approach to fixing the broken process.","Pragmatic problem-solvers move faster than idealists.","The pragmatic compromise satisfied both parties.","A pragmatic leader delivers results despite imperfect conditions.","Pragmatic decision: order in. Idealistic plan: cook from scratch.","Pragmatic = focused on WHAT WORKS rather than what's ideal or perfect. Essential quality in fast-moving environments."),
  w(832,"empathy","सहानुभूति / दूसरों की भावना समझना","the ability to understand and share another's feelings","/ˈɛmpəθi/","Advanced Adjectives","noun","B2",["compassion","understanding"],["indifference","coldness"],"Empathy is the most human leadership quality.","Empathy builds deeper customer relationships.","I listen with empathy before offering solutions.","High-empathy leaders build loyal, motivated teams.","The nurse showed remarkable empathy with anxious patients.","Empathy: understanding that everyone's Wi-Fi pain is equally real.","Empathy (feel WITH someone) vs Sympathy (feel FOR someone). Leaders need empathy; friends offer both."),
  w(833,"assertive","दृढ़ / निश्चित मत वाला","confident in stating opinions and claiming rights","/əˈsɜːrtɪv/","Advanced Adjectives","adjective","C1",["confident","direct","firm"],["passive","aggressive"],"Be assertive — say what you need clearly and respectfully.","Assertive communication prevents misunderstandings.","She assertively negotiated a 20% salary increase.","Assertive employees are respected by peers and managers.","The assertive presenter held the room's attention throughout.","Assertive: 'I need this by Friday.' Not assertive: 'Maybe... if you have time... no pressure...'","Assertive = confident and clear, without being aggressive. The middle ground between passive and aggressive communication."),
  w(834,"spontaneous","स्वत:स्फूर्त / अचानक","happening naturally without planning","/spɒnˈteɪnɪəs/","Advanced Adjectives","adjective","C1",["natural","impulsive","unplanned"],["planned","calculated"],"Her spontaneous laugh was infectious and real.","I made a spontaneous decision to apply for the job.","Spontaneous gestures of kindness mean the most.","The spontaneous team outing boosted morale more than any event.","His spontaneous performance won the audience over completely.","Spontaneous road trip at midnight: the best and worst idea ever.","Spontaneous = not planned in advance, happening naturally. Can be positive (fun, genuine) or risky (impulsive)."),
  w(835,"resilience","लचीलापन / सहनशीलता","the capacity to recover quickly from difficulties","/rɪˈzɪlɪəns/","Advanced Adjectives","noun","C1",["toughness","adaptability"],["fragility","weakness"],"Resilience is not about avoiding failure — it's about recovering from it.","I developed resilience through repeated challenges.","Team resilience during the crisis was extraordinary.","Resilience training is now standard in many companies.","Emotional resilience separates average performers from great ones.","Resilience: bouncing back from Monday every single week.","Resilience ≠ never struggling. It means you BOUNCE BACK after you do. Build it through small, hard challenges."),
  w(836,"prodigious","अत्यंत विलक्षण / असाधारण","remarkably great in extent or ability","/prəˈdɪdʒəs/","Advanced Adjectives","adjective","C2",["remarkable","extraordinary","impressive"],["mediocre","ordinary"],"Mozart showed prodigious musical talent at age 4.","The prodigious effort of the team delivered an impossible result.","She wrote a prodigious amount of code in just two days.","The scientist's prodigious memory helped her win debates.","The startup showed prodigious growth in its first quarter.","My prodigious appetite is my most admirable quality.","Prodigious = impressively large or remarkable in some way. Often used for talent, effort, or achievement."),
  w(837,"astute","चालाक / बुद्धिमान","having a sharp and clear understanding of things","/əˈstjuːt/","Advanced Adjectives","adjective","C2",["shrewd","perceptive","sharp"],["naive","gullible"],"She made an astute observation that changed our strategy.","An astute investor reads market signals others miss.","His astute leadership guided the team through a crisis.","The astute buyer noticed the contract error and saved ₹2 lakh.","The astute negotiator always knew when to pause and when to push.","Astute observation: I notice when the biscuits are finished.","Astute = quickly and accurately understands complex situations. A top compliment for intelligent, perceptive people."),
  w(838,"mediocre","औसत / साधारण","of only moderate quality; not very good","/ˌmiːdɪˈoʊkər/","Advanced Adjectives","adjective","B2",["average","ordinary","unremarkable"],["exceptional","outstanding"],"Don't settle for mediocre results when excellence is possible.","The mediocre performance disappointed the entire board.","Mediocre writing is forgotten; clear writing is remembered.","Mediocre service leads to customer attrition over time.","Mediocre input leads to mediocre output — every time.","I am mediocre at cricket. But I play with enthusiasm.","Mediocre = not terrible, but not good either. It's a slightly negative word for 'just average.' Push past it."),
  w(839,"candid","स्पष्टवादी / खुलकर बोलने वाला","honest, direct, and open","/ˈkændɪd/","Advanced Adjectives","adjective","C1",["frank","open","truthful"],["evasive","dishonest"],"I prefer candid feedback to empty praise.","Be candid in your interview — authenticity is valued.","The candid discussion helped resolve the team conflict.","The CEO was refreshingly candid about the company's struggles.","A candid self-evaluation helps you grow faster.","Candid review: 'You speak well in your native language.' Working on English!","Candid ≠ rude. Candid = honest but respectful. 'Candid conversation' is a professional term for a frank discussion."),
  w(840,"intrinsic","आंतरिक / स्वाभाविक","belonging naturally to something; coming from within","/ɪnˈtrɪnsɪk/","Advanced Adjectives","adjective","C2",["inherent","natural","inborn"],["extrinsic","external"],"Intrinsic motivation lasts longer than external rewards.","Curiosity is an intrinsic part of a scientist's mindset.","Intrinsic rewards include pride, purpose, and joy.","The intrinsic value of education cannot be measured in money.","She found intrinsic satisfaction in teaching underprivileged children.","My intrinsic motivation for studying: fear of failure.","Intrinsic = from INSIDE (self-driven). Extrinsic = from OUTSIDE (money, praise). Both motivate, but intrinsic lasts longer."),
  w(841,"feasible","संभव / व्यावहारिक","possible and practical to do","/ˈfiːzɪbəl/","Advanced Adjectives","adjective","C1",["possible","practical","workable"],["impossible","impractical"],"Is it feasible to complete this in two days?","A feasibility study was conducted before the project began.","The proposed solution is technically feasible but costly.","The team assessed whether the plan was feasible given current resources.","Feasible options were shortlisted and presented to the board.","Is it feasible to finish this assignment tonight? Technically yes. Realistically no.","'Feasible' = can it be done? 'Viable' = is it worth doing? Ask both before committing to any plan."),
  w(842,"viable","व्यावसायिक दृष्टि से सक्षम / टिकाऊ","capable of working or succeeding","/ˈvaɪəbəl/","Advanced Adjectives","adjective","C1",["workable","sustainable","possible"],["unviable","impossible"],"Is this business model financially viable?","Present only viable solutions, not just wishful thinking.","A viable alternative to the current system was proposed.","The startup needed a viable revenue model from Day 1.","Three viable options were evaluated by the steering committee.","Viable career plan: in progress. Viable eating schedule: also in progress.","Viable = practical AND sustainable. It must work AND keep working. 'Technically feasible but not commercially viable' is common."),
  w(843,"ambivalent","दुविधाग्रस्त / अनिश्चित मन","having mixed feelings about something","/æmˈbɪvələnt/","Advanced Adjectives","adjective","C2",["uncertain","undecided","conflicted"],["certain","committed"],"I feel ambivalent about accepting the job offer.","She was ambivalent about leaving her hometown.","Ambivalent consumers are harder to convert into buyers.","The team was ambivalent about adopting the new software.","The ambivalent response from clients indicated mixed market interest.","Ambivalent about dessert: want it, shouldn't have it. Will have it.","Ambivalent = two opposite feelings at the same time. 'I love this job but also want to quit.' That's ambivalence."),
  w(844,"unprecedented","अभूतपूर्व / पहले कभी नहीं हुआ","never done or experienced before","/ʌnˈprɛsɪdɛntɪd/","Advanced Adjectives","adjective","C1",["historic","first-ever","unparalleled"],["common","routine"],"The pandemic caused unprecedented disruption to the economy.","She achieved unprecedented results in her first quarter.","The technology offers unprecedented accuracy in diagnosis.","The company posted unprecedented losses during the lockdown.","The agreement was hailed as an unprecedented diplomatic achievement.","Unprecedented: waking up before my alarm. Truly historic.","Unprecedented = the FIRST TIME this has happened. Very strong word. Don't overuse it or it loses its impact."),
  w(845,"analogous","सादृश्य / समान","similar or comparable to something else","/əˈnæləɡəs/","Advanced Adjectives","adjective","C2",["similar","comparable","parallel"],["different","distinct"],"The situation is analogous to what happened in 2008.","This new policy is analogous to existing data protection laws.","Using analogous cases strengthens a legal argument.","The product launch strategy was analogous to a successful 2019 campaign.","Teaching is analogous to planting seeds — results come later.","My situation is analogous to running late for a train — every morning.","Analogous = parallel in function or meaning. Used to explain something new by comparing it to something familiar."),
  w(846,"innate","जन्मजात / प्राकृतिक","existing from birth; natural and not learned","/ɪˈneɪt/","Advanced Adjectives","adjective","C2",["natural","inborn","inherent"],["acquired","learned"],"She has an innate talent for connecting with people.","Innate curiosity drives the best scientists and engineers.","Not all skills are innate — most are developed with practice.","The team had an innate ability to find creative solutions.","His innate leadership ability was visible from the start.","Innate ability to sleep anywhere: confirmed talent.","Innate = born with it. But research shows most skills are BUILT, not born. Growth mindset > fixed mindset."),
  w(847,"benevolent","परोपकारी / दयालु","well-meaning and kind; doing good for others","/bɪˈnɛvələnt/","Advanced Adjectives","adjective","C2",["kind","generous","charitable"],["malevolent","cruel"],"The company has a benevolent policy of supporting employees' education.","He was known as a benevolent leader who cared for his people.","Benevolent organisations give back to the communities they serve.","The foundation's benevolent work reached millions of families.","Benevolent gestures from leadership build team loyalty.","Benevolent dictator of the household: me, about chai tea levels.","Benevolent = genuinely wanting to do good and being kind. Often used in leadership, philanthropy, and descriptions of character."),
  w(848,"tangible","मूर्त / ठोस","real, physical, and measurable","/ˈtændʒɪbəl/","Advanced Adjectives","adjective","C1",["concrete","real","measurable"],["intangible","abstract"],"Show tangible results, not just good intentions.","The training had tangible benefits on team performance.","We need tangible proof before making the decision.","Tangible improvements were recorded after the new process.","Tangible assets include land, buildings, and machinery.","Tangible outcome of study session: 3 pages. Intangible: existential crisis.","Tangible = physical or clearly measurable. Intangible = abstract, like trust or brand value. Both matter in business."),
  w(849,"eloquence","वाक्पटुता / प्रभावशाली भाषा","the ability to speak or write clearly and expressively","/ˈɛləkwəns/","Advanced Adjectives","noun","C2",["fluency","expressiveness","rhetoric"],["stammering","vagueness"],"Her eloquence in English impressed the interview panel.","Eloquence is not about vocabulary — it's about clarity and feeling.","His eloquence helped him close difficult deals.","The speech was celebrated for its eloquence and passion.","The advocate's eloquence moved the courtroom to tears.","Eloquence goal: sound like Shashi Tharoor. Current level: working on it.","Eloquence comes from practice, preparation, and reading widely. Great speakers read constantly and think in stories."),
  w(850,"tenacity","दृढ़ता / अडिगता","the quality of continuing despite difficulty","/tɪˈnæsɪti/","Advanced Adjectives","noun","C2",["persistence","determination","grit"],["giving up","weakness"],"Tenacity is what separates those who achieve from those who wish.","She showed tenacity in rebuilding her company after bankruptcy.","Tenacity and patience are the twin engines of long-term success.","His tenacity in sales led to a record-breaking quarter.","The team's tenacity through the setbacks was remarkable.","Tenacity: I've attempted this habit 20 times. I'll try again Monday.","Tenacity = keeping going when everything says stop. Grit, determination, persistence — all synonyms. All valuable."),

  // ─── Advanced Verbs (851–900) ─────────────────────────────────────────────
  w(851,"amplify","बढ़ाना / प्रवर्धित करना","to increase or make something stronger or louder","/ˈæmplɪfaɪ/","Advanced Verbs","verb","C1",["strengthen","boost","magnify"],["diminish","reduce"],"Use data to amplify your argument in presentations.","Social media amplifies both truth and misinformation.","Good leadership amplifies the team's collective strengths.","The campaign amplified the brand's reach by 3×.","The speaker's words were amplified by the stadium system.","Coffee amplifies my morning energy and my anxiety equally.",vf("amplify","amplifies","amplifying","amplified","amplified")),
  w(852,"consolidate","सुदृढ़ करना / एक करना","to combine things to make them stronger or simpler","/kənˈsɒlɪdeɪt/","Advanced Verbs","verb","C1",["merge","combine","strengthen"],["divide","scatter"],"Consolidate your notes into one document before the exam.","The company consolidated three departments into one.","I consolidated my loan payments into a single monthly EMI.","Consolidate your market position before expanding.","Two regions were consolidated under a single director.","Consolidating my laundry and my dishes into one catastrophic evening.",vf("consolidate","consolidates","consolidating","consolidated","consolidated")),
  w(853,"evaluate","मूल्यांकन करना","to assess or judge the quality or value of something","/ɪˈvæljueɪt/","Advanced Verbs","verb","B2",["assess","judge","analyse"],["ignore","assume"],"Evaluate each option before making a final decision.","We evaluated the ROI of every marketing channel.","Teachers evaluate students through exams and assignments.","The committee evaluated 50 proposals and chose five.","The software was evaluated by the QA team before launch.","I evaluate movie options for 30 minutes and still pick the wrong one.",vf("evaluate","evaluates","evaluating","evaluated","evaluated")),
  w(854,"facilitate","सुगम बनाना / सहायता करना","to make a process easier","/fəˈsɪlɪteɪt/","Advanced Verbs","verb","C1",["enable","assist","support"],["hinder","block"],"Good communication facilitates faster decision-making.","I facilitated the workshop for 30 managers.","Technology facilitates remote collaboration across time zones.","The mediator facilitated a resolution between both parties.","The training programme facilitated knowledge transfer efficiently.","Chai facilitates every productive conversation in India.",vf("facilitate","facilitates","facilitating","facilitated","facilitated")),
  w(855,"formulate","तैयार करना / निरूपित करना","to develop or express something carefully","/ˈfɔːrmjʊleɪt/","Advanced Verbs","verb","C1",["develop","devise","create"],["copy","ignore"],"Formulate your response before answering in an interview.","The team formulated a three-year digital strategy.","I formulated a plan to improve customer satisfaction.","The policy was formulated after extensive stakeholder consultation.","The scientist formulated a new hypothesis based on the data.","I formulated a plan to exercise daily. Plan formulated. Execution: TBD.",vf("formulate","formulates","formulating","formulated","formulated")),
  w(856,"mitigate","कम करना / शमन करना","to make something less severe or harmful","/ˈmɪtɪɡeɪt/","Advanced Verbs","verb","C2",["reduce","lessen","minimise"],["increase","worsen"],"Invest in training to mitigate skill gaps on the team.","The government took steps to mitigate the impact of inflation.","Regular testing mitigates software risk significantly.","Insurance is used to mitigate financial risk.","Safety protocols mitigate the risk of workplace accidents.","I mitigate traffic stress by leaving early. Or telling myself to leave early.",vf("mitigate","mitigates","mitigating","mitigated","mitigated")),
  w(857,"anticipate","पहले से अनुमान लगाना","to expect and prepare for something before it happens","/ænˈtɪsɪpeɪt/","Advanced Verbs","verb","C1",["foresee","predict","expect"],["ignore","react"],"Anticipate problems before they become crises.","I anticipated the client's question and prepared an answer.","We didn't anticipate the level of demand after launch.","Great managers anticipate their team's needs proactively.","The risk team anticipated regulatory changes and prepared.","I anticipated hunger and packed two extra rotis. Wise.",vf("anticipate","anticipates","anticipating","anticipated","anticipated")),
  w(858,"convey","व्यक्त करना / संप्रेषित करना","to communicate an idea or feeling","/kənˈveɪ/","Advanced Verbs","verb","B2",["communicate","express","transmit"],["hide","conceal"],"Convey your ideas clearly and concisely in writing.","His tone of voice conveyed genuine concern.","How do you convey complex information to a non-technical audience?","The ad conveyed the brand's values in just 30 seconds.","The report conveys the urgency of the situation effectively.","I tried to convey frustration calmly. The vein in my neck did not agree.",vf("convey","conveys","conveying","conveyed","conveyed")),
  w(859,"substantiate","प्रमाणित करना / समर्थन देना","to provide evidence to support a claim","/səbˈstænʃɪeɪt/","Advanced Verbs","verb","C2",["prove","confirm","validate"],["refute","deny"],"Substantiate every claim in your research paper.","Can you substantiate that number with data?","The journalist substantiated her claims with recorded evidence.","He couldn't substantiate the complaint with any evidence.","The audit report substantiated concerns about financial mismanagement.","I substantiated my request for a raise with 6 months of data.",vf("substantiate","substantiates","substantiating","substantiated","substantiated")),
  w(860,"rectify","सुधारना / ठीक करना","to correct an error or wrong","/ˈrɛktɪfaɪ/","Advanced Verbs","verb","C1",["correct","fix","remedy"],["worsen","ignore"],"Rectify the error in the report before submitting.","The team rectified the production issue within 2 hours.","How will you rectify this mistake with the client?","The software update rectified the critical security vulnerability.","The billing error was rectified and refunded within a day.","Rectified my typo in the email — after 10 people had seen it.",vf("rectify","rectifies","rectifying","rectified","rectified")),
  w(861,"defer","स्थगित करना / टालना","to delay something to a later time; to yield to another's judgment","/dɪˈfɜːr/","Advanced Verbs","verb","C1",["postpone","delay","yield"],["advance","lead"],"We deferred the decision until more data was available.","I defer to the expert on this technical matter.","The launch was deferred by three weeks due to testing issues.","Defer payment options are offered to financial hardship cases.","The team deferred final approval to the executive committee.","I deferred studying until 11 PM. Efficient, as always.",vf("defer","defers","deferring","deferred","deferred")),
  w(862,"validate","मान्य करना / प्रमाणित करना","to confirm something is correct, true, or acceptable","/ˈvælɪdeɪt/","Advanced Verbs","verb","C1",["confirm","verify","authenticate"],["invalidate","reject"],"Validate your assumptions before building the product.","The research validated the initial hypothesis.","Always validate data before presenting it as fact.","User testing validated our design decisions.","The certificate was validated by the issuing institution.","I validated my decision to eat dessert. It was correct.",vf("validate","validates","validating","validated","validated")),
  w(863,"integrate","एकीकृत करना / जोड़ना","to combine parts into a whole","/ˈɪntɪɡreɪt/","Advanced Verbs","verb","C1",["combine","merge","incorporate"],["separate","divide"],"Integrate all feedback before submitting the final report.","The new employee integrated well with the existing team.","We integrate data from three sources into one dashboard.","The app integrates with Google Calendar and Outlook.","Successfully integrating diverse teams requires cultural awareness.","Integrating sleep and productivity: still trying to crack the code.",vf("integrate","integrates","integrating","integrated","integrated")),
  w(864,"quantify","मात्रा में बताना","to express something in numbers or amounts","/ˈkwɒntɪfaɪ/","Advanced Verbs","verb","C1",["measure","calculate","assess"],["estimate","guess"],"Quantify your achievements on your resume.","It's hard to quantify the value of employee morale.","The report quantified the financial impact of the delay.","Can you quantify the improvement in customer satisfaction?","The risk was quantified at ₹20 lakh per event.","Quantifying my love of chai: infinite. Units: cups per day.",vf("quantify","quantifies","quantifying","quantified","quantified")),
  w(865,"clarify","स्पष्ट करना","to make something easier to understand","/ˈklærɪfaɪ/","Advanced Verbs","verb","B2",["explain","clear up","define"],["confuse","obscure"],"Clarify the scope before the project begins.","I asked the client to clarify their deadline.","The email clarified the policy changes effectively.","Always clarify ambiguity in instructions before acting.","The manager clarified expectations to avoid confusion.","Clarifying question: 'What do you mean by done?' Always worth asking.",vf("clarify","clarifies","clarifying","clarified","clarified")),
  w(866,"iterate","दोहराना / सुधारते जाना","to repeat a process, improving each time","/ˈɪtəreɪt/","Advanced Verbs","verb","C2",["repeat","refine","improve"],["finalise","stop"],"Great products are built by iterating on user feedback.","We iterated through five design versions before the final.","Iterate fast — done is better than perfect.","The team iterated the prototype twice before user testing.","Agile methodology involves iterating in two-week sprints.","I iterate on my morning routine — still not optimal after 10 years.",vf("iterate","iterates","iterating","iterated","iterated")),
  w(867,"discern","परखना / विवेचन करना","to recognise or understand something with difficulty","/dɪˈsɜːrn/","Advanced Verbs","verb","C2",["perceive","distinguish","detect"],["overlook","confuse"],"A good leader can discern what truly matters.","I couldn't discern a clear pattern in the data.","He has a rare ability to discern truth from hype.","Discerning readers notice errors that others miss.","She discerned the conflict of interest before anyone else.","It takes skill to discern genuine feedback from flattery.",vf("discern","discerns","discerning","discerned","discerned")),
  w(868,"extrapolate","अनुमान लगाना / विस्तारित करना","to extend conclusions from known data to unknown situations","/ɪkˈstræpəleɪt/","Advanced Verbs","verb","C2",["project","estimate","predict"],["observe","measure"],"Don't extrapolate beyond what the data supports.","Based on Q1 results, we can extrapolate full-year revenue.","The researcher extrapolated global trends from regional data.","Extrapolating from a small sample can be misleading.","The model extrapolated future demand using historical growth rates.","I extrapolated from 2 weeks of habit data that I'll be perfect by July.",vf("extrapolate","extrapolates","extrapolating","extrapolated","extrapolated")),
  w(869,"harmonise","सामंजस्य बिठाना","to make things work well together","/ˈhɑːrmənaɪz/","Advanced Verbs","verb","C2",["align","coordinate","synchronise"],["conflict","clash"],"Harmonise team goals with company objectives.","The two departments needed to harmonise their processes.","The policy was harmonised across all regional offices.","Good design harmonises form and function.","Tax laws were harmonised across the EU member states.","Harmonising two different music playlists: harder than it sounds.",vf("harmonise","harmonises","harmonising","harmonised","harmonised")),
  w(870,"overhaul","पूरी तरह सुधारना","to completely renovate or revise something","/ˈoʊvərˌhɔːl/","Advanced Verbs","verb","C2",["revamp","rebuild","transform"],["patch","maintain"],"We need to overhaul the entire onboarding process.","The team overhauled the app's user interface in Q2.","A system overhaul was necessary after three security breaches.","The HR policy was completely overhauled to reflect modern practices.","The car needed a full engine overhaul after 10 years.","Overhauling my wardrobe: said that 3 years ago.",vf("overhaul","overhauls","overhauling","overhauled","overhauled")),
  w(871,"assert","दावा करना / दृढ़ता से कहना","to state something confidently and forcefully","/əˈsɜːrt/","Advanced Verbs","verb","C1",["claim","state","maintain"],["deny","doubt"],"Assert your rights clearly and professionally.","The lawyer asserted that her client was innocent.","She asserted her position without backing down.","The report asserted a direct link between sleep and productivity.","He asserted control over the project after the team struggled.","Asserting my right to the last seat — respectfully.",vf("assert","asserts","asserting","asserted","asserted")),
  w(872,"infer","निष्कर्ष निकालना","to conclude from evidence without being explicitly told","/ɪnˈfɜːr/","Advanced Verbs","verb","C1",["deduce","conclude","derive"],["assume","guess"],"What can you infer from this graph?","I inferred from his tone that he was unhappy with the result.","Don't infer more than the data supports.","Good readers infer meaning from context clues.","The analyst inferred future trends from historical patterns.","I inferred from the silence that my idea was not great.",vf("infer","infers","inferring","inferred","inferred")),
  w(873,"transcend","पार करना / ऊपर उठना","to go beyond the limits of something","/trænsˈsɛnd/","Advanced Verbs","verb","C2",["surpass","exceed","go beyond"],["limit","restrict"],"Great leaders transcend their own ego to serve others.","Her talent transcended her lack of formal education.","Good music transcends language and culture.","The brand transcended local markets to reach a global audience.","His performance transcended expectations and redefined the role.","My love of chai transcends all dietary restrictions.",vf("transcend","transcends","transcending","transcended","transcended")),
  w(874,"diverge","भिन्न होना / अलग दिशा में जाना","to go in different directions or differ from each other","/daɪˈvɜːrdʒ/","Advanced Verbs","verb","C2",["differ","branch","deviate"],["converge","align"],"Our opinions diverged sharply on the marketing strategy.","The two reports diverged significantly in their conclusions.","The road diverges into two paths — take the one that scares you.","Audience preferences have diverged across age groups.","Cultural values diverge even within the same country.","My plans and reality diverge every single morning.",vf("diverge","diverges","diverging","diverged","diverged")),
  w(875,"converge","एक बिंदु पर मिलना","to come together toward the same point or conclusion","/kənˈvɜːrdʒ/","Advanced Verbs","verb","C2",["meet","align","unite"],["diverge","separate"],"The two strategies eventually converged into one plan.","Tech and healthcare are converging to create new innovations.","All roads converge at the city centre.","The team's diverse ideas converged into a unified proposal.","Global trends are converging faster than ever before.","My calendar and my sleep schedule never converge.",vf("converge","converges","converging","converged","converged")),
  w(876,"collaborate","सहयोग करना","to work with others toward a shared goal","/kəˈlæbəreɪt/","Advanced Verbs","verb","B2",["cooperate","partner","team up"],["compete","work alone"],"We collaborated with three agencies on the campaign.","Great things happen when smart people collaborate freely.","I collaborated with the data team to build the dashboard.","The two companies collaborated to develop a joint product.","Staff from 10 countries collaborated on the global report.","Collaborating on where to eat: always the hardest team exercise.",vf("collaborate","collaborates","collaborating","collaborated","collaborated")),
  w(877,"deliberate","जानबूझकर / सोच-समझकर करना","done on purpose; to think carefully","/dɪˈlɪbərɪt/","Advanced Verbs","verb/adjective","C1",["intentional","calculated","considered"],["accidental","impulsive"],"This was a deliberate choice, not a mistake.","The committee deliberated for two hours before deciding.","Deliberate practice is more effective than casual repetition.","The design error was deliberate — it was a test.","The board deliberated at length on the acquisition strategy.","Deliberate avoidance of the gym for 3 weeks. Deliberate.",vf("deliberate","deliberates","deliberating","deliberated","deliberated")),
  w(878,"mobilize","जुटाना / सक्रिय करना","to bring together for action or effort","/ˈmoʊbɪlaɪz/","Advanced Verbs","verb","C2",["organise","rally","marshal"],["demobilise","scatter"],"The NGO mobilized volunteers across 12 states.","We mobilized the team in 24 hours to handle the crisis.","Digital platforms mobilize public opinion at scale.","The startup mobilized ₹2 crore in 48 hours through crowdfunding.","The government mobilized emergency services within hours.","Mobilizing my brain before 9 AM: still in development.",vf("mobilize","mobilizes","mobilizing","mobilized","mobilized")),
  w(879,"propagate","फैलाना / प्रसार करना","to spread or promote something widely","/ˈprɒpəɡeɪt/","Advanced Verbs","verb","C2",["spread","disseminate","circulate"],["suppress","contain"],"Don't propagate misinformation — verify before sharing.","Good practices must be propagated across the organisation.","Social media propagates ideas faster than any medium before it.","The campaign propagated health awareness across rural communities.","Knowledge is propagated best through storytelling and examples.","Propagating good habits: I pin them to the fridge. Results: variable.",vf("propagate","propagates","propagating","propagated","propagated")),
  w(880,"negate","नकारना / अस्वीकार करना","to cancel out or make something invalid","/nɪˈɡeɪt/","Advanced Verbs","verb","C2",["cancel","nullify","invalidate"],["confirm","support"],"One bad decision can negate years of good work.","Negativity in the team negated the impact of our training.","A poor review negates a strong product launch.","The exception clause negated the main contract terms.","The defense's argument was negated by the video evidence.","One bad meal negates my entire week of eating well. Apparently.",vf("negate","negates","negating","negated","negated")),
  w(881,"reconcile","सुलझाना / मेल-मिलाप करना","to make two things compatible; to resolve a disagreement","/ˈrɛkənsaɪl/","Advanced Verbs","verb","C2",["resolve","settle","balance"],["conflict","dispute"],"Reconcile your accounts at the end of every month.","The two managers reconciled their differences after mediation.","It's hard to reconcile quality with speed in this project.","The accounts were reconciled with the bank statements.","The team was reconciled after the facilitator-led workshop.","Reconciling what I plan to eat with what I actually eat: daily battle.",vf("reconcile","reconciles","reconciling","reconciled","reconciled")),
  w(882,"incentivize","प्रोत्साहित करना","to motivate someone using rewards or benefits","/ɪnˈsɛntɪvaɪz/","Advanced Verbs","verb","C2",["motivate","reward","encourage"],["discourage","penalise"],"Incentivize good performance with bonuses and recognition.","The company incentivized early adoption with a 30% discount.","Customers were incentivized through a referral programme.","Incentivizing the right behaviors drives the right results.","Tax breaks incentivize investment in green technology.","Incentivized to work out: bought gym shoes. Still on display.",vf("incentivize","incentivizes","incentivizing","incentivized","incentivized")),
  w(883,"conceptualize","अवधारणा बनाना","to form a concept or idea about something","/kənˈsɛptʃʊəlaɪz/","Advanced Verbs","verb","C2",["envision","conceptualise","imagine"],["overlook","ignore"],"Before coding, conceptualise the full user experience.","She conceptualized the product design in one brainstorming session.","Good innovators conceptualize solutions before they're needed.","The team conceptualized three different campaign directions.","The architect conceptualized the building's layout before drawing.","I conceptualized an organised life. Execution: perpetually in progress.",vf("conceptualize","conceptualizes","conceptualizing","conceptualized","conceptualized")),
  w(884,"replicate","दोहराना / नकल करना","to copy or reproduce something exactly","/ˈrɛplɪkeɪt/","Advanced Verbs","verb","C1",["copy","reproduce","duplicate"],["originate","create"],"Can you replicate this result in a different market?","The success of the Mumbai branch was replicated in Chennai.","Scientists replicate experiments to verify results.","This design cannot be replicated without the original files.","The training was replicated across 40 offices nationwide.","I replicated my grandmother's recipe — almost. Close enough.",vf("replicate","replicates","replicating","replicated","replicated")),
  w(885,"transpose","स्थानांतरित करना / अदला-बदली करना","to transfer something to a different place or context","/trænsˈpoʊz/","Advanced Verbs","verb","C2",["transfer","shift","move"],["keep","retain"],"Transpose the data from the old format to the new template.","Good ideas can be transposed across industries.","The melody was transposed to a higher key.","He transposed the successful rural model to an urban context.","The formula was transposed incorrectly — causing a ₹5 lakh error.","Transposing habits from holidays to workdays: never easy.",vf("transpose","transposes","transposing","transposed","transposed")),
  w(886,"benchmark","मानदंड स्थापित करना","to set a standard for comparison","/ˈbɛntʃmɑːrk/","Advanced Verbs","verb","C1",["measure","compare","standardise"],["guess","assume"],"Benchmark your performance against industry standards.","We benchmarked the new process against global best practices.","HR benchmarked salaries using market data from five surveys.","The analyst benchmarked the startup against 10 comparable firms.","The service level was benchmarked quarterly for consistency.","I benchmarked my productivity against my colleague. Big mistake.",vf("benchmark","benchmarks","benchmarking","benchmarked","benchmarked")),
  w(887,"innovate","नवाचार करना","to introduce new ideas or methods","/ˈɪnəveɪt/","Advanced Verbs","verb","B2",["create","invent","pioneer"],["copy","stagnate"],"Innovate or be disrupted — there is no middle ground.","The company constantly innovates to stay ahead.","We innovated our delivery process to cut costs.","Teams that innovate together build stronger bonds.","The product team innovated under tight budget constraints.","I innovated my lunch: old rice + new sauce = new dish!",vf("innovate","innovates","innovating","innovated","innovated")),
  w(888,"mandate","अनिवार्य करना","to officially require or authorise something","/ˈmændeɪt/","Advanced Verbs","verb/noun","C1",["require","order","direct"],["suggest","allow"],"The policy mandates annual safety training for all staff.","The government mandated masks during the pandemic.","He was given a mandate to restructure the team.","The board mandated a 20% cost reduction by year-end.","Attendance was mandated for all department heads.","Someone mandate a 4-day work week. Please.",vf("mandate","mandates","mandating","mandated","mandated")),
  w(889,"counteract","प्रतिकार करना","to reduce or prevent the effects of something","/ˌkaʊntərˈækt/","Advanced Verbs","verb","C2",["offset","neutralise","combat"],["worsen","increase"],"Exercise helps counteract the effects of sedentary work.","The medication counteracts the side effects of the treatment.","We introduced bonuses to counteract growing staff dissatisfaction.","The ad campaign counteracted negative press coverage.","Strong governance can counteract the risks of rapid growth.","I counteract unhealthy eating with… more unhealthy eating.",vf("counteract","counteracts","counteracting","counteracted","counteracted")),
  w(890,"precipitate","जल्दी लाना / उत्पन्न करना","to cause something to happen suddenly or earlier than expected","/prɪˈsɪpɪteɪt/","Advanced Verbs","verb","C2",["trigger","cause","hasten"],["delay","prevent"],"The poor results precipitated an urgent board review.","The scandal precipitated the CEO's resignation.","A single tweet precipitated a crisis for the brand.","Lack of planning precipitated the project's failure.","The news precipitated a sharp drop in share prices.","My alarm not going off precipitated a very stressful morning.",vf("precipitate","precipitates","precipitating","precipitated","precipitated")),

  // ─── Phrasal Expressions (891–940) ────────────────────────────────────────
  w(891,"give up","छोड़ देना / हार मानना","to stop trying","/ɡɪv ʌp/","Phrasal Expressions","phrasal verb","A2",["quit","surrender","abandon"],["persist","continue"],"Never give up on learning English — consistency wins.","She wanted to give up, but kept pushing for one more week.","I refuse to give up on my dream.","The company gave up trying to enter the Chinese market.","After five failed attempts, he finally gave up the appeal.","I give up trying to maintain inbox zero. It's impossible.","'Give up' + gerund: 'I gave up smoking.' 'Give up on' + noun: 'Don't give up on your goals.'"),
  w(892,"pick up","सीखना / उठाना / बेहतर होना","to learn or improve; to physically lift","/pɪk ʌp/","Phrasal Expressions","phrasal verb","A2",["learn","improve","collect"],["drop","deteriorate"],"I picked up Spanish while travelling in South America.","Business is starting to pick up after a slow quarter.","Can you pick up the report from the printer?","She picked up great interview tips from the workshop.","Sales picked up significantly after the product relaunch.","I picked up procrastination in college. Never put it down.","'Pick up' a skill = learn naturally. 'Pick up speed' = increase pace. 'Pick up someone' = collect a person."),
  w(893,"break down","टूट जाना / सरल करना","to fail mechanically; to explain in steps; to lose emotional control","/breɪk daʊn/","Phrasal Expressions","phrasal verb","B1",["fail","collapse","analyse"],["function","hold up"],"Break down the task into smaller steps.","The car broke down on the highway.","She broke down crying when she heard the news.","The proposal broke down during the final presentation.","The manager broke down the quarterly data for the team.","My study plan breaks down every Sunday night. Reliably.","Three meanings: 1) Stop working (machine). 2) Analyse/simplify. 3) Cry or lose composure. All are common!"),
  w(894,"carry out","पूरा करना / निष्पादित करना","to complete or perform a task or plan","/ˈkæri aʊt/","Phrasal Expressions","phrasal verb","B1",["execute","complete","perform"],["abandon","neglect"],"Carry out the plan we discussed in the meeting.","The team carried out the audit over three days.","Always carry out a safety check before starting work.","He carried out his responsibilities with exceptional care.","The research was carried out by an independent team.","I carried out exactly zero of my weekend plans. Success!","'Carry out' = take action to COMPLETE a specific task or plan. More formal than 'do.' Common in reports and instructions."),
  w(895,"come up with","सोचना / विचार करना","to think of or produce a new idea","/kʌm ʌp wɪð/","Phrasal Expressions","phrasal verb","B1",["invent","devise","produce"],["copy","copy"],"Can you come up with three alternatives by tomorrow?","She came up with the best marketing idea of the year.","I came up with a solution in the middle of the night.","The team came up with a creative workaround.","No one could come up with a better plan than hers.","I came up with this excuse. I'm proud of it.","'Come up with' = invent or think of something NEW. Always positive and creative in connotation."),
  w(896,"deal with","सामना करना / निपटना","to handle or manage a situation or problem","/diːl wɪð/","Phrasal Expressions","phrasal verb","A2",["handle","manage","address"],["avoid","ignore"],"I'll deal with the complaint before end of day.","How do you deal with difficult clients?","Deal with the most urgent issues first.","The team dealt with five crises in one week.","HR dealt with the workplace dispute professionally.","Dealing with Mondays: it's a process. Still figuring it out.","'Deal with' = take responsibility for handling something. Can mean emotions too: 'I'm still dealing with this.'"),
  w(897,"figure out","समझना / हल निकालना","to understand or solve something","/ˈfɪɡər aʊt/","Phrasal Expressions","phrasal verb","A2",["understand","solve","determine"],["confuse","give up"],"I finally figured out how to use the new software.","Can you figure out the best route to take?","She figured out the issue in less than 10 minutes.","I couldn't figure out why the formula wasn't working.","We need to figure out a solution before the meeting.","I've been trying to figure out my life plan since 2019.","'Figure out' = understand something that was unclear, or find a solution to a problem. Very versatile."),
  w(898,"get along","मिलजुल कर रहना","to have a friendly relationship with someone","/ɡɛt əˈlɒŋ/","Phrasal Expressions","phrasal verb","A2",["bond","connect","agree"],["clash","conflict"],"I get along well with all my colleagues.","Do you get along with your manager?","They didn't get along at first but became close friends.","Getting along with clients is essential in customer-facing roles.","The two departments don't always get along — but they collaborate.","I get along with everyone. Except my alarm clock.","'Get along (with someone)' = have a good, smooth relationship. 'Get along in life' = manage and progress."),
  w(899,"hold on","रुकना / टिके रहना","to wait; to keep going despite difficulty","/hoʊld ɒn/","Phrasal Expressions","phrasal verb","A2",["wait","persist","endure"],["let go","quit"],"Hold on — I'll be with you in a minute.","Hold on to your dreams even when it's hard.","Can you hold on while I check the details?","Hold on — something is wrong with this data.","The startup held on through three difficult years.","Hold on — I need to check if this is a good idea. Spoiler: it is.","'Hold on' = wait (informal). 'Hold on to' = keep/retain something. 'Hold on through' = endure a tough period."),
  w(900,"look forward to","उत्सुकता से प्रतीक्षा करना","to feel excited and positive about a future event","/lʊk ˈfɔːrwərd tuː/","Phrasal Expressions","phrasal verb","A2",["anticipate","await","expect"],["dread","fear"],"I look forward to meeting you on Tuesday.","I'm looking forward to starting my new job.","She looked forward to every training session.","The team looked forward to the annual retreat.","I look forward to your feedback on this proposal.","I look forward to Fridays the way I look forward to nothing else.","Always followed by a noun or gerund (-ing form): 'I look forward to hearing from you' — NOT 'look forward to hear.'"),
  w(901,"make up","बनाना / क्षमा करना / मेकअप करना","to invent; to resolve a conflict; cosmetics","/meɪk ʌp/","Phrasal Expressions","phrasal verb","A2",["invent","reconcile","create"],["reveal","fight"],"Don't make up excuses — tell the truth.","They fought and then made up quickly.","I made up a story to explain the delay.","The team made up after the project conflict was resolved.","She made up the entire presentation on the spot.","I make up great plans. The follow-through is the issue.","'Make up a story' = invent. 'Make up (with someone)' = reconcile. 'Put on makeup' = cosmetics. Three meanings!"),
  w(902,"point out","बताना / ध्यान दिलाना","to draw attention to something","/pɔɪnt aʊt/","Phrasal Expressions","phrasal verb","B1",["indicate","highlight","mention"],["hide","overlook"],"Can you point out the error in this report?","She pointed out a key risk we had overlooked.","Please point out any mistakes in my work.","The analyst pointed out three gaps in the data.","He pointed out that the deadline had already passed.","Pointing out errors in other people's work: an art form.","'Point out' = bring something specific to someone's attention. Constructive and professional. Different from 'criticise.'"),
  w(903,"put off","टालना / देरी करना","to delay or postpone; to make someone lose interest","/pʊt ɒf/","Phrasal Expressions","phrasal verb","B1",["delay","postpone","defer"],["advance","attract"],"Stop putting off your important tasks until evening.","The meeting was put off until next Thursday.","His rude tone put off the entire team.","I keep putting off updating my LinkedIn profile.","The deadline was put off by a week due to client changes.","I keep putting off 'beginning' — and the irony is not lost on me.","'Put off a task' = delay. 'Put someone off' = make them lose interest or enthusiasm. Two different uses!"),
  w(904,"run out of","समाप्त हो जाना","to use all of something so none is left","/rʌn aʊt əv/","Phrasal Expressions","phrasal verb","A2",["exhaust","deplete","use up"],["replenish","refill"],"We've run out of time for this discussion.","I ran out of internet data two days before the recharge.","The team ran out of ideas after two hours.","We ran out of stock during the sale campaign.","The patience of the committee ran out after the third delay.","Ran out of coffee. Day cancelled.","'Run out of' something = have NONE left. 'Running low on' = almost finished. Two useful phrases."),
  w(905,"show up","आना / प्रकट होना","to appear or arrive; to be present","/ʃoʊ ʌp/","Phrasal Expressions","phrasal verb","A2",["arrive","appear","attend"],["miss","avoid"],"Showing up consistently is half the battle.","She showed up late but delivered perfectly.","Just show up — presence matters more than perfection.","Three team members didn't show up for the meeting.","The vendor showed up an hour early for installation.","I show up for every meeting. The enthusiasm varies.","'Show up' (arrive/appear) is more informal than 'attend.' In life: 'Just show up' = presence and consistency matter."),
  w(906,"stand for","प्रतिनिधित्व करना / किसी बात के लिए खड़ा होना","to represent; to tolerate","/stænd fɔːr/","Phrasal Expressions","phrasal verb","B1",["represent","symbolise","support"],["oppose","reject"],"What does your brand stand for?","I won't stand for dishonesty in any form.","The abbreviation 'ETA' stands for 'Estimated Time of Arrival'.","Our company stands for quality, integrity, and care.","She stood for fairness even when it was unpopular.","My username stands for my initials and birth year. Very creative.","'Stand for something' = what it represents or means. 'Won't stand for' = refuse to tolerate."),
  w(907,"take care of","देखभाल करना / संभालना","to look after; to handle","/teɪk keər əv/","Phrasal Expressions","phrasal verb","A2",["handle","manage","attend to"],["neglect","ignore"],"I'll take care of the invoicing while you handle the client.","Take care of your health — work can wait.","She takes care of all the admin for the department.","The team took care of every detail for the launch event.","He took care of customer complaints with grace and speed.","I'll take care of dinner. (Orders food online immediately.)","'Take care of' = handle a task OR care for a person. Both are essential life phrases."),
  w(908,"turn down","अस्वीकार करना / शोर कम करना","to reject an offer; to reduce volume or intensity","/tɜːrn daʊn/","Phrasal Expressions","phrasal verb","B1",["reject","decline","refuse"],["accept","accept"],"I turned down the offer because the salary was too low.","Turn down the music — I'm on a call!","Never turn down a chance to learn.","The board turned down the acquisition proposal.","She turned down the partnership without giving a reason.","I turned down the alarm. Just five more minutes. (× 10)","'Turn down an offer' = decline. 'Turn down the volume' = reduce. Two separate meanings — context is everything."),
  w(909,"work out","सुलझाना / कसरत करना","to find a solution; to exercise; to end well","/wɜːrk aʊt/","Phrasal Expressions","phrasal verb","A2",["solve","exercise","resolve"],["fail","give up"],"It'll work out — just be patient.","Let's work out a schedule that suits everyone.","I work out every morning to stay focused.","The team worked out the technical issues overnight.","Eventually, the partnership worked out for both companies.","It'll all work out. I tell myself this daily. Occasionally it's true.","Three meanings: 1) Solve/figure out. 2) Exercise. 3) End well/successfully. All three are very commonly used."),
  w(910,"build up","धीरे-धीरे बनाना / बढ़ाना","to increase or develop gradually","/bɪld ʌp/","Phrasal Expressions","phrasal verb","B1",["increase","develop","grow"],["decrease","demolish"],"Build up your vocabulary by learning 10 words daily.","She built up her business from scratch over 5 years.","Build up trust before asking for something big.","The team built up momentum over the first quarter.","A slow buildup of customer complaints eventually became a crisis.","Building up my study habit — still in progress after 6 months.","'Build up' = develop or increase gradually over time. Very useful for skills, habits, and business growth."),
  w(911,"catch up","बराबर आना / बातें करना","to reach the same level; to update each other","/kætʃ ʌp/","Phrasal Expressions","phrasal verb","A2",["keep pace","update","reconnect"],["fall behind","ignore"],"I need to catch up on emails from last week.","Let's catch up over coffee next week.","He caught up on the missed lectures using recordings.","She caught up with the team after her leave.","The company caught up to its competitor in market share.","Caught up on three weeks of chores in one day. New record.","'Catch up on' = complete things you missed. 'Catch up with' = reconnect with someone. Both are essential."),
  w(912,"cut back","कम करना","to reduce or decrease something","/kʌt bæk/","Phrasal Expressions","phrasal verb","B1",["reduce","decrease","trim"],["increase","expand"],"We need to cut back on unnecessary expenses.","The company cut back 20% of its workforce.","I'm cutting back on caffeine this month.","Advertising costs were cut back during the slow season.","The project scope was cut back to meet the deadline.","Cutting back on screen time: watch 5 shows instead of 6.","'Cut back on' something = reduce the amount or frequency. Important in both personal finance and business."),
  w(913,"draw up","तैयार करना / बनाना","to prepare or write a formal document","/drɔː ʌp/","Phrasal Expressions","phrasal verb","B2",["prepare","draft","write"],["discard","abandon"],"Draw up a detailed plan before the client presentation.","The lawyer drew up the contract in two days.","I'll draw up a list of requirements by end of day.","An agreement was drawn up and signed by all parties.","The proposal was drawn up over a weekend.","I drew up a budget. Then ignored it immediately.","'Draw up a contract/document/plan' = to prepare and write something formally. Very common in legal and business contexts."),
  w(914,"fall behind","पिछड़ जाना","to be slower than expected; to not make progress","/fɔːl bɪˈhaɪnd/","Phrasal Expressions","phrasal verb","B1",["lag","trail","lose ground"],["lead","advance"],"I fell behind on my reading during busy weeks.","The project fell behind schedule by two weeks.","Don't fall behind — consistent effort beats cramming.","The country fell behind in renewable energy adoption.","She fell behind on rent and needed a payment plan.","I fell behind on my habit tracker. To track my progress. Ironic.","'Fall behind (on something)' = not keeping up. 'Falling behind schedule' is extremely common in project management."),
  w(915,"fill in","भरना / जानकारी देना","to complete a form; to inform someone of missed info","/fɪl ɪn/","Phrasal Expressions","phrasal verb","A2",["complete","inform","substitute"],["blank","skip"],"Fill in the application form carefully.","Can you fill me in on what I missed in the meeting?","She filled in for the team lead during his leave.","Fill in all mandatory fields before submitting the form.","The new intern was filled in on the project background.","Filled in my diary: three entries since January. Great habit.","'Fill in a form' = complete it. 'Fill someone in' = update them. 'Fill in for someone' = replace them temporarily."),
  w(916,"keep up with","तालमेल रखना","to stay at the same level or pace as something","/kiːp ʌp wɪð/","Phrasal Expressions","phrasal verb","B1",["match","follow","track"],["fall behind","lag"],"It's hard to keep up with all the new AI developments.","She keeps up with industry trends through daily reading.","I struggle to keep up with the workload some weeks.","The company kept up with competitor pricing by adjusting quarterly.","Keeping up with technology is a lifelong commitment.","Can't keep up with the news. It changes every hour.","'Keep up with' = maintain pace with something or someone. 'Keep up' on its own = continue, don't stop."),
  w(917,"let down","निराश करना","to disappoint someone","/lɛt daʊn/","Phrasal Expressions","phrasal verb","B1",["disappoint","fail","betray"],["inspire","support"],"I never want to let my team down.","He let the client down by missing the deadline.","Don't let yourself down by not preparing.","The product let customers down with poor quality.","She felt let down when her promotion was given to someone else.","I let myself down by not studying. Regular occurrence.","'Let someone down' = disappoint them by failing to meet their expectations. Powerful emotionally."),
  w(918,"move on","आगे बढ़ना","to progress; to stop focusing on the past","/muːv ɒn/","Phrasal Expressions","phrasal verb","A2",["progress","advance","continue"],["dwell","stay"],"Move on from failure — learn and keep going.","Let's move on to the next agenda item.","She moved on from the difficult experience with grace.","The team moved on to the implementation phase.","After the rejection, I moved on and applied to 10 more companies.","Moving on from that embarrassing moment. Or trying to.","'Move on' = stop dwelling on something and progress forward. Also used in meetings to change topics."),
  w(919,"reach out","संपर्क करना","to make contact with someone","/riːtʃ aʊt/","Phrasal Expressions","phrasal verb","A2",["contact","connect","approach"],["ignore","avoid"],"Reach out if you have any questions.","I reached out to three mentors for career advice.","The company reaches out to customers with personalised emails.","She reached out to reconnect after five years.","Feel free to reach out anytime — I'm here to help.","Reached out to an old friend. Took 3 weeks to reply. Worth it.","'Reach out to someone' = initiate contact. Very common in professional emails and LinkedIn messages."),
  w(920,"set up","स्थापित करना / व्यवस्था करना","to prepare or establish something","/sɛt ʌp/","Phrasal Expressions","phrasal verb","A2",["establish","arrange","prepare"],["close","dismantle"],"Can you set up a meeting for next Monday?","She set up her own business at 26.","Set up your workspace before you begin working.","The team set up the product demo environment overnight.","The new office was set up and ready in three days.","Set up a new habit tracker app. Day 1 done. Day 2: forgot.","'Set up a meeting/system/business' = establish or prepare it. One of the most commonly used phrasal verbs."),
  w(921,"step up","आगे आना / बेहतर करना","to take on more responsibility; to improve","/stɛp ʌp/","Phrasal Expressions","phrasal verb","B2",["rise","improve","increase"],["step back","reduce"],"We need everyone to step up this quarter.","She stepped up as team lead when the manager was on leave.","The brand stepped up its quality standards significantly.","Step up your communication skills to advance in your career.","The team stepped up production to meet the surge in demand.","Stepped up my study game. Slightly. Progress!","'Step up' = take on more responsibility or do better. A call to action in leadership: 'Step up and lead.'"),
  w(922,"take over","संभालना / नियंत्रण लेना","to take control of something","/teɪk ˈoʊvər/","Phrasal Expressions","phrasal verb","B1",["acquire","control","assume"],["give up","surrender"],"Can you take over the project while I'm on leave?","The new manager took over the team smoothly.","The company was taken over by a larger corporation.","I'll take over the presentation from slide 10.","Automation is taking over many repetitive tasks.","Took over the kitchen. Disaster followed. Then pizza was ordered.","'Take over a task' = continue someone else's work. 'Take over a company' = acquire it. Both are common."),
  w(923,"think through","ध्यान से सोचना","to consider every aspect of something carefully","/θɪŋk θruː/","Phrasal Expressions","phrasal verb","B2",["analyse","consider","plan"],["rush","ignore"],"Think through every risk before committing.","She thought through all options before making the decision.","Think the plan through before presenting it to the board.","The engineer thought through the architecture thoroughly.","The CEO thought through the acquisition for six months.","I thought through my morning routine once. Still chaotic.","'Think through' = think carefully about ALL aspects, not just the obvious ones. Essential before major decisions."),
  w(924,"wind up","समाप्त होना / परिणाम होना","to end up in a situation; to finish something","/waɪnd ʌp/","Phrasal Expressions","phrasal verb","B1",["end up","conclude","finish"],["start","begin"],"If you don't plan, you wind up reacting to everything.","We wound up staying at the office until 9 PM.","The meeting wound up much later than expected.","The startup wound up closing after running out of funding.","She wound up choosing the riskiest option — and it paid off.","I wound up binge-watching instead of studying. Classic.","'Wind up' = end up in a situation, often unplanned. 'Wind up a meeting' = bring it to a close."),
  w(925,"go over","समीक्षा करना / दोहराना","to review or check something carefully","/ɡoʊ ˈoʊvər/","Phrasal Expressions","phrasal verb","A2",["review","examine","check"],["ignore","skip"],"Go over the report before the meeting starts.","Let me go over the key points one more time.","The accountant went over every expense in the budget.","Please go over the contract before signing anything.","The manager went over the presentation with the team.","Go over my plan: sounds great in theory, falls apart in practice.","'Go over' something = review it carefully. Very useful before meetings, exams, interviews, and submissions."),
  w(926,"bring up","ज़िक्र करना / चर्चा में लाना","to mention a topic; to raise a child","/brɪŋ ʌp/","Phrasal Expressions","phrasal verb","A2",["mention","raise","introduce"],["ignore","suppress"],"Please bring up this issue in today's meeting.","I was brought up to always say thank you.","She bravely brought up the salary disparity issue.","He brought up a valid point about the project timeline.","The audit team brought up concerns about the approval process.","Brought up that I deserved a raise. Brought up again. And again.","'Bring up a topic' = introduce it for discussion. 'Bring up a child' = raise and care for a child. Two meanings."),
  w(927,"call off","रद्द करना","to cancel something","/kɔːl ɒf/","Phrasal Expressions","phrasal verb","B1",["cancel","abandon","stop"],["proceed","continue"],"The outdoor event was called off due to heavy rain.","Let's call off the meeting — the key stakeholder is unavailable.","The deal was called off after the due diligence findings.","The strike was called off after the management agreed to demands.","The pitch was called off when the investor pulled out.","Called off plans to exercise. Weather was involved. Always weather.","'Call off' = cancel something that was already scheduled. Different from 'cancel' only in register — both mean the same."),
  w(928,"carry on","जारी रखना","to continue doing something","/ˈkæri ɒn/","Phrasal Expressions","phrasal verb","A2",["continue","proceed","persist"],["stop","give up"],"Carry on with the work — I'll join in 5 minutes.","She carried on despite many setbacks.","Carry on learning English every day — it compounds.","The team carried on after the manager resigned.","Please carry on with the presentation.","Carry on with studying. (Immediately distracted by phone.)","'Carry on' = keep going; continue. 'Carry on doing something' = don't stop. British English prefers 'carry on.'"),
  w(929,"cut off","बाधित करना / रोकना","to interrupt; to stop supply; to isolate","/kʌt ɒf/","Phrasal Expressions","phrasal verb","B1",["disconnect","interrupt","stop"],["connect","continue"],"Don't cut me off — let me finish my point.","The internet was cut off during the storm.","He was cut off from his team during the crisis.","The funding was cut off without warning.","The speaker was cut off before reaching his conclusion.","Cut off by a car on the highway. Daily experience.","'Cut someone off' (in conversation) = interrupt. 'Cut off supply/funding' = stop it. 'Cut off a route' = block it."),
  w(930,"draw on","से लाभ उठाना / उपयोग करना","to use knowledge or experience as a resource","/drɔː ɒn/","Phrasal Expressions","phrasal verb","C1",["use","utilise","apply"],["ignore","waste"],"Draw on your past experience when solving new problems.","She drew on her teaching background to train the team.","The speaker drew on 20 years of industry insight.","The report draws on data from 15 countries.","Draw on every resource available before making the decision.","Drawing on my experience of failing exams to teach others better.","'Draw on something' = use it as a resource or source of support. Common in interviews: 'I draw on my experience of...'"),
  w(931,"ease up","कम करना / ढीला पड़ना","to reduce pressure or intensity","/iːz ʌp/","Phrasal Expressions","phrasal verb","B2",["relax","reduce","lessen"],["intensify","increase"],"Ease up on the deadlines — the team is overwhelmed.","Traffic usually eases up after 10 AM.","The pressure eased up after the launch was complete.","She eased up on her diet after reaching her goal weight.","The boss finally eased up after three months of high pressure.","Ease up on the self-criticism — you're doing fine!","'Ease up' = relax pressure or effort. 'Ease up on someone' = be less strict or demanding with them."),
  w(932,"follow through","अंत तक करना / पूरा करना","to complete what you started","/ˈfɒloʊ θruː/","Phrasal Expressions","phrasal verb","B2",["complete","finish","deliver"],["abandon","stop"],"Follow through on your commitments — every time.","She followed through on every promise she made.","Following through is what separates good from great.","The team followed through on the pilot programme successfully.","He didn't follow through, and the client was unhappy.","I follow through on plans sometimes. It's improving.","'Follow through on a commitment/promise/plan' = actually DO what you said. The most important professional habit."),
  w(933,"gear up","तैयार होना","to prepare for something important","/ɡɪər ʌp/","Phrasal Expressions","phrasal verb","B2",["prepare","ready","prime"],["relax","unwind"],"Gear up for the big presentation tomorrow.","The team is gearing up for the product launch.","Companies gear up for the festive season months in advance.","I geared up for the interview with three mock sessions.","The factory geared up production to handle peak demand.","Gearing up for Monday: on Sunday night, always.","'Gear up for something' = actively prepare and get ready for an upcoming event or challenge."),
  w(934,"hold back","रोकना / झिझकना","to stop from moving forward; to restrain","/hoʊld bæk/","Phrasal Expressions","phrasal verb","B1",["restrain","suppress","delay"],["release","proceed"],"Don't hold back — share your honest opinion.","Fear is what holds most people back from success.","He held back his frustration professionally.","Bureaucracy often holds back innovation in large companies.","She was held back by self-doubt for years.","What's holding me back? Me. Definitely me.","'Hold back' = prevent progress (something holds you back) OR suppress a feeling (hold back emotion)."),
  w(935,"kick off","शुरू करना","to start something, often enthusiastically","/kɪk ɒf/","Phrasal Expressions","phrasal verb","B1",["start","begin","launch"],["end","close"],"Let's kick off the meeting with a quick update.","The project kicks off on the first of next month.","They kicked off the campaign with a live event.","The event kicked off with a motivational keynote.","The sprint kicked off with goal-setting for the team.","Kicked off my diet on Monday. And Tuesday. And Wednesday.","'Kick off' = begin with energy and intention. 'The kick-off meeting' is the first meeting of a project. Very common."),
  w(936,"lay out","व्यवस्थित करना / प्रस्तुत करना","to present or arrange something clearly","/leɪ aʊt/","Phrasal Expressions","phrasal verb","B2",["present","arrange","explain"],["hide","confuse"],"Lay out your argument clearly before presenting.","She laid out the project plan on a single slide.","Lay out all options before making a decision.","The architect laid out the design in great detail.","The proposal clearly laid out the timeline and budget.","Laid out my study plan. Beautiful. Followed it: not at all.","'Lay out a plan/argument/design' = present it in an organised, clear way. Very common in business writing."),
  w(937,"narrow down","सीमित करना / विकल्प कम करना","to reduce choices to a smaller number","/ˈnæroʊ daʊn/","Phrasal Expressions","phrasal verb","B2",["shortlist","filter","reduce"],["expand","broaden"],"Narrow down your options to three before deciding.","We narrowed down the candidates to a final shortlist of 5.","The investigation narrowed down the cause to one department.","Narrow down the scope before the project begins.","She narrowed down her career options to two industries.","Narrowing down where to eat: from 20 options to 18.","'Narrow down' = reduce from many to fewer. Common in hiring, research, decisions, and strategy."),
  w(938,"open up","खुलना / खुलकर बातें करना","to become more open or share more; to begin operations","/ˈoʊpən ʌp/","Phrasal Expressions","phrasal verb","B1",["share","reveal","begin"],["close","shut down"],"Open up about your challenges — don't bottle things up.","The new market opened up after the regulation changed.","She opened up about her struggles in the interview.","The platform opened up a new revenue stream.","The company opened up offices in three new cities.","I opened up once. It was terrifying. Slowly getting better.","'Open up to someone' = share personal feelings honestly. 'Open up a market' = enter it. Two separate uses."),
  w(939,"pay off","फल मिलना / उतारना","to yield results; to repay a debt","/peɪ ɒf/","Phrasal Expressions","phrasal verb","A2",["benefit","reward","repay"],["fail","waste"],"Your hard work will pay off — just be consistent.","The investment paid off within 18 months.","I paid off my loan two years early.","Taking the extra course finally paid off during the promotion round.","The company's R&D investment paid off with a breakthrough product.","English practice paying off: you reading this!","'Pay off' (effort) = produce positive results. 'Pay off debt' = finish repaying a loan. Both are common."),
  w(940,"scale up","बड़े पैमाने पर करना","to increase in size or production","/skeɪl ʌp/","Phrasal Expressions","phrasal verb","C1",["expand","grow","increase"],["scale back","reduce"],"We plan to scale up operations next year.","The pilot programme was scaled up nationally after success.","Scale up production to meet the holiday season demand.","The company scaled up hiring by 40% in Q3.","Technology helped the startup scale up efficiently.","Plan: scale up productivity. Reality: steady as she goes.",vf("scale up","scales up","scaling up","scaled up","scaled up")),

  // ─── Technology & Digital (941–1000) ─────────────────────────────────────
  w(941,"algorithm","एल्गोरिदम","a step-by-step set of instructions for solving a problem","/ˈælɡərɪðəm/","Technology & Digital","noun","C1",["process","formula","procedure"],["random","chaos"],"Search engines use algorithms to rank web pages.","The recommendation algorithm shows you what you like.","An algorithm is a recipe — follow the steps, get the result.","The trading algorithm analysed 10,000 data points per second.","The algorithm was refined after user feedback.","My morning algorithm: alarm, phone, 20 minutes of nothing.","Algorithm = a set of rules for a computer (or human) to follow. Used in coding, AI, and data analysis."),
  w(942,"automation","स्वचालन","using technology to perform tasks without human involvement","/ˌɔːtəˈmeɪʃən/","Technology & Digital","noun","C1",["robotics","AI","mechanisation"],["manual work","human effort"],"Automation is changing every industry in the world.","Email automation saved our team 5 hours per week.","Automation handles repetitive tasks so humans can focus creatively.","Factory automation increased production by 60%.","Marketing automation triggered emails based on user behaviour.","Automation took over my calendar — I just confirm meetings now.","Automation = machines or software doing work previously done by humans. Can eliminate some jobs, create others."),
  w(943,"bandwidth","बैंडविड्थ / डेटा गति","the rate at which data is transferred over a network","/ˈbændwɪdθ/","Technology & Digital","noun","B2",["data speed","throughput","capacity"],["latency","slowness"],"High bandwidth allows smooth video streaming.","The server's bandwidth was maxed out during the product launch.","Upgrade your internet bandwidth for video conferencing.","Low bandwidth causes video calls to freeze and stutter.","The app uses minimal bandwidth for users in low-connectivity areas.","Bandwidth fine. My phone's battery: not so fine.","Tech: bandwidth = data transmission speed. Work context: 'I don't have bandwidth' = no capacity. Same word, two uses."),
  w(944,"cloud computing","क्लाउड कंप्यूटिंग","storing and accessing data over the internet, not locally","/klaʊd kəmˈpjuːtɪŋ/","Technology & Digital","noun","B2",["cloud storage","SaaS","remote computing"],["local storage","on-premise"],"Cloud computing lets you access files from anywhere.","Our company migrated to cloud computing to reduce IT costs.","Google Drive and Dropbox are cloud computing services.","Cloud computing enables real-time collaboration across time zones.","The startup reduced IT costs by 40% through cloud computing.","Everything I own is in the cloud. And yet I'm still disorganised.","Cloud computing = infrastructure you rent over the internet. AWS, Google Cloud, and Azure are the big three."),
  w(945,"cybersecurity","साइबर सुरक्षा","the practice of protecting systems from digital attacks","/ˌsaɪbərˈsɪkjʊrɪti/","Technology & Digital","noun","C1",["data security","information security"],["vulnerability","breach"],"Cybersecurity is a top priority for every modern organisation.","Strong passwords are the first line of cybersecurity.","Cybersecurity threats have increased significantly post-pandemic.","The company hired a cybersecurity team after the data breach.","Employee training is critical to effective cybersecurity.","Cybersecurity advice: don't use 'password123'. I know. I know.","Cybersecurity = protecting digital systems from hackers, viruses, and unauthorised access. A fast-growing career field."),
  w(946,"encryption","एन्क्रिप्शन / कूटलेखन","converting data into a code to prevent unauthorised access","/ɪnˈkrɪpʃən/","Technology & Digital","noun","C2",["encoding","security","scrambling"],["decryption","plaintext"],"End-to-end encryption protects your messages from being read.","WhatsApp uses encryption to secure user conversations.","All financial data is stored with 256-bit encryption.","Without encryption, sensitive data is vulnerable to theft.","The app uses encryption to protect your health records.","Encryption: so my embarrassing messages remain private. Thank you, WhatsApp.","Encryption = scrambling data so only authorised parties can read it. Essential for banking, health, and communications."),
  w(947,"API","एप्लिकेशन प्रोग्रामिंग इंटरफेस","a way for software systems to communicate","/eɪ.piː.aɪ/","Technology & Digital","abbreviation","C1",["interface","connector","integration"],["manual transfer"],"The weather app uses an API to fetch real-time data.","Developers use APIs to connect different software systems.","We integrated payment via a payment gateway API.","The map was embedded using Google Maps API.","Our platform offers open APIs for third-party developers.","API: how apps talk to each other. Like WhatsApp calling your bank.","API = Application Programming Interface. It lets different apps share data and functions without exposing their code."),
  w(948,"artificial intelligence","कृत्रिम बुद्धिमत्ता","computer systems performing tasks that require human intelligence","/ˌɑːrtɪˈfɪʃəl ɪnˈtɛlɪdʒəns/","Technology & Digital","noun","C1",["AI","machine learning","deep learning"],["human intelligence"],"Artificial intelligence is transforming healthcare, education, and business.","AI-powered tools can write, design, and code.","We use AI to personalise the user experience.","Artificial intelligence models learn from vast amounts of data.","The company invested heavily in artificial intelligence research.","AI: writing my assignment? Helping me understand? Both? Absolutely both.","AI = computer systems that simulate human thinking. Machine learning is how AI learns. Deep learning is a subset of ML."),
  w(949,"machine learning","मशीन लर्निंग","AI technology that learns from data without being programmed","/məˈʃiːn ˈlɜːrnɪŋ/","Technology & Digital","noun","C2",["ML","deep learning","predictive AI"],["rule-based systems"],"Netflix uses machine learning to recommend content.","Machine learning models improve as they process more data.","I'm studying machine learning to build smarter applications.","Machine learning helps detect fraud in banking transactions.","The demand forecasting tool was powered by machine learning.","Machine learning: teaching computers to do what I couldn't in school.","Machine learning ≠ AI. ML is a SUBSET of AI. The model trains on data and improves over time automatically."),
  w(950,"big data","बड़ा डेटा","extremely large datasets that require special tools to analyse","/bɪɡ ˈdeɪtə/","Technology & Digital","noun","C1",["data analytics","large-scale data"],["small data","sample"],"Big data helps businesses understand customer patterns.","The healthcare industry uses big data to predict outbreaks.","We analyse big data to improve campaign performance.","Big data processing requires specialised infrastructure and tools.","The company built a big data pipeline to ingest real-time sensor data.","My search history is basically big data for my overthinking.","Big data = too large for Excel. Requires tools like Hadoop, Spark, or BigQuery. Volume, Velocity, Variety = the 3 Vs."),
  w(951,"blockchain","ब्लॉकचेन","a secure, decentralised digital ledger technology","/ˈblɒktʃeɪn/","Technology & Digital","noun","C2",["distributed ledger","crypto tech"],["centralised database"],"Blockchain powers Bitcoin and other cryptocurrencies.","Blockchain ensures transactions are transparent and tamper-proof.","Supply chain transparency is improved with blockchain.","The contract was executed as a smart contract on blockchain.","Blockchain technology eliminates the need for a trusted middleman.","Blockchain: I understand 40% of it and I'm okay with that.","Blockchain = a chain of digital records shared across many computers. No single person controls it. Very secure."),
  w(952,"UX","उपयोगकर्ता अनुभव (User Experience)","how a user feels when interacting with a product","/juːˈɛks/","Technology & Digital","abbreviation","C1",["user experience","usability","interaction design"],["poor design"],"Good UX makes apps feel natural and effortless.","The redesign improved UX by reducing steps from 7 to 3.","Always design with the user in mind — that's UX thinking.","The app's UX was rated 4.9/5 by beta users.","UX and UI work together — experience and interface.","Using an app with terrible UX: please, just let me pay you easily!","UX = how it FEELS to use something. UI = how it LOOKS. Great products need both. 'User-centred design' = UX principle."),
  w(953,"UI","यूज़र इंटरफेस (User Interface)","the visual elements a user interacts with in a product","/juːˈaɪ/","Technology & Digital","abbreviation","C1",["interface","frontend","visual design"],["backend"],"The new UI used clean fonts and minimal colour.","The UI was redesigned after poor usability test results.","UI design includes buttons, icons, typography, and layout.","The app's UI was praised for its simplicity and elegance.","UI improvements led to a 30% increase in user retention.","When UI is bad: I spend 5 minutes looking for the 'logout' button.","UI = what you SEE and CLICK. UX = what you FEEL. Both are measured in user testing."),
  w(954,"SaaS","सॉफ्टवेयर एज़ ए सर्विस","software delivered via the internet on a subscription basis","/sæz/","Technology & Digital","abbreviation","C1",["subscription software","cloud software"],["installed software","on-premise"],"Zoom, Slack, and Notion are popular SaaS products.","SaaS allows businesses to use software without maintaining it.","The company generates 80% of revenue from SaaS subscriptions.","SaaS products require internet access to function.","We migrated from installed software to a SaaS model in Q2.","SaaS: software you never own but always pay for. Worth it if it works.","SaaS = Software as a Service. You access it via the internet and pay monthly. No installation needed. Example: Gmail."),
  w(955,"agile","एजाइल / फुर्तीला तरीका","a flexible project management approach using short cycles","/ˈædʒaɪl/","Technology & Digital","adjective/noun","C1",["flexible","iterative","adaptive"],["waterfall","rigid"],"We work in agile sprints of two weeks.","Agile methodology allows teams to adapt quickly to changes.","I transitioned from waterfall to agile and never looked back.","The product team runs agile standups every morning.","Agile projects deliver working software in small, fast iterations.","Agile: fast, flexible, and frequent meetings. Very frequent.","Agile = deliver in small working chunks, get feedback, improve. Key terms: sprint, backlog, scrum, standup, retrospective."),
  w(956,"sprint","स्प्रिंट / त्वरित कार्य-चक्र","a short, time-boxed period of focused work in agile","/sprɪnt/","Technology & Digital","noun","C1",["iteration","cycle","period"],["marathon","project"],"We completed the feature in the 2-week sprint.","Sprint planning sets goals for the next iteration.","The development sprint focused on payment integration.","Sprint velocity measures how much work a team can complete.","Each sprint ends with a review and retrospective.","This sprint's goal: write 500 lines of code. Actual output: 200. Improving!","Sprint = 1–4 weeks of focused work on specific goals. Ends with a review (what was built) and retrospective (what to improve)."),
  w(957,"scrum","स्क्रम / एजाइल फ्रेमवर्क","an agile framework for developing and delivering complex products","/skrʌm/","Technology & Digital","noun","C1",["framework","process","agile method"],["waterfall"],"The development team uses Scrum as their framework.","Daily Scrum meetings are called standups.","The Scrum master facilitates the process and removes blockers.","Our product backlog is managed using the Scrum framework.","Scrum ceremonies include sprint planning, review, and retrospective.","Daily scrum at 9 AM: 15 minutes, three questions. Simple but effective.","Scrum roles: Product Owner (what to build), Scrum Master (how to work), Development Team (who builds). Learn all three."),
  w(958,"DevOps","डेवऑप्स","combining development and operations for faster software delivery","/ˈdɛvɒps/","Technology & Digital","noun","C2",["CI/CD","continuous delivery"],["siloed development"],"DevOps practices reduced our deployment time by 80%.","DevOps bridges the gap between development and IT operations.","The DevOps team automates testing and deployment pipelines.","DevOps culture emphasises collaboration, not blame.","We adopted DevOps and now deploy daily instead of monthly.","DevOps: developers and ops people agreeing. Rare and beautiful.","DevOps = Development + Operations working together. CI/CD pipelines automate testing and deployment for faster delivery."),
  w(959,"repository","रिपॉजिटरी / संग्रहण स्थान","a storage location for code or data","/rɪˈpɒzɪtəri/","Technology & Digital","noun","C1",["storage","database","archive"],["scattered files"],"All code is stored in the GitHub repository.","Clone the repository and follow the setup instructions.","The data repository contains 10 years of customer records.","Each project has its own version-controlled repository.","The repository was made public after the product launch.","My GitHub repository: full of unfinished projects and good intentions.","Repository (repo) = where code is stored and managed. GitHub, GitLab, and Bitbucket are popular platforms."),
  w(960,"debugging","बग ठीक करना / त्रुटि सुधार","the process of finding and fixing errors in code","/diːˈbʌɡɪŋ/","Technology & Digital","noun","C1",["troubleshooting","fixing","error correction"],["coding","developing"],"Debugging can take longer than writing the original code.","I spent 3 hours debugging a missing semicolon.","Good debugging skills are essential for every developer.","The QA team found 12 bugs during the debugging phase.","Debugging tools like breakpoints help isolate issues quickly.","Debugging: 10% fixing the issue. 90% finding the issue.","Debugging = finding and removing bugs (errors) in code. Print statements, debuggers, and rubber ducks are common tools."),
  w(961,"iteration","पुनरावृत्ति / बेहतरीन सुधार","a new version or repetition of a process","/ˌɪtəˈreɪʃən/","Technology & Digital","noun","C1",["version","cycle","round"],["final","completion"],"Each iteration improved the design based on feedback.","We're on the third iteration of the product roadmap.","Iteration is faster than trying to get it perfect the first time.","The algorithm was refined across 10 iterations.","The team shipped 4 iterations of the feature in one month.","Iteration 1: rough. Iteration 2: better. Iteration 10: finally decent.","Iteration = one pass through a process. Iterative design = keep improving through cycles. 'Done is better than perfect.'"),
  w(962,"scalability","स्केलेबिलिटी / विस्तारशीलता","the ability of a system to handle growth","/ˌskeɪləˈbɪlɪti/","Technology & Digital","noun","C2",["flexibility","growth capacity"],["rigidity","bottleneck"],"Scalability is essential when building a product for millions.","The database lacked scalability and crashed under high traffic.","Cloud systems are built for scalability from Day 1.","The architecture was redesigned for better scalability.","Scalability is a top concern for any startup expecting rapid growth.","Scalability check: one user? Works. Ten thousand users? Also works. Success.","Scalability = can the system GROW without breaking? 'It scales well' = it can handle increasing load."),
  w(963,"open source","ओपन सोर्स","software with publicly available code anyone can use","/ˌoʊpən ˈsɔːrs/","Technology & Digital","adjective/noun","C1",["free software","public code","community-built"],["proprietary","closed source"],"Linux is one of the most successful open source projects.","Open source software allows anyone to use, modify, and share code.","We built our product on open source frameworks to save costs.","The company contributed to open source to attract developer talent.","Open source tools like VSCode and Git are used globally.","Using open source tools for free. Donating back? Aspirational.","Open source ≠ free (as in money). It's free to use and modify the code. Companies still make money from services."),
  w(964,"latency","लेटेंसी / देरी","the delay between a request and a response","/ˈleɪtənsi/","Technology & Digital","noun","C2",["delay","response time","lag"],["speed","throughput"],"High latency causes lag in video calls.","Reducing latency improves user experience significantly.","The server latency was reduced from 500ms to 50ms.","Low latency is critical for real-time gaming and trading.","Edge computing reduces latency by processing data closer to users.","Meeting latency: my brain's delay in understanding complex slides.","Latency = how LONG it takes to get a response. Bandwidth = how MUCH data. Both affect performance."),
  w(965,"prototype","प्रोटोटाइप / नमूना","an early model of a product for testing","/ˈproʊtətaɪp/","Technology & Digital","noun","C1",["model","mockup","draft"],["final product","release"],"We built a clickable prototype before writing a single line of code.","The prototype was tested by 50 users in the first week.","Never skip the prototype stage — it saves massive rework.","The prototype revealed three critical design flaws.","The product prototype was presented to investors at the pitch.","Prototype: it does 30% of what the final product will do. Show it anyway!","Prototype = early, testable version. The goal is to learn fast and fail cheap. Build → test → improve → repeat."),
  w(966,"integration","एकीकरण / जोड़","combining separate systems or components into one","/ˌɪntɪˈɡreɪʃən/","Technology & Digital","noun","C1",["connection","merger","linking"],["separation","isolation"],"The payment integration was completed in two days.","System integration was the most complex part of the project.","Third-party integration allows the app to work with other tools.","The CRM integration pulled data from three separate systems.","API-based integration ensured real-time data sync.","Calendar integration: now my phone knows my meetings before I do.","Integration = connecting two systems so they work as one. API integration is the most common type."),
  w(967,"dashboard","डैशबोर्ड","a visual display of key data and metrics","/ˈdæʃbɔːrd/","Technology & Digital","noun","B2",["control panel","display","interface"],["raw data","spreadsheet"],"The sales dashboard shows real-time revenue and leads.","I built a dashboard in Google Data Studio.","All KPIs are tracked on the management dashboard.","The dashboard refreshes every 15 minutes automatically.","The live dashboard impressed the investors at the demo.","My life could use a dashboard: health, finances, productivity. Currently: chaos.","Dashboard = one screen showing all important metrics. Good dashboards show what matters — nothing else."),
  w(968,"data pipeline","डेटा पाइपलाइन","a system that moves and processes data from source to destination","/ˈdeɪtə ˈpaɪplaɪn/","Technology & Digital","noun","C2",["data flow","ETL","data architecture"],["manual data entry"],"The data pipeline ingests 10 million records per day.","A broken data pipeline means no reports for anyone.","We built a real-time data pipeline for streaming analytics.","The pipeline moves data from the source system to the data warehouse.","The data pipeline was automated using Apache Airflow.","Data pipeline broke. Entire analytics team in crisis mode. It was a comma.","Data pipeline = the automated journey of data from collection → processing → storage → analysis. Automate it!"),
  w(969,"deployment","तैनाती / डेप्लॉयमेंट","the process of releasing software for users","/dɪˈplɔɪmənt/","Technology & Digital","noun","C1",["release","launch","rollout"],["development","building"],"The deployment went live at midnight on Saturday.","Post-deployment monitoring caught two issues in 30 minutes.","Automated deployment reduced release time from 2 days to 2 hours.","The staging environment mirrors production for safe deployment.","Deployment to production requires approval from the QA lead.","Deployment successful. App down in 3 minutes. Classic.","Deployment = taking your code from 'done' to 'live for users.' Always test in staging before production deployment!"),
  w(970,"version control","संस्करण नियंत्रण","a system for tracking changes to code or files over time","/ˈvɜːrʒən kənˈtroʊl/","Technology & Digital","noun","C1",["Git","source control","tracking"],["unversioned","manual backup"],"Version control lets teams work on code simultaneously.","Git is the most widely used version control system.","Without version control, overwriting someone else's work is easy.","Version control allowed us to roll back after the bad deployment.","Every developer should know version control before joining a team.","Version control: because 'final_v2_FINAL_actualfinal.docx' is not a system.","Version control (Git) = track every change to your code. Branch = work on a feature. Merge = combine it back."),
  w(971,"neural network","न्यूरल नेटवर्क","an AI system modelled on the human brain","/ˈnjʊərəl ˈnɛtwɜːrk/","Technology & Digital","noun","C2",["deep learning","AI model"],["rule-based system"],"Image recognition is powered by neural networks.","A neural network learns patterns from millions of examples.","Deep learning uses multi-layer neural networks.","The neural network identified fraud with 99.2% accuracy.","Neural networks require significant computational power to train.","Neural network: trained on 10 billion words. Me: still learning 'whom' vs 'who'.","Neural networks = layers of connected nodes (like brain neurons). They learn by seeing lots of examples."),
  w(972,"fintech","फिनटेक / वित्तीय प्रौद्योगिकी","technology applied to financial services","/ˈfɪntɛk/","Technology & Digital","noun","C1",["financial technology","digital finance"],["traditional banking"],"Fintech companies like Paytm changed how India pays.","Fintech is disrupting traditional banking and insurance.","I'm considering a career in fintech after my MBA.","Fintech startups raised a record $135 billion globally last year.","The fintech platform enabled instant loans with AI-based credit scoring.","Fintech: the reason I haven't been to a bank in 3 years.","Fintech = Finance + Technology. Includes digital payments, online banking, robo-advisors, and crypto platforms."),
  w(973,"edtech","एडटेक / शिक्षा प्रौद्योगिकी","technology applied to education","/ˈɛdtɛk/","Technology & Digital","noun","C1",["education technology","e-learning"],["classroom","offline learning"],"This app is an example of edtech at its best.","Edtech platforms like BYJU'S and Coursera grew during the pandemic.","Edtech is making quality education accessible worldwide.","The edtech company raised ₹500 crore to expand to rural India.","AI-powered edtech personalises learning based on student progress.","Edtech: because school at home during COVID taught us a lot about WiFi.","Edtech = Education + Technology. Includes apps, platforms, LMS, and AI tutors. A fast-growing sector in India."),
  w(974,"IoT","इंटरनेट ऑफ थिंग्स (Internet of Things)","a network of physical devices connected to the internet","/aɪ.oʊ.tiː/","Technology & Digital","abbreviation","C2",["connected devices","smart devices"],["offline devices"],"IoT devices include smart thermostats, watches, and cars.","IoT helps factories monitor machines in real time.","The smart home is powered entirely by IoT devices.","IoT security is a major concern as more devices connect.","Our supply chain uses IoT sensors to track inventory.","IoT: my fridge knows I'm out of milk. I didn't ask. It told me.","IoT = everyday objects connected to the internet and sharing data. Examples: smart bulbs, fitness trackers, smart meters."),
  w(975,"SLA","सेवा स्तर समझौता (Service Level Agreement)","a contract defining the expected level of service","/ɛs.ɛl.eɪ/","Technology & Digital","abbreviation","C1",["agreement","contract","commitment"],["no guarantee"],"Our SLA guarantees 99.9% uptime for all clients.","Breach of SLA results in service credits.","Always negotiate SLA terms before signing with a vendor.","The cloud provider's SLA covers response time and resolution.","SLA compliance is reviewed monthly by the operations team.","SLA says 4-hour response. Actual response: 48 hours. SLA violated.","SLA = a contract between service provider and client. It sets MINIMUM standards for availability, response, and quality."),
  w(976,"MVP","न्यूनतम व्यावहारिक उत्पाद (Minimum Viable Product)","the simplest version of a product that can be released","/ɛm.viː.piː/","Technology & Digital","abbreviation","C1",["prototype","first version","basic product"],["full product","final version"],"Launch an MVP first — get feedback before building more.","Our MVP had just three features but solved the core problem.","The startup's MVP attracted 10,000 users in its first week.","Investors funded us based on the MVP demo.","Build the MVP in 4 weeks, not 4 months.","My MVP lifestyle: minimum effort, viable results. Working on that.","MVP = the SMALLEST product that still delivers value to the user. Launch it, learn from real users, then build more."),
  w(977,"product roadmap","उत्पाद रोडमैप","a plan showing a product's development priorities over time","/ˈprɒdʌkt ˈroʊdmæp/","Technology & Digital","noun","C1",["plan","strategy","timeline"],["ad hoc","unplanned"],"The product roadmap is reviewed every quarter.","Share the roadmap with stakeholders for alignment.","The product roadmap prioritises features by impact.","Roadmap items are linked to business goals and user needs.","The investor presentation included a 12-month product roadmap.","My personal roadmap: English fluent by Day 75. On track!","Product roadmap = visual plan of what you'll build and when. It answers: What? When? Why? for every feature."),
  w(978,"tech stack","टेक स्टैक / तकनीकी संरचना","the combination of technologies used to build a product","/tɛk stæk/","Technology & Digital","noun","C1",["tools","framework","platform"],["single tool"],"Our tech stack is React, Node.js, and MongoDB.","Choose your tech stack based on scalability and team skills.","A modern SaaS tech stack includes cloud, CI/CD, and microservices.","The tech stack was evaluated before building the new platform.","Interview question: 'What is your preferred tech stack?'","My current tech stack: Google, YouTube, and hope.","Tech stack = all the tools and languages used together to build and run a product. Full-stack = front + back end."),
  w(979,"microservices","माइक्रोसर्विसेज","an architecture where a system is split into small, independent services","/ˈmaɪkroʊˌsɜːrvɪsɪz/","Technology & Digital","noun","C2",["distributed system","modular architecture"],["monolith","single system"],"Netflix uses microservices to scale independently.","Microservices allow teams to deploy updates without affecting the whole system.","We migrated from a monolith to microservices over 18 months.","Each microservice handles one business function — and one only.","Microservices require strong orchestration and communication design.","Microservices: when your app is 300 tiny apps wearing a trench coat.","Microservices = small independent services that do ONE thing well. Easier to scale, update, and debug independently."),
  w(980,"A/B testing","ए/बी परीक्षण","comparing two versions of something to see which performs better","/eɪ.biː ˈtɛstɪŋ/","Technology & Digital","noun","C1",["split testing","comparative testing"],["single version"],"We A/B tested two email subject lines — B won by 30%.","A/B testing helps you make data-driven design decisions.","Run A/B tests before rolling out any major change.","The A/B test showed Version B had 25% higher conversion.","A/B testing removed gut feeling from product decisions.","A/B testing my morning routine: alarm at 6 vs alarm at 7. 7 won.","A/B testing = show Version A to Group A and Version B to Group B. Measure. Pick the winner. No guessing."),
  w(981,"conversion rate","रूपांतरण दर","the percentage of users who take a desired action","/kənˈvɜːrʒən reɪt/","Technology & Digital","noun","C1",["success rate","completion rate"],["bounce rate","drop-off"],"Our conversion rate improved from 2% to 5% after the redesign.","Conversion rate = buyers / total visitors × 100.","Optimise the landing page to increase conversion rate.","A 1% increase in conversion rate doubled monthly revenue.","The conversion rate was tracked in the CRM dashboard.","Conversion rate for me completing side projects: approximately 0%.","Conversion rate = % of visitors who DO what you want them to do (buy, sign up, download). Optimise this obsessively."),
  w(982,"churn rate","ग्राहक छोड़ने की दर","the rate at which customers stop using a product","/tʃɜːrn reɪt/","Technology & Digital","noun","C1",["attrition","cancellation rate"],["retention rate","loyalty"],"A high churn rate signals poor product-market fit.","We reduced churn rate by 15% through proactive customer success.","Churn rate = customers lost / total customers × 100.","Even a 1% reduction in churn can add millions in revenue.","The subscription product's churn rate was reviewed monthly.","My gym has a high churn rate. I contributed significantly.","Churn = losing customers. High churn = problem. Low churn = happy customers. Retention is the goal."),
  w(983,"user story","उपयोगकर्ता कहानी","a short description of a feature from the user's perspective","/ˈjuːzər ˈstɔːri/","Technology & Digital","noun","C1",["requirement","feature request"],["technical spec"],"A user story follows this format: 'As a [user], I want to [action] so that [benefit].'","Each sprint is planned around a set of user stories.","The product manager wrote 25 user stories for Q3.","User stories keep development focused on real user needs.","The development team estimated effort for each user story.","User story: As a person, I want chai so that I can function.","User story = describes a feature from the USER's point of view. Keeps the team focused on solving real problems."),
  w(984,"frontend","फ्रंटएंड / उपयोगकर्ता पक्ष","the part of a website or app the user sees and interacts with","/ˈfrʌntɛnd/","Technology & Digital","noun","B2",["UI","client-side","visual layer"],["backend","server-side"],"The frontend was built with React and Tailwind CSS.","A good frontend makes complex features feel simple.","Frontend developers focus on performance, design, and usability.","The frontend loads in under 1 second on mobile.","Frontend and backend must work seamlessly together.","Frontend: the beautiful face. Backend: the brain. Both need to function.","Frontend = what users see and click. HTML, CSS, JavaScript. React, Vue, Angular are popular frontend frameworks."),
  w(985,"backend","बैकएंड / सर्वर पक्ष","the server-side of an app that processes data","/ˈbækɛnd/","Technology & Digital","noun","B2",["server","database","API"],["frontend","client-side"],"The backend processes requests and returns responses.","The backend was built with Node.js and PostgreSQL.","Backend bugs are harder to find but more critical to fix.","The payment backend handled 10,000 transactions per minute.","A robust backend ensures reliability, security, and scalability.","Backend error. Please contact support. (Support: also me.)","Backend = where data is stored, processed, and served. Python, Java, Go, Node.js are popular backend languages."),
  w(986,"codebase","कोडबेस","all the code that makes up a software project","/ˈkoʊdbeɪs/","Technology & Digital","noun","C1",["source code","repository","code"],["executable","binary"],"New developers need time to understand the codebase.","A well-documented codebase saves hours of onboarding time.","Technical debt accumulates when the codebase isn't cleaned up.","The codebase was refactored before the major feature release.","Our codebase has 500,000 lines — and counting.","Inheriting an undocumented codebase: a rite of passage.","Codebase = all the source code for a project. Clean codebases are easier to maintain, test, and scale."),
  w(987,"tech debt","तकनीकी ऋण","code that was done quickly and needs to be improved later","/tɛk dɛt/","Technology & Digital","noun","C2",["technical debt","shortcuts","legacy code"],["clean code","best practice"],"We carry tech debt from our rapid MVP phase.","Ignoring tech debt slows future development significantly.","Every sprint, we allocate 20% of time to paying down tech debt.","Tech debt compounds — fix it early, not late.","The codebase had massive tech debt from 3 years of shortcuts.","Tech debt: future me's problem. (Future me is angry about this.)","Tech debt = shortcuts taken now that create problems later. Like borrowing time from the future. Always costs more."),
  w(988,"uptime","अपटाइम / सेवा उपलब्धता","the time a system is fully operational and available","/ˈʌptaɪm/","Technology & Digital","noun","C1",["availability","reliability"],["downtime","outage"],"We guarantee 99.9% uptime — that's less than 9 hours of downtime per year.","High uptime is critical for e-commerce platforms.","The server's uptime was monitored 24/7 by the ops team.","Downtime during peak hours cost the company ₹50 lakh.","Uptime improved after migrating to a redundant cloud architecture.","My brain's uptime: 7 AM–1 PM. After that, please email.","99.9% uptime = 8.77 hours downtime/year. 99.99% = 52.6 minutes. Every 9 matters. Reliability is a premium feature."),
  w(989,"refactor","रिफैक्टर / कोड सुधारना","to restructure existing code without changing its behaviour","/riːˈfæktər/","Technology & Digital","verb","C2",["clean","restructure","improve"],["add features","introduce bugs"],"Refactor the code before adding new features.","We refactored the payment module to reduce complexity.","Regular refactoring prevents tech debt from accumulating.","The refactored code was 40% shorter and easier to maintain.","The team spent a full sprint refactoring the legacy codebase.","Refactored the code. Same functionality. 30% fewer headaches.",vf("refactor","refactors","refactoring","refactored","refactored")),
  w(990,"load balancing","लोड बैलेंसिंग","distributing workload across multiple servers","/loʊd ˈbælənsɪŋ/","Technology & Digital","noun","C2",["distribution","traffic management"],["overload","single point of failure"],"Load balancing prevents any single server from crashing.","We implemented load balancing before the product launch.","Cloud providers offer automatic load balancing services.","Without load balancing, the server crashed during a traffic spike.","Load balancing ensured zero downtime during the campaign.","Load balancing: like a fair manager who shares work equally.","Load balancing = distribute incoming requests across multiple servers so no one server gets overwhelmed. Essential at scale."),
  w(991,"caching","कैशिंग / अस्थायी संग्रहण","storing frequently accessed data temporarily for faster access","/ˈkæʃɪŋ/","Technology & Digital","noun","C2",["temporary storage","performance optimisation"],["real-time fetch","live query"],"Caching reduced our API response time by 90%.","Clear your browser cache if the page isn't updating.","We cache homepage data to handle 100,000 users per second.","Redis is a popular in-memory caching tool.","Caching cuts database load by storing repeated query results.","Caching: teaching your computer to remember things so you don't repeat yourself.","Caching = store data temporarily for fast retrieval. Without it, every request hits the database — slow and expensive."),
  w(992,"webhook","वेबहुक","an automated message sent from one app to another when an event occurs","/ˈwɛbhʊk/","Technology & Digital","noun","C2",["callback","event trigger","notification"],["polling","manual check"],"The payment webhook notifies our system when a transaction completes.","Webhooks eliminate the need to repeatedly poll for updates.","We set up a webhook to trigger an email when an order ships.","The developer configured 10 webhooks for different user events.","Webhook delivery failure was detected and retried automatically.","Webhook fired. Our system got notified. No one had to refresh the page. Magic.","Webhook = a push notification from one system to another. Triggered by an event. More efficient than polling."),
  w(993,"monolith","मोनोलिथ / एकल संरचना","a software system built as a single, large unit","/ˈmɒnəlɪθ/","Technology & Digital","noun","C2",["single unit","legacy system"],["microservices","distributed"],"Our app started as a monolith and grew unmanageable.","Many startups begin with a monolith — it's faster to build.","Moving from a monolith to microservices takes years.","A well-structured monolith is better than badly designed microservices.","The monolith handled 1 million users before we needed to split it.","Monolith: one giant system. Works great until it doesn't.","Monolith = everything in one place. Faster to build. Harder to scale and maintain at large scale."),
  w(994,"infrastructure","बुनियादी ढाँचा / इन्फ्रास्ट्रक्चर","the foundational systems supporting a technology product","/ˈɪnfrəstrʌktʃər/","Technology & Digital","noun","C1",["systems","platform","base"],["application","service"],"Cloud infrastructure scales automatically with demand.","Investing in infrastructure early prevents outages later.","The team manages infrastructure on AWS.","Infrastructure as Code (IaC) automates server configuration.","The infrastructure team rebuilt the entire system in 6 months.","Good infrastructure is invisible. Bad infrastructure is all you can see.","Infrastructure = the underlying systems (servers, networks, databases) that everything runs on. Without it: nothing works."),
  w(995,"sprint retrospective","स्प्रिंट पूर्वविवेचन","a team meeting after a sprint to review what worked and what didn't","/sprɪnt ˌrɛtrəˈspɛktɪv/","Technology & Digital","noun","C1",["review","post-mortem","reflection"],["sprint planning"],"Our retrospective always ends with three action items.","Retrospectives are not blame sessions — they're improvement tools.","We identify what to start, stop, and continue in each retrospective.","The retrospective revealed that daily standups were too long.","Every sprint ends with a retrospective to learn and improve.","Retrospective insight: we talk too much. Noted. (Took 90 minutes to note this.)","Sprint retrospective = look back at the last sprint. What went well? What didn't? What will you change? Honest and safe."),
  w(996,"product backlog","उत्पाद बैकलॉग","a prioritised list of features or tasks to be built","/ˈprɒdʌkt ˈbæklɒɡ/","Technology & Digital","noun","C1",["task list","feature queue"],["sprint backlog","done"],"The product backlog had 120 items at the start of Q1.","Prioritise the backlog based on user impact and effort.","Only the Product Owner can add items to the product backlog.","The backlog is reviewed and refined every two weeks.","Backlog grooming keeps the list clean and actionable.","Backlog: 300 items. Sprint capacity: 10. Maths is brutal.","Product backlog = everything the team WANTS to build. Sprint backlog = what they WILL build this sprint. Big difference."),
  w(997,"real-time","रियल-टाइम / वास्तविक समय","happening or processing instantly without delay","/ˈrɪəl taɪm/","Technology & Digital","adjective","C1",["live","instant","immediate"],["delayed","batch"],"The dashboard shows real-time sales data.","Real-time notifications improve user engagement dramatically.","We built a real-time chat feature using WebSockets.","Real-time fraud detection prevents losses instantly.","The system processes real-time data from 10,000 IoT sensors.","Real-time update: still procrastinating. Thanks for the notification.","Real-time = no delay between event and response. Essential for trading, gaming, chat, and IoT applications."),
  w(998,"DevSecOps","डेवसेकऑप्स","integrating security practices into DevOps processes","/dɛv.sɛk.ɒps/","Technology & Digital","noun","C2",["secure DevOps","security integration"],["post-deployment security"],"DevSecOps embeds security at every stage of development.","We shifted from DevOps to DevSecOps after a data breach.","Security scanning is automated in our DevSecOps pipeline.","DevSecOps ensures vulnerabilities are caught before deployment.","The team adopted DevSecOps to reduce compliance risk.","DevSecOps: because security can't be an afterthought anymore.","DevSecOps = Development + Security + Operations. Security is built IN, not bolted ON. Caught early = cheaper to fix."),
  w(999,"LLM","लार्ज लैंग्वेज मॉडल (Large Language Model)","an AI model trained on vast text to generate and understand language","/ɛl.ɛl.ɛm/","Technology & Digital","abbreviation","C2",["AI language model","GPT"],["human intelligence","rule-based AI"],"ChatGPT is an LLM that generates text based on prompts.","LLMs are trained on billions of words from the internet.","The company built a custom LLM for healthcare queries.","LLMs can summarise, translate, code, and explain.","LLMs have fundamentally changed how we write, search, and code.","LLM: who I ask when Google doesn't understand me either.","LLM = AI trained on huge amounts of text to predict and generate language. GPT-4, Claude, Gemini are examples."),
  w(1000,"prompt engineering","प्रॉम्प्ट इंजीनियरिंग","the skill of crafting effective inputs for AI models","/prɒmpt ˌɛndʒɪˈnɪərɪŋ/","Technology & Digital","noun","C2",["AI prompting","instruction crafting"],["random queries"],"Good prompt engineering gets you 10× better AI results.","Prompt engineering is a new skill every knowledge worker needs.","I prompt engineered my way to a perfect essay outline.","The researcher specialised in prompt engineering for LLMs.","Prompt engineering involves structure, context, and clear instructions.","Prompt engineering: asking the AI politely and specifically. Works for humans too.","Prompt engineering = designing clear, specific instructions for AI. Better prompts = better outputs. 'Garbage in, garbage out.'"),
].filter(Boolean);

// Append new words
data.words = [...data.words, ...newWords];
data.totalWords = data.words.length;

fs.writeFileSync(FILE, JSON.stringify(data, null, 2));
console.log(`✅ vocabulary.json updated — total words: ${data.totalWords}`);
